import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type TransactionType = 'income' | 'expense';

export interface Transaction {
  id: number;
  name: string;
  amount: number;
  type: TransactionType;
  date: string;
}

export interface Client {
  id: number;
  name: string;
  phone: string;
  type: 'client' | 'supplier';
}

export type ViewState = 'dashboard' | 'clients' | 'invoices' | 'settings';

export interface Stats {
  income: number;
  expense: number;
  balance: number;
}

import { Client, Transaction } from '../types';

const TRX_KEY = 'almohaseb_transactions';
const CLIENTS_KEY = 'almohaseb_clients';

export const loadTransactions = (): Transaction[] => {
  try {
    const data = localStorage.getItem(TRX_KEY);
    return data ? JSON.parse(data) : [];
  } catch (e) {
    console.error("Failed to load transactions", e);
    return [];
  }
};

export const saveTransactions = (data: Transaction[]) => {
  try {
    localStorage.setItem(TRX_KEY, JSON.stringify(data));
  } catch (e) {
    console.error("Failed to save transactions", e);
  }
};

export const loadClients = (): Client[] => {
  try {
    const data = localStorage.getItem(CLIENTS_KEY);
    return data ? JSON.parse(data) : [];
  } catch (e) {
    console.error("Failed to load clients", e);
    return [];
  }
};

export const saveClients = (data: Client[]) => {
  try {
    localStorage.setItem(CLIENTS_KEY, JSON.stringify(data));
  } catch (e) {
    console.error("Failed to save clients", e);
  }
};

export const clearAllData = () => {
    localStorage.removeItem(TRX_KEY);
    localStorage.removeItem(CLIENTS_KEY);
}

