import React, { useState, useEffect } from 'react';
import { X, Check } from 'lucide-react';
import { TransactionType } from '../types';

interface AddModalProps {
  isOpen: boolean;
  initialType: 'transaction' | 'client';
  onClose: () => void;
  onSaveTransaction: (data: { name: string; amount: number; type: TransactionType }) => void;
  onSaveClient: (data: { name: string; phone: string; type: 'client' | 'supplier' }) => void;
}

const AddModal: React.FC<AddModalProps> = ({ isOpen, initialType, onClose, onSaveTransaction, onSaveClient }) => {
  const [activeTab, setActiveTab] = useState<'transaction' | 'client'>(initialType);

  // Transaction State
  const [trxName, setTrxName] = useState('');
  const [trxAmount, setTrxAmount] = useState('');
  const [trxType, setTrxType] = useState<TransactionType>('income');

  // Client State
  const [clientName, setClientName] = useState('');
  const [clientPhone, setClientPhone] = useState('');
  const [clientType, setClientType] = useState<'client' | 'supplier'>('client');

  useEffect(() => {
    if (isOpen) {
      setActiveTab(initialType);
      // Reset fields
      setTrxName('');
      setTrxAmount('');
      setClientName('');
      setClientPhone('');
    }
  }, [isOpen, initialType]);

  if (!isOpen) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (activeTab === 'transaction') {
      if (!trxName || !trxAmount) return;
      onSaveTransaction({
        name: trxName,
        amount: parseFloat(trxAmount),
        type: trxType
      });
    } else {
      if (!clientName) return;
      onSaveClient({
        name: clientName,
        phone: clientPhone,
        type: clientType
      });
    }
  };

  return (
    <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex items-center justify-center p-4 fade-in no-print">
      <div className="bg-white rounded-2xl w-full max-w-md shadow-2xl overflow-hidden transform transition-all scale-100">
        <div className="bg-slate-50 px-6 py-4 border-b border-slate-100 flex justify-between items-center">
          <h3 className="font-bold text-lg text-slate-800">إضافة جديدة</h3>
          <button onClick={onClose} className="text-slate-400 hover:text-red-500 transition-colors">
            <X size={24} />
          </button>
        </div>

        <div className="p-6">
          {/* Tabs */}
          <div className="flex bg-slate-100 p-1 rounded-xl mb-6">
            <button
              onClick={() => setActiveTab('transaction')}
              className={`flex-1 py-2 text-sm font-bold rounded-lg transition-all ${
                activeTab === 'transaction' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'
              }`}
            >
              حركة مالية
            </button>
            <button
              onClick={() => setActiveTab('client')}
              className={`flex-1 py-2 text-sm font-bold rounded-lg transition-all ${
                activeTab === 'client' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'
              }`}
            >
              عميل / مورد
            </button>
          </div>

          <form onSubmit={handleSubmit} className="space-y-4">

            {activeTab === 'transaction' ? (
              <>
                <div className="grid grid-cols-2 gap-4">
                  <button
                    type="button"
                    onClick={() => setTrxType('income')}
                    className={`p-3 rounded-xl border-2 font-bold text-sm transition-all ${
                      trxType === 'income' 
                        ? 'border-emerald-500 bg-emerald-50 text-emerald-700' 
                        : 'border-slate-100 hover:border-slate-300 text-slate-500'
                    }`}
                  >
                    قبض (دخل) 💵
                  </button>
                  <button
                    type="button"
                    onClick={() => setTrxType('expense')}
                    className={`p-3 rounded-xl border-2 font-bold text-sm transition-all ${
                      trxType === 'expense' 
                        ? 'border-red-500 bg-red-50 text-red-700' 
                        : 'border-slate-100 hover:border-slate-300 text-slate-500'
                    }`}
                  >
                    صرف (خرج) 💸
                  </button>
                </div>

                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">بيان العملية</label>
                  <input
                    type="text"
                    value={trxName}
                    onChange={(e) => setTrxName(e.target.value)}
                    className="w-full border border-slate-200 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-blue-500 focus:outline-none"
                    placeholder="مثال: فاتورة مبيعات، إيجار..."
                    required
                  />
                </div>

                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">المبلغ (ج.م)</label>
                  <input
                    type="number"
                    value={trxAmount}
                    onChange={(e) => setTrxAmount(e.target.value)}
                    className="w-full border border-slate-200 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-blue-500 focus:outline-none font-bold"
                    placeholder="0.00"
                    min="0"
                    step="0.01"
                    required
                  />
                </div>
              </>
            ) : (
              <>
                 <div className="grid grid-cols-2 gap-4">
                  <button
                    type="button"
                    onClick={() => setClientType('client')}
                    className={`p-3 rounded-xl border-2 font-bold text-sm transition-all ${
                      clientType === 'client' 
                        ? 'border-blue-500 bg-blue-50 text-blue-700' 
                        : 'border-slate-100 hover:border-slate-300 text-slate-500'
                    }`}
                  >
                    عميل 👤
                  </button>
                  <button
                    type="button"
                    onClick={() => setClientType('supplier')}
                    className={`p-3 rounded-xl border-2 font-bold text-sm transition-all ${
                      clientType === 'supplier' 
                        ? 'border-orange-500 bg-orange-50 text-orange-700' 
                        : 'border-slate-100 hover:border-slate-300 text-slate-500'
                    }`}
                  >
                    مورد 📦
                  </button>
                </div>

                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">الاسم بالكامل</label>
                  <input
                    type="text"
                    value={clientName}
                    onChange={(e) => setClientName(e.target.value)}
                    className="w-full border border-slate-200 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-blue-500 focus:outline-none"
                    placeholder="اسم الشخص أو الشركة"
                    required
                  />
                </div>

                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">رقم الهاتف</label>
                  <input
                    type="tel"
                    value={clientPhone}
                    onChange={(e) => setClientPhone(e.target.value)}
                    className="w-full border border-slate-200 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-blue-500 focus:outline-none"
                    placeholder="01xxxxxxxxx"
                  />
                </div>
              </>
            )}

            <div className="pt-4 flex gap-3">
              <button
                type="button"
                onClick={onClose}
                className="flex-1 py-3 text-slate-600 bg-slate-100 hover:bg-slate-200 rounded-xl font-bold transition-colors"
              >
                إلغاء
              </button>
              <button
                type="submit"
                className="flex-[2] py-3 text-white bg-blue-600 hover:bg-blue-700 rounded-xl font-bold transition-colors shadow-lg shadow-blue-200 flex items-center justify-center gap-2"
              >
                <Check size={20} />
                حفظ البيانات
              </button>
            </div>
          </form>
        </div>
      </div>
    </div>
  );
};

export default AddModal;

import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import Clients from './components/Clients';
import AddModal from './components/AddModal';
import { ViewState, Transaction, Client, Stats, TransactionType } from './types';
import { loadTransactions, saveTransactions, loadClients, saveClients, clearAllData } from './services/storage';
import { Plus, Printer, Bell } from 'lucide-react';

function App() {
  const [currentView, setCurrentView] = useState<ViewState>('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [clients, setClients] = useState<Client[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [modalInitialType, setModalInitialType] = useState<'transaction' | 'client'>('transaction');

  // Load data on mount
  useEffect(() => {
    setTransactions(loadTransactions());
    setClients(loadClients());
  }, []);

  // Calculate Stats
  const stats: Stats = useMemo(() => {
    let income = 0;
    let expense = 0;
    transactions.forEach(t => {
      if (t.type === 'income') income += t.amount;
      else expense += t.amount;
    });
    return { income, expense, balance: income - expense };
  }, [transactions]);

  // Handlers
  const handleAddTransaction = (data: { name: string; amount: number; type: TransactionType }) => {
    const newTrx: Transaction = {
      id: Date.now(),
      name: data.name,
      amount: data.amount,
      type: data.type,
      date: new Date().toLocaleDateString('ar-EG'),
    };
    const updated = [...transactions, newTrx];
    setTransactions(updated);
    saveTransactions(updated);
    setIsModalOpen(false);
  };

  const handleDeleteTransaction = (id: number) => {
    if (window.confirm('هل أنت متأكد من حذف هذه العملية؟')) {
      const updated = transactions.filter(t => t.id !== id);
      setTransactions(updated);
      saveTransactions(updated);
    }
  };

  const handleAddClient = (data: { name: string; phone: string; type: 'client' | 'supplier' }) => {
    const newClient: Client = {
      id: Date.now(),
      name: data.name,
      phone: data.phone,
      type: data.type,
    };
    const updated = [...clients, newClient];
    setClients(updated);
    saveClients(updated);
    setIsModalOpen(false);
  };

  const handleDeleteClient = (id: number) => {
    const updated = clients.filter(c => c.id !== id);
    setClients(updated);
    saveClients(updated);
  };

  const handleClearData = () => {
    clearAllData();
    setTransactions([]);
    setClients([]);
    window.location.reload();
  };

  const openModal = (type: 'transaction' | 'client') => {
    setModalInitialType(type);
    setIsModalOpen(true);
  };

  return (
    <div className="flex min-h-screen bg-slate-50 font-sans">
      <Sidebar 
        currentView={currentView} 
        onChangeView={setCurrentView} 
        onClearData={handleClearData} 
      />

      <main className="flex-1 flex flex-col relative overflow-hidden">
        {/* Header */}
        <header className="h-20 bg-white shadow-sm flex justify-between items-center px-8 z-20 no-print sticky top-0">
          <div>
            <h2 className="text-xl font-bold text-slate-800">
                {currentView === 'dashboard' && 'لوحة التحكم الرئيسية'}
                {currentView === 'clients' && 'إدارة العملاء والموردين'}
                {currentView === 'invoices' && 'سجل الفواتير'}
            </h2>
          </div>
          <div className="flex items-center gap-4">
             <button 
                onClick={() => window.print()}
                className="flex items-center gap-2 bg-slate-800 text-white px-4 py-2 rounded-lg hover:bg-slate-700 transition text-sm font-bold"
             >
                <Printer size={18} />
                طباعة تقرير
             </button>
             <div className="relative cursor-pointer w-10 h-10 rounded-full bg-slate-100 flex items-center justify-center hover:bg-slate-200 transition">
                <Bell size={20} className="text-slate-600" />
                <span className="absolute top-2 right-2 w-2 h-2 bg-red-500 rounded-full border border-white"></span>
             </div>
          </div>
        </header>

        {/* Content */}
        <div className="flex-1 overflow-auto p-8 relative">
          <div className="max-w-7xl mx-auto">
            {/* Print Header (Visible only when printing) */}
            <div className="hidden print-only mb-8 text-center border-b pb-4">
                <h1 className="text-3xl font-bold text-black mb-2">Al-Mohaseb Pro - تقرير مالي</h1>
                <p className="text-gray-600">تاريخ التقرير: {new Date().toLocaleDateString('ar-EG')}</p>
            </div>

            {currentView === 'dashboard' && (
              <Dashboard 
                stats={stats} 
                transactions={transactions} 
                onDeleteTransaction={handleDeleteTransaction} 
              />
            )}

            {currentView === 'invoices' && (
               <Dashboard 
                stats={stats} 
                transactions={transactions} 
                onDeleteTransaction={handleDeleteTransaction} 
              />
            )}

            {currentView === 'clients' && (
              <Clients 
                clients={clients} 
                onDeleteClient={handleDeleteClient}
                onOpenAddModal={() => openModal('client')}
              />
            )}
          </div>
        </div>

        {/* FAB (Floating Action Button) */}
        <button
          onClick={() => openModal('transaction')}
          className="fixed bottom-8 left-8 bg-blue-600 hover:bg-blue-700 text-white w-14 h-14 rounded-full shadow-2xl flex items-center justify-center transition-transform hover:scale-110 active:scale-95 z-40 no-print"
        >
          <Plus size={28} />
        </button>

        {/* Modal */}
        <AddModal 
          isOpen={isModalOpen}
          initialType={modalInitialType}
          onClose={() => setIsModalOpen(false)}
          onSaveTransaction={handleAddTransaction}
          onSaveClient={handleAddClient}
        />

      </main>
    </div>
  );
}

export default App;

