// Transactions
export const loadTransactions = (): Transaction[] => {
  try {
    const data = localStorage.getItem(TRX_KEY);
    return data ? JSON.parse(data) : [];
  } catch (e) {
    console.error("Failed to load transactions", e);
    return [];
  }
};

