  const [itemName, setItemName] = useState('');

  useEffect(() => {
    if (isOpen) {
      // Reset fields based on mode
      setTrxName('');
      setTrxAmount('');
      setEntityName('');
      setEntityPhone('');
      setItemName('');
    }
