import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import Clients from './components/Clients';
import Suppliers from './components/Suppliers';
import Items from './components/Items';
import AddModal from './components/AddModal';
import { ViewState, Transaction, Client, Supplier, Item, Stats, TransactionType, ModalMode } from './types';
import { 
    loadTransactions, saveTransactions, 
    loadClients, saveClients, 
    loadSuppliers, saveSuppliers, 
    loadItems, saveItems, 
    clearAllData 
} from './services/storage';
import { Plus, Printer, Bell, Search, Download } from 'lucide-react';

function App() {
  const [currentView, setCurrentView] = useState<ViewState>('dashboard');

  // Data State
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [clients, setClients] = useState<Client[]>([]);
  const [suppliers, setSuppliers] = useState<Supplier[]>([]);
  const [items, setItems] = useState<Item[]>([]);

  // Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [modalMode, setModalMode] = useState<ModalMode>('transaction');
  const [targetSupplierId, setTargetSupplierId] = useState<number | undefined>(undefined);
  const [targetClientId, setTargetClientId] = useState<number | undefined>(undefined);
  const [targetName, setTargetName] = useState<string>(''); // Name of client/supplier for modal title

  // Editing State
  const [editingId, setEditingId] = useState<number | null>(null);
  const [editingInitialData, setEditingInitialData] = useState<any>(null);

  // Search State
  const [searchTerm, setSearchTerm] = useState('');

  // Load data on mount
  useEffect(() => {
    setTransactions(loadTransactions());
    setClients(loadClients());
    setSuppliers(loadSuppliers());
    setItems(loadItems());
  }, []);

  // Calculate Stats
  const stats: Stats = useMemo(() => {
    let income = 0;
    let expense = 0;
    transactions.forEach(t => {
      if (t.type === 'income') income += t.amount;
      else expense += t.amount;
    });
    return { income, expense, balance: income - expense };
  }, [transactions]);

  // Filter Logic
  const filteredTransactions = useMemo(() => {
    if (!searchTerm) return transactions;
    return transactions.filter(t => 
      t.name.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [transactions, searchTerm]);

  const filteredClients = useMemo(() => {
    if (!searchTerm) return clients;
    return clients.filter(c => 
      c.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      c.phone.includes(searchTerm)
    );
  }, [clients, searchTerm]);

  const filteredSuppliers = useMemo(() => {
    if (!searchTerm) return suppliers;
    return suppliers.filter(s => {
        const nameMatch = s.name.toLowerCase().includes(searchTerm.toLowerCase());
        const phoneMatch = s.phone.includes(searchTerm);
        return nameMatch || phoneMatch;
    });
  }, [suppliers, searchTerm]);

  const filteredItems = useMemo(() => {
    if (!searchTerm) return items;
    return items.filter(i => {
        const itemMatch = i.name.toLowerCase().includes(searchTerm.toLowerCase());
        const supplierMatch = suppliers.find(s => s.id === i.supplierId)?.name.toLowerCase().includes(searchTerm.toLowerCase());
        return itemMatch || supplierMatch;
    });
  }, [items, suppliers, searchTerm]);

  // CSV Export Logic
  const handleExportCSV = () => {
    let csvContent = "data:text/csv;charset=utf-8,\uFEFF"; // BOM for Arabic
    let filename = "export.csv";

    if (currentView === 'clients') {
      csvContent += "ID,Name,Phone\n";
      filteredClients.forEach(c => {
         csvContent += `${c.id},"${c.name}","${c.phone}"\n`;
      });
      filename = "clients.csv";
    } else if (currentView === 'suppliers') {
      csvContent += "ID,Name,Phone\n";
      filteredSuppliers.forEach(s => {
         csvContent += `${s.id},"${s.name}","${s.phone}"\n`;
      });
      filename = "suppliers.csv";
    } else if (currentView === 'items') {
        csvContent += "ID,Name,Supplier\n";
        filteredItems.forEach(i => {
           const supplierName = suppliers.find(s => s.id === i.supplierId)?.name || 'Unknown';
           csvContent += `${i.id},"${i.name}","${supplierName}"\n`;
        });
        filename = "items.csv";
    } else {
      csvContent += "ID,Date,Description,Type,Amount\n";
      filteredTransactions.forEach(t => {
         const typeAr = t.type === 'income' ? 'قبض' : 'صرف';
         csvContent += `${t.id},${t.date},"${t.name}",${typeAr},${t.amount}\n`;
      });
      filename = "transactions.csv";
    }

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", filename);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // --- Handlers (Create & Update) ---

  const handleSaveTransaction = (data: { name: string; amount: number; type: TransactionType; clientId?: number; supplierId?: number }) => {
    const newTrx: Transaction = {
      id: Date.now(),
      name: data.name,
      amount: data.amount,
      type: data.type,
      date: new Date().toLocaleDateString('ar-EG'),
      clientId: data.clientId,
      supplierId: data.supplierId
    };
    const updated = [...transactions, newTrx];
    setTransactions(updated);
    saveTransactions(updated);
    closeModal();
  };

  const handleSaveClient = (data: { name: string; phone: string; image?: string }) => {
    let updated: Client[];

    if (editingId) {
        // Update existing
        updated = clients.map(c => c.id === editingId ? { ...c, ...data, image: data.image || c.image } : c);
    } else {
        // Create new
        const newClient: Client = {
          id: Date.now(),
          name: data.name,
          phone: data.phone,
          image: data.image
        };
        updated = [...clients, newClient];
    }
    setClients(updated);
    saveClients(updated);
    closeModal();
  };

  const handleSaveSupplier = (data: { name: string; phone: string; image?: string }) => {
      let updated: Supplier[];
      if (editingId) {
          updated = suppliers.map(s => s.id === editingId ? { ...s, ...data, image: data.image || s.image } : s);
      } else {
          const newSupplier: Supplier = {
              id: Date.now(),
              name: data.name,
              phone: data.phone,
              image: data.image
          };
          updated = [...suppliers, newSupplier];
      }
      setSuppliers(updated);
      saveSuppliers(updated);
      closeModal();
  };

  const handleSaveItem = (data: { name: string; supplierId: number; image?: string }) => {
      const newItem: Item = {
          id: Date.now(),
          name: data.name,
          supplierId: data.supplierId,
          image: data.image
      };
      const updated = [...items, newItem];
      setItems(updated);
      saveItems(updated);
      closeModal();
  };

  // --- Deletion Handlers ---

  const handleDeleteTransaction = (id: number) => {
    const updated = transactions.filter(t => t.id !== id);
    setTransactions(updated);
    saveTransactions(updated);
  };

  const handleDeleteClient = (id: number) => {
    const updated = clients.filter(c => c.id !== id);
    setClients(updated);
    saveClients(updated);
  };

  const handleDeleteSupplier = (id: number) => {
      const updatedSuppliers = suppliers.filter(s => s.id !== id);
      const updatedItems = items.filter(i => i.supplierId !== id); // Cascade delete items
      setSuppliers(updatedSuppliers);
      setItems(updatedItems);
      saveSuppliers(updatedSuppliers);
      saveItems(updatedItems);
  };

  const handleDeleteItem = (id: number) => {
      const updated = items.filter(i => i.id !== id);
      setItems(updated);
      saveItems(updated);
  };

  const handleClearData = () => {
    clearAllData();
    setTransactions([]);
    setClients([]);
    setSuppliers([]);
    setItems([]);
    window.location.reload();
  };

  // --- Modal & Editing Triggers ---

  const closeModal = () => {
      setIsModalOpen(false);
      setEditingId(null);
      setEditingInitialData(null);
      setTargetClientId(undefined);
      setTargetSupplierId(undefined);
      setTargetName('');
  };

  const openTransactionModal = () => {
      setModalMode('transaction');
      setIsModalOpen(true);
  };

  const openClientModal = () => {
      setModalMode('add-client');
      setIsModalOpen(true);
  };

  const openSupplierModal = () => {
      setModalMode('add-supplier');
      setIsModalOpen(true);
  };

  const openAddItemModal = (supplierId?: number) => {
      setTargetSupplierId(supplierId);
      setModalMode('add-item');
      setIsModalOpen(true);
  };

  // Action Triggers
  const handleClientAction = (clientId: number, clientName: string) => {
      setTargetClientId(clientId);
      setTargetName(clientName);
      setModalMode('client-action');
      setIsModalOpen(true);
  };

  const handleSupplierAction = (supplierId: number, supplierName: string) => {
      setTargetSupplierId(supplierId);
      setTargetName(supplierName);
      setModalMode('supplier-action');
      setIsModalOpen(true);
  };

  // Edit Triggers
  const handleEditClient = (client: Client) => {
      setEditingId(client.id);
      setEditingInitialData(client);
      setModalMode('add-client');
      setIsModalOpen(true);
  };

  const handleEditSupplier = (supplier: Supplier) => {
      setEditingId(supplier.id);
      setEditingInitialData(supplier);
      setModalMode('add-supplier');
      setIsModalOpen(true);
  };

  return (
    <div className="flex min-h-screen bg-slate-50 font-sans">
      <Sidebar 
        currentView={currentView} 
        onChangeView={setCurrentView} 
        onClearData={handleClearData} 
      />

      <main className="flex-1 flex flex-col relative overflow-hidden">
        {/* Header */}
        <header className="h-20 bg-white shadow-sm flex justify-between items-center px-8 z-20 no-print sticky top-0">
          <div>
            <h2 className="text-xl font-bold text-slate-800">
                {currentView === 'dashboard' && 'لوحة التحكم الرئيسية'}
                {currentView === 'clients' && 'إدارة العملاء'}
                {currentView === 'suppliers' && 'الموردين والشركات'}
                {currentView === 'items' && 'المخزن والأصناف'}
                {currentView === 'invoices' && 'سجل الفواتير'}
            </h2>
          </div>

          {/* Search Bar */}
          <div className="flex-1 mx-8 max-w-lg hidden md:block">
            <div className="relative group">
              <Search className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-blue-500 transition-colors" size={18} />
              <input 
                type="text" 
                placeholder="بحث..." 
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full bg-slate-100 border-none rounded-xl py-2.5 pr-10 pl-4 focus:ring-2 focus:ring-blue-500 outline-none transition-all text-sm"
              />
            </div>
          </div>

          <div className="flex items-center gap-3">
             <button 
                onClick={handleExportCSV}
                className="flex items-center gap-2 bg-emerald-600 text-white px-4 py-2 rounded-lg hover:bg-emerald-700 transition text-sm font-bold shadow-sm"
                title="تصدير إلى CSV"
             >
                <Download size={18} />
                <span className="hidden lg:inline">تصدير CSV</span>
             </button>

             <button 
                onClick={() => window.print()}
                className="flex items-center gap-2 bg-slate-800 text-white px-4 py-2 rounded-lg hover:bg-slate-700 transition text-sm font-bold shadow-sm"
             >
                <Printer size={18} />
                <span className="hidden lg:inline">طباعة</span>
             </button>

             <div className="relative cursor-pointer w-10 h-10 rounded-full bg-slate-100 flex items-center justify-center hover:bg-slate-200 transition ml-2">
                <Bell size={20} className="text-slate-600" />
                <span className="absolute top-2 right-2 w-2 h-2 bg-red-500 rounded-full border border-white"></span>
             </div>
          </div>
        </header>

        {/* Content */}
        <div className="flex-1 overflow-auto p-8 relative">
          <div className="max-w-7xl mx-auto">
            {/* Print Header */}
            <div className="hidden print-only mb-8 text-center border-b pb-4">
                <h1 className="text-3xl font-bold text-black mb-2">Al-Mohaseb Pro - تقرير مالي</h1>
                <p className="text-gray-600">تاريخ التقرير: {new Date().toLocaleDateString('ar-EG')}</p>
            </div>

            {currentView === 'dashboard' && (
              <Dashboard 
                stats={stats} 
                transactions={filteredTransactions} 
                onDeleteTransaction={handleDeleteTransaction} 
              />
            )}

            {currentView === 'invoices' && (
               <Dashboard 
                stats={stats} 
                transactions={filteredTransactions} 
                onDeleteTransaction={handleDeleteTransaction} 
              />
            )}

            {currentView === 'clients' && (
              <Clients 
                clients={filteredClients} 
                onDeleteClient={handleDeleteClient}
                onEditClient={handleEditClient}
                onOpenAddModal={openClientModal}
                onClientAction={handleClientAction}
              />
            )}

            {currentView === 'suppliers' && (
              <Suppliers 
                suppliers={filteredSuppliers}
                onDeleteSupplier={handleDeleteSupplier}
                onEditSupplier={handleEditSupplier}
                onOpenAddSupplierModal={openSupplierModal}
                onSupplierAction={handleSupplierAction}
              />
            )}

            {currentView === 'items' && (
              <Items 
                items={filteredItems}
                suppliers={suppliers}
                onDeleteItem={handleDeleteItem}
                onOpenAddItemModal={() => openAddItemModal()}
              />
            )}
          </div>
        </div>

        {/* FAB (Floating Action Button) */}
        <button
          onClick={() => {
              if (currentView === 'clients') openClientModal();
              else if (currentView === 'suppliers') openSupplierModal();
              else if (currentView === 'items') openAddItemModal();
              else openTransactionModal();
          }}
          className={`fixed bottom-8 left-8 text-white w-14 h-14 rounded-full shadow-2xl flex items-center justify-center transition-transform hover:scale-110 active:scale-95 z-40 no-print ${currentView === 'suppliers' ? 'bg-orange-600 hover:bg-orange-700' : currentView === 'items' ? 'bg-slate-700 hover:bg-slate-800' : 'bg-blue-600 hover:bg-blue-700'}`}
        >
          <Plus size={28} />
        </button>

        {/* Modal */}
        <AddModal 
          isOpen={isModalOpen}
          mode={modalMode}
          targetSupplierId={targetSupplierId}
          targetClientId={targetClientId}
          targetName={targetName}
          suppliers={suppliers}
          initialData={editingInitialData}
          onClose={closeModal}
          onSaveTransaction={handleSaveTransaction}
          onSaveClient={handleSaveClient}
          onSaveSupplier={handleSaveSupplier}
          onSaveItem={handleSaveItem}
        />

      </main>
    </div>
  );
}

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { X, Check, Upload, Image as ImageIcon, FileText, Banknote, ArrowRightLeft } from 'lucide-react';
import { TransactionType, ModalMode, Supplier } from '../types';

interface AddModalProps {
  isOpen: boolean;
  mode: ModalMode;
  targetSupplierId?: number;
  targetClientId?: number; // Added for client context
  targetName?: string; // Display name for the client/supplier
  suppliers?: Supplier[];
  initialData?: any;
  onClose: () => void;
  onSaveTransaction: (data: { name: string; amount: number; type: TransactionType; clientId?: number; supplierId?: number }) => void;
  onSaveClient: (data: { name: string; phone: string; image?: string }) => void;
  onSaveSupplier: (data: { name: string; phone: string; image?: string }) => void;
  onSaveItem: (data: { name: string; supplierId: number; image?: string }) => void;
}

const AddModal: React.FC<AddModalProps> = ({ 
    isOpen, 
    mode, 
    targetSupplierId, 
    targetClientId,
    targetName,
    suppliers = [],
    initialData,
    onClose, 
    onSaveTransaction, 
    onSaveClient, 
    onSaveSupplier,
    onSaveItem
}) => {

  // Transaction State
  const [trxName, setTrxName] = useState('');
  const [trxAmount, setTrxAmount] = useState('');
  const [trxType, setTrxType] = useState<TransactionType>('income');
  const [trxSubType, setTrxSubType] = useState<string>(''); // To track specific action (Invoice vs Receipt)

  // Client/Supplier State
  const [entityName, setEntityName] = useState('');
  const [entityPhone, setEntityPhone] = useState('');

  // Item State
  const [itemName, setItemName] = useState('');
  const [selectedSupplierId, setSelectedSupplierId] = useState<number | undefined>(undefined);

  // Image State
  const [selectedImage, setSelectedImage] = useState<string | undefined>(undefined);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedImage(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  useEffect(() => {
    if (isOpen) {
      if (initialData && mode === 'add-client') {
          setEntityName(initialData.name);
          setEntityPhone(initialData.phone);
          setSelectedImage(initialData.image);
      } else if (initialData && mode === 'add-supplier') {
          setEntityName(initialData.name);
          setEntityPhone(initialData.phone);
          setSelectedImage(initialData.image);
      } else {
          // Reset
          setTrxName('');
          setTrxAmount('');
          setEntityName('');
          setEntityPhone('');
          setItemName('');
          setSelectedImage(undefined);
          setSelectedSupplierId(targetSupplierId);

          // Set defaults for specific actions
          if (mode === 'client-action') {
              setTrxType('income'); // Default to receiving money/sales
              setTrxSubType('sales_invoice');
          } else if (mode === 'supplier-action') {
              setTrxType('expense'); // Default to paying money/purchase
              setTrxSubType('purchase_invoice');
          } else {
              setTrxType('income');
              setTrxSubType('');
          }
      }
    }
  }, [isOpen, mode, initialData, targetSupplierId]);

  // Update default name based on sub-type selection
  useEffect(() => {
    if (mode === 'client-action' && targetName) {
        if (trxSubType === 'sales_invoice') setTrxName(`فاتورة بيع - ${targetName}`);
        else if (trxSubType === 'receipt') setTrxName(`سند قبض من ${targetName}`);
        else if (trxSubType === 'refund') setTrxName(`مرتجع نقدي لـ ${targetName}`);
    } else if (mode === 'supplier-action' && targetName) {
        if (trxSubType === 'purchase_invoice') setTrxName(`فاتورة شراء - ${targetName}`);
        else if (trxSubType === 'payment') setTrxName(`سند دفع لـ ${targetName}`);
        else if (trxSubType === 'refund') setTrxName(`مرتجع نقدي من ${targetName}`);
    }
  }, [trxSubType, mode, targetName]);

  if (!isOpen) return null;

  const getTitle = () => {
      if (initialData) return 'تعديل البيانات';
      switch(mode) {
          case 'transaction': return 'تسجيل حركة مالية';
          case 'client-action': return `تسجيل عملية لـ ${targetName}`;
          case 'supplier-action': return `تسجيل عملية لـ ${targetName}`;
          case 'add-client': return 'إضافة عميل جديد';
          case 'add-supplier': return 'إضافة مورد جديد';
          case 'add-item': return 'إضافة صنف جديد';
      }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (mode === 'transaction' || mode === 'client-action' || mode === 'supplier-action') {
      if (!trxName || !trxAmount) return;
      onSaveTransaction({ 
          name: trxName, 
          amount: parseFloat(trxAmount), 
          type: trxType,
          clientId: targetClientId,
          supplierId: targetSupplierId
      });
    } 
    else if (mode === 'add-client') {
      if (!entityName) return;
      onSaveClient({ name: entityName, phone: entityPhone, image: selectedImage });
    }
    else if (mode === 'add-supplier') {
        if (!entityName) return;
        onSaveSupplier({ name: entityName, phone: entityPhone, image: selectedImage });
    }
    else if (mode === 'add-item') {
        const finalSupplierId = targetSupplierId || selectedSupplierId;
        if (!itemName || !finalSupplierId) {
            alert('يرجى كتابة اسم الصنف واختيار المورد');
            return;
        }
        onSaveItem({ name: itemName, supplierId: finalSupplierId, image: selectedImage });
    }
  };

  // Helper for rendering transaction type buttons in normal mode
  const renderNormalTransactionTypes = () => (
    <div className="grid grid-cols-2 gap-4">
      <button
        type="button"
        onClick={() => setTrxType('income')}
        className={`p-3 rounded-xl border-2 font-bold text-sm transition-all ${
          trxType === 'income' 
            ? 'border-emerald-500 bg-emerald-50 text-emerald-700' 
            : 'border-slate-100 hover:border-slate-300 text-slate-500'
        }`}
      >
        قبض (دخل) 💵
      </button>
      <button
        type="button"
        onClick={() => setTrxType('expense')}
        className={`p-3 rounded-xl border-2 font-bold text-sm transition-all ${
          trxType === 'expense' 
            ? 'border-red-500 bg-red-50 text-red-700' 
            : 'border-slate-100 hover:border-slate-300 text-slate-500'
        }`}
      >
        صرف (خرج) 💸
      </button>
    </div>
  );

  // Helper for Client Action Buttons
  const renderClientActionTypes = () => (
      <div className="grid grid-cols-3 gap-2 mb-4">
          <button
            type="button"
            onClick={() => { setTrxType('income'); setTrxSubType('sales_invoice'); }}
            className={`flex flex-col items-center justify-center p-2 rounded-lg border-2 text-xs font-bold transition-all ${
                trxSubType === 'sales_invoice' ? 'border-blue-500 bg-blue-50 text-blue-700' : 'border-slate-100 text-slate-500'
            }`}
          >
              <FileText size={20} className="mb-1" />
              فاتورة بيع
          </button>
          <button
            type="button"
            onClick={() => { setTrxType('income'); setTrxSubType('receipt'); }}
            className={`flex flex-col items-center justify-center p-2 rounded-lg border-2 text-xs font-bold transition-all ${
                trxSubType === 'receipt' ? 'border-emerald-500 bg-emerald-50 text-emerald-700' : 'border-slate-100 text-slate-500'
            }`}
          >
              <Banknote size={20} className="mb-1" />
              سند قبض
          </button>
          <button
            type="button"
            onClick={() => { setTrxType('expense'); setTrxSubType('refund'); }}
            className={`flex flex-col items-center justify-center p-2 rounded-lg border-2 text-xs font-bold transition-all ${
                trxSubType === 'refund' ? 'border-red-500 bg-red-50 text-red-700' : 'border-slate-100 text-slate-500'
            }`}
          >
              <ArrowRightLeft size={20} className="mb-1" />
              مرتجع (صرف)
          </button>
      </div>
  );

  // Helper for Supplier Action Buttons
  const renderSupplierActionTypes = () => (
    <div className="grid grid-cols-3 gap-2 mb-4">
        <button
          type="button"
          onClick={() => { setTrxType('expense'); setTrxSubType('purchase_invoice'); }}
          className={`flex flex-col items-center justify-center p-2 rounded-lg border-2 text-xs font-bold transition-all ${
              trxSubType === 'purchase_invoice' ? 'border-orange-500 bg-orange-50 text-orange-700' : 'border-slate-100 text-slate-500'
          }`}
        >
            <FileText size={20} className="mb-1" />
            فاتورة شراء
        </button>
        <button
          type="button"
          onClick={() => { setTrxType('expense'); setTrxSubType('payment'); }}
          className={`flex flex-col items-center justify-center p-2 rounded-lg border-2 text-xs font-bold transition-all ${
              trxSubType === 'payment' ? 'border-red-500 bg-red-50 text-red-700' : 'border-slate-100 text-slate-500'
          }`}
        >
            <Banknote size={20} className="mb-1" />
            سند دفع
        </button>
        <button
          type="button"
          onClick={() => { setTrxType('income'); setTrxSubType('refund'); }}
          className={`flex flex-col items-center justify-center p-2 rounded-lg border-2 text-xs font-bold transition-all ${
              trxSubType === 'refund' ? 'border-emerald-500 bg-emerald-50 text-emerald-700' : 'border-slate-100 text-slate-500'
          }`}
        >
            <ArrowRightLeft size={20} className="mb-1" />
            مرتجع (قبض)
        </button>
    </div>
);

  return (
    <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex items-center justify-center p-4 fade-in no-print">
      <div className="bg-white rounded-2xl w-full max-w-md shadow-2xl overflow-hidden transform transition-all scale-100 max-h-[90vh] overflow-y-auto">
        <div className="bg-slate-50 px-6 py-4 border-b border-slate-100 flex justify-between items-center sticky top-0 z-10">
          <h3 className="font-bold text-lg text-slate-800">{getTitle()}</h3>
          <button onClick={onClose} className="text-slate-400 hover:text-red-500 transition-colors">
            <X size={24} />
          </button>
        </div>

        <div className="p-6">
          <form onSubmit={handleSubmit} className="space-y-4">

            {/* Image Upload for Client, Supplier, Item */}
            {(mode === 'add-client' || mode === 'add-supplier' || mode === 'add-item') && (
                <div className="flex justify-center mb-4">
                    <div 
                        onClick={() => fileInputRef.current?.click()}
                        className="w-24 h-24 rounded-full border-2 border-dashed border-slate-300 flex items-center justify-center cursor-pointer hover:border-blue-500 hover:bg-blue-50 transition-colors overflow-hidden relative group"
                    >
                        {selectedImage ? (
                            <img src={selectedImage} alt="Preview" className="w-full h-full object-cover" />
                        ) : (
                            <div className="text-center text-slate-400">
                                <Upload size={24} className="mx-auto mb-1" />
                                <span className="text-[10px]">صورة</span>
                            </div>
                        )}
                        <input 
                            type="file" 
                            ref={fileInputRef} 
                            onChange={handleImageChange} 
                            accept="image/*" 
                            className="hidden" 
                        />
                    </div>
                </div>
            )}

            {/* Transaction Modes */}
            {(mode === 'transaction' || mode === 'client-action' || mode === 'supplier-action') && (
              <>
                {mode === 'transaction' && renderNormalTransactionTypes()}
                {mode === 'client-action' && renderClientActionTypes()}
                {mode === 'supplier-action' && renderSupplierActionTypes()}

                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">بيان العملية</label>
                  <input
                    type="text"
                    value={trxName}
                    onChange={(e) => setTrxName(e.target.value)}
                    className="w-full border border-slate-200 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-blue-500 focus:outline-none"
                    placeholder="وصف العملية..."
                    required
                  />
                </div>

                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">المبلغ (ج.م)</label>
                  <input
                    type="number"
                    value={trxAmount}
                    onChange={(e) => setTrxAmount(e.target.value)}
                    className="w-full border border-slate-200 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-blue-500 focus:outline-none font-bold text-lg"
                    placeholder="0.00"
                    min="0"
                    step="0.01"
                    required
                  />
                </div>
              </>
            )}

            {(mode === 'add-client' || mode === 'add-supplier') && (
              <>
                <div className="bg-blue-50 text-blue-800 p-3 rounded-lg text-sm mb-2 font-medium">
                    {mode === 'add-client' ? (initialData ? 'تعديل بيانات العميل' : 'بيانات العميل الجديد') : (initialData ? 'تعديل بيانات المورد' : 'بيانات المورد / الشركة')}
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">الاسم بالكامل</label>
                  <input
                    type="text"
                    value={entityName}
                    onChange={(e) => setEntityName(e.target.value)}
                    className="w-full border border-slate-200 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-blue-500 focus:outline-none"
                    placeholder={mode === 'add-client' ? "اسم العميل" : "اسم الشركة أو المورد"}
                    required
                  />
                </div>

                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">رقم الهاتف</label>
                  <input
                    type="tel"
                    value={entityPhone}
                    onChange={(e) => setEntityPhone(e.target.value)}
                    className="w-full border border-slate-200 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-blue-500 focus:outline-none"
                    placeholder="01xxxxxxxxx"
                  />
                </div>
              </>
            )}

            {mode === 'add-item' && (
                <>
                 <div className="bg-orange-50 text-orange-800 p-3 rounded-lg text-sm mb-2 font-medium">
                    إضافة صنف جديد للمخزن
                </div>
                 <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">اسم الصنف / المنتج</label>
                  <input
                    type="text"
                    value={itemName}
                    onChange={(e) => setItemName(e.target.value)}
                    className="w-full border border-slate-200 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-blue-500 focus:outline-none"
                    placeholder="مثال: أربو، علف بادي..."
                    required
                  />
                </div>

                {!targetSupplierId && (
                    <div>
                        <label className="block text-sm font-semibold text-slate-700 mb-1">المورد / الشركة المنتجة</label>
                        <select 
                            value={selectedSupplierId || ''} 
                            onChange={(e) => setSelectedSupplierId(Number(e.target.value))}
                            className="w-full border border-slate-200 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-blue-500 focus:outline-none bg-white"
                            required
                        >
                            <option value="">اختر المورد...</option>
                            {suppliers.map(s => (
                                <option key={s.id} value={s.id}>{s.name}</option>
                            ))}
                        </select>
                    </div>
                )}
                </>
            )}

            <div className="pt-4 flex gap-3">
              <button
                type="button"
                onClick={onClose}
                className="flex-1 py-3 text-slate-600 bg-slate-100 hover:bg-slate-200 rounded-xl font-bold transition-colors"
              >
                إلغاء
              </button>
              <button
                type="submit"
                className="flex-[2] py-3 text-white bg-blue-600 hover:bg-blue-700 rounded-xl font-bold transition-colors shadow-lg shadow-blue-200 flex items-center justify-center gap-2"
              >
                <Check size={20} />
                {initialData ? 'حفظ التعديلات' : 'حفظ البيانات'}
              </button>
            </div>
          </form>
        </div>
      </div>
    </div>
  );
};

export default AddModal;

import React, { useState, useEffect, useRef } from 'react';
import { X, Check, Upload, Image as ImageIcon, FileText, Banknote, ArrowRightLeft } from 'lucide-react';
import { TransactionType, ModalMode, Supplier, Client } from '../types';

interface AddModalProps {
  isOpen: boolean;
  mode: ModalMode;
  targetSupplierId?: number;
  targetClientId?: number;
  targetName?: string;
  suppliers?: Supplier[];
  clients?: Client[]; // Added clients list
  initialData?: any;
  onClose: () => void;
  onSaveTransaction: (data: { name: string; amount: number; type: TransactionType; clientId?: number; supplierId?: number }) => void;
  onSaveClient: (data: { name: string; phone: string; image?: string }) => void;
  onSaveSupplier: (data: { name: string; phone: string; image?: string }) => void;
  onSaveItem: (data: { name: string; supplierId: number; image?: string }) => void;
}

const AddModal: React.FC<AddModalProps> = ({ 
    isOpen, 
    mode, 
    targetSupplierId, 
    targetClientId,
    targetName,
    suppliers = [],
    clients = [], // Default empty array
    initialData,
    onClose, 
    onSaveTransaction, 
    onSaveClient, 
    onSaveSupplier, 
    onSaveItem
}) => {

  // Transaction State
  const [trxName, setTrxName] = useState('');
  const [trxAmount, setTrxAmount] = useState('');
  const [trxType, setTrxType] = useState<TransactionType>('income');
  const [trxSubType, setTrxSubType] = useState<string>('');

  // Client/Supplier Selection State (for generic transaction mode)
  const [selectedClientId, setSelectedClientId] = useState<number | undefined>(undefined);
  const [selectedTxSupplierId, setSelectedTxSupplierId] = useState<number | undefined>(undefined);

  // Client/Supplier Creation State
  const [entityName, setEntityName] = useState('');
  const [entityPhone, setEntityPhone] = useState('');

  // Item State
  const [itemName, setItemName] = useState('');
  const [selectedSupplierId, setSelectedSupplierId] = useState<number | undefined>(undefined); // For Item creation

  // Image State
  const [selectedImage, setSelectedImage] = useState<string | undefined>(undefined);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedImage(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  useEffect(() => {
    if (isOpen) {
      if (initialData && mode === 'add-client') {
          setEntityName(initialData.name);
          setEntityPhone(initialData.phone);
          setSelectedImage(initialData.image);
      } else if (initialData && mode === 'add-supplier') {
          setEntityName(initialData.name);
          setEntityPhone(initialData.phone);
          setSelectedImage(initialData.image);
      } else {
          // Reset Form
          setTrxName('');
          setTrxAmount('');
          setEntityName('');
          setEntityPhone('');
          setItemName('');
          setSelectedImage(undefined);

          // Reset Selections
          setSelectedSupplierId(targetSupplierId);
          setSelectedClientId(undefined);
          setSelectedTxSupplierId(undefined);

          // Set defaults for specific actions
          if (mode === 'client-action') {
              setTrxType('income');
              setTrxSubType('sales_invoice');
          } else if (mode === 'supplier-action') {
              setTrxType('expense');
              setTrxSubType('purchase_invoice');
          } else {
              setTrxType('income');
              setTrxSubType('');
          }
      }
    }
  }, [isOpen, mode, initialData, targetSupplierId]);

  // Update default name based on sub-type selection
  useEffect(() => {
    if (mode === 'client-action' && targetName) {
        if (trxSubType === 'sales_invoice') setTrxName(`فاتورة بيع - ${targetName}`);
        else if (trxSubType === 'receipt') setTrxName(`سند قبض من ${targetName}`);
        else if (trxSubType === 'refund') setTrxName(`مرتجع نقدي لـ ${targetName}`);
    } else if (mode === 'supplier-action' && targetName) {
        if (trxSubType === 'purchase_invoice') setTrxName(`فاتورة شراء - ${targetName}`);
        else if (trxSubType === 'payment') setTrxName(`سند دفع لـ ${targetName}`);
        else if (trxSubType === 'refund') setTrxName(`مرتجع نقدي من ${targetName}`);
    }
  }, [trxSubType, mode, targetName]);

  if (!isOpen) return null;

  const getTitle = () => {
      if (initialData) return 'تعديل البيانات';
      switch(mode) {
          case 'transaction': return 'إضافة فاتورة / عملية مالية';
          case 'client-action': return `تسجيل عملية لـ ${targetName}`;
          case 'supplier-action': return `تسجيل عملية لـ ${targetName}`;
          case 'add-client': return 'إضافة عميل جديد';
          case 'add-supplier': return 'إضافة مورد جديد';
          case 'add-item': return 'إضافة صنف جديد';
      }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (mode === 'transaction' || mode === 'client-action' || mode === 'supplier-action') {
      if (!trxName || !trxAmount) return;

      // Determine Client/Supplier ID
      let finalClientId = targetClientId;
      let finalSupplierId = targetSupplierId;

      // In generic transaction mode, use selected dropdown values
      if (mode === 'transaction') {
          if (trxType === 'income') finalClientId = selectedClientId;
          if (trxType === 'expense') finalSupplierId = selectedTxSupplierId;
      }

      onSaveTransaction({ 
          name: trxName, 
          amount: parseFloat(trxAmount), 
          type: trxType,
          clientId: finalClientId,
          supplierId: finalSupplierId
      });
    } 
    else if (mode === 'add-client') {
      if (!entityName) return;
      onSaveClient({ name: entityName, phone: entityPhone, image: selectedImage });
    }
    else if (mode === 'add-supplier') {
        if (!entityName) return;
        onSaveSupplier({ name: entityName, phone: entityPhone, image: selectedImage });
    }
    else if (mode === 'add-item') {
        const finalSupplierId = targetSupplierId || selectedSupplierId;
        if (!itemName || !finalSupplierId) {
            alert('يرجى كتابة اسم الصنف واختيار المورد');
            return;
        }
        onSaveItem({ name: itemName, supplierId: finalSupplierId, image: selectedImage });
    }
  };

  // Helper for rendering transaction type buttons in normal mode
  const renderNormalTransactionTypes = () => (
    <div className="grid grid-cols-2 gap-4">
      <button
        type="button"
        onClick={() => { setTrxType('income'); setSelectedTxSupplierId(undefined); }}
        className={`p-3 rounded-xl border-2 flex flex-col items-center justify-center gap-1 transition-all ${
          trxType === 'income' 
            ? 'border-emerald-500 bg-emerald-50 text-emerald-700' 
            : 'border-slate-100 hover:border-slate-300 text-slate-500'
        }`}
      >
        <span className="font-bold text-sm">قبض / فاتورة بيع 💵</span>
        <span className="text-[10px] opacity-70">إيرادات، مبيعات</span>
      </button>
      <button
        type="button"
        onClick={() => { setTrxType('expense'); setSelectedClientId(undefined); }}
        className={`p-3 rounded-xl border-2 flex flex-col items-center justify-center gap-1 transition-all ${
          trxType === 'expense' 
            ? 'border-red-500 bg-red-50 text-red-700' 
            : 'border-slate-100 hover:border-slate-300 text-slate-500'
        }`}
      >
        <span className="font-bold text-sm">صرف / شراء 💸</span>
        <span className="text-[10px] opacity-70">مصروفات، فواتير موردين</span>
      </button>
    </div>
  );

  // Helper for Client Action Buttons
  const renderClientActionTypes = () => (
      <div className="grid grid-cols-3 gap-2 mb-4">
          <button
            type="button"
            onClick={() => { setTrxType('income'); setTrxSubType('sales_invoice'); }}
            className={`flex flex-col items-center justify-center p-2 rounded-lg border-2 text-xs font-bold transition-all ${
                trxSubType === 'sales_invoice' ? 'border-blue-500 bg-blue-50 text-blue-700' : 'border-slate-100 text-slate-500'
            }`}
          >
              <FileText size={20} className="mb-1" />
              فاتورة بيع
          </button>
          <button
            type="button"
            onClick={() => { setTrxType('income'); setTrxSubType('receipt'); }}
            className={`flex flex-col items-center justify-center p-2 rounded-lg border-2 text-xs font-bold transition-all ${
                trxSubType === 'receipt' ? 'border-emerald-500 bg-emerald-50 text-emerald-700' : 'border-slate-100 text-slate-500'
            }`}
          >
              <Banknote size={20} className="mb-1" />
              سند قبض
          </button>
          <button
            type="button"
            onClick={() => { setTrxType('expense'); setTrxSubType('refund'); }}
            className={`flex flex-col items-center justify-center p-2 rounded-lg border-2 text-xs font-bold transition-all ${
                trxSubType === 'refund' ? 'border-red-500 bg-red-50 text-red-700' : 'border-slate-100 text-slate-500'
            }`}
          >
              <ArrowRightLeft size={20} className="mb-1" />
              مرتجع
          </button>
      </div>
  );

  // Helper for Supplier Action Buttons
  const renderSupplierActionTypes = () => (
    <div className="grid grid-cols-3 gap-2 mb-4">
        <button
          type="button"
          onClick={() => { setTrxType('expense'); setTrxSubType('purchase_invoice'); }}
          className={`flex flex-col items-center justify-center p-2 rounded-lg border-2 text-xs font-bold transition-all ${
              trxSubType === 'purchase_invoice' ? 'border-orange-500 bg-orange-50 text-orange-700' : 'border-slate-100 text-slate-500'
          }`}
        >
            <FileText size={20} className="mb-1" />
            فاتورة شراء
        </button>
        <button
          type="button"
          onClick={() => { setTrxType('expense'); setTrxSubType('payment'); }}
          className={`flex flex-col items-center justify-center p-2 rounded-lg border-2 text-xs font-bold transition-all ${
              trxSubType === 'payment' ? 'border-red-500 bg-red-50 text-red-700' : 'border-slate-100 text-slate-500'
          }`}
        >
            <Banknote size={20} className="mb-1" />
            سند دفع
        </button>
        <button
          type="button"
          onClick={() => { setTrxType('income'); setTrxSubType('refund'); }}
          className={`flex flex-col items-center justify-center p-2 rounded-lg border-2 text-xs font-bold transition-all ${
              trxSubType === 'refund' ? 'border-emerald-500 bg-emerald-50 text-emerald-700' : 'border-slate-100 text-slate-500'
          }`}
        >
            <ArrowRightLeft size={20} className="mb-1" />
            مرتجع
        </button>
    </div>
);

  return (
    <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex items-center justify-center p-4 fade-in no-print">
      <div className="bg-white rounded-2xl w-full max-w-md shadow-2xl overflow-hidden transform transition-all scale-100 max-h-[90vh] overflow-y-auto">
        <div className="bg-slate-50 px-6 py-4 border-b border-slate-100 flex justify-between items-center sticky top-0 z-10">
          <h3 className="font-bold text-lg text-slate-800">{getTitle()}</h3>
          <button onClick={onClose} className="text-slate-400 hover:text-red-500 transition-colors">
            <X size={24} />
          </button>
        </div>

        <div className="p-6">
          <form onSubmit={handleSubmit} className="space-y-4">

            {/* Image Upload for Client, Supplier, Item */}
            {(mode === 'add-client' || mode === 'add-supplier' || mode === 'add-item') && (
                <div className="flex justify-center mb-4">
                    <div 
                        onClick={() => fileInputRef.current?.click()}
                        className="w-24 h-24 rounded-full border-2 border-dashed border-slate-300 flex items-center justify-center cursor-pointer hover:border-blue-500 hover:bg-blue-50 transition-colors overflow-hidden relative group"
                    >
                        {selectedImage ? (
                            <img src={selectedImage} alt="Preview" className="w-full h-full object-cover" />
                        ) : (
                            <div className="text-center text-slate-400">
                                <Upload size={24} className="mx-auto mb-1" />
                                <span className="text-[10px]">صورة</span>
                            </div>
                        )}
                        <input 
                            type="file" 
                            ref={fileInputRef} 
                            onChange={handleImageChange} 
                            accept="image/*" 
                            className="hidden" 
                        />
                    </div>
                </div>
            )}

            {/* Transaction Modes */}
            {(mode === 'transaction' || mode === 'client-action' || mode === 'supplier-action') && (
              <>
                {mode === 'transaction' && renderNormalTransactionTypes()}
                {mode === 'client-action' && renderClientActionTypes()}
                {mode === 'supplier-action' && renderSupplierActionTypes()}

                {/* Client/Supplier Selection for Generic Transaction Mode */}
                {mode === 'transaction' && trxType === 'income' && clients && clients.length > 0 && (
                    <div className="bg-blue-50 p-3 rounded-lg border border-blue-100">
                        <label className="block text-xs font-bold text-blue-800 mb-1">تحديد العميل (اختياري)</label>
                        <select 
                            value={selectedClientId || ''}
                            onChange={(e) => {
                                const val = Number(e.target.value);
                                setSelectedClientId(val || undefined);
                                if(val) {
                                    const c = clients.find(cl => cl.id === val);
                                    if(c && !trxName) setTrxName(`فاتورة بيع - ${c.name}`);
                                }
                            }}
                            className="w-full border border-blue-200 rounded-md p-2 text-sm bg-white focus:outline-none"
                        >
                            <option value="">-- عميل عام / نقدي --</option>
                            {clients.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                        </select>
                    </div>
                )}

                {mode === 'transaction' && trxType === 'expense' && suppliers && suppliers.length > 0 && (
                    <div className="bg-orange-50 p-3 rounded-lg border border-orange-100">
                        <label className="block text-xs font-bold text-orange-800 mb-1">تحديد المورد (اختياري)</label>
                        <select 
                            value={selectedTxSupplierId || ''}
                            onChange={(e) => {
                                const val = Number(e.target.value);
                                setSelectedTxSupplierId(val || undefined);
                                if(val) {
                                    const s = suppliers.find(sup => sup.id === val);
                                    if(s && !trxName) setTrxName(`فاتورة شراء - ${s.name}`);
                                }
                            }}
                            className="w-full border border-orange-200 rounded-md p-2 text-sm bg-white focus:outline-none"
                        >
                            <option value="">-- مورد عام / مصروفات تشغيل --</option>
                            {suppliers.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                        </select>
                    </div>
                )}

                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">بيان العملية / الفاتورة</label>
                  <input
                    type="text"
                    value={trxName}
                    onChange={(e) => setTrxName(e.target.value)}
                    className="w-full border border-slate-200 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-blue-500 focus:outline-none"
                    placeholder="مثال: فاتورة رقم 123"
                    required
                  />
                </div>

                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">المبلغ (ج.م)</label>
                  <input
                    type="number"
                    value={trxAmount}
                    onChange={(e) => setTrxAmount(e.target.value)}
                    className="w-full border border-slate-200 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-blue-500 focus:outline-none font-bold text-lg"
                    placeholder="0.00"
                    min="0"
                    step="0.01"
                    required
                  />
                </div>
              </>
            )}

            {(mode === 'add-client' || mode === 'add-supplier') && (
              <>
                <div className="bg-blue-50 text-blue-800 p-3 rounded-lg text-sm mb-2 font-medium">
                    {mode === 'add-client' ? (initialData ? 'تعديل بيانات العميل' : 'بيانات العميل الجديد') : (initialData ? 'تعديل بيانات المورد' : 'بيانات المورد / الشركة')}
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">الاسم بالكامل</label>
                  <input
                    type="text"
                    value={entityName}
                    onChange={(e) => setEntityName(e.target.value)}
                    className="w-full border border-slate-200 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-blue-500 focus:outline-none"
                    placeholder={mode === 'add-client' ? "اسم العميل" : "اسم الشركة أو المورد"}
                    required
                  />
                </div>

                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">رقم الهاتف</label>
                  <input
                    type="tel"
                    value={entityPhone}
                    onChange={(e) => setEntityPhone(e.target.value)}
                    className="w-full border border-slate-200 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-blue-500 focus:outline-none"
                    placeholder="01xxxxxxxxx"
                  />
                </div>
              </>
            )}

            {mode === 'add-item' && (
                <>
                 <div className="bg-orange-50 text-orange-800 p-3 rounded-lg text-sm mb-2 font-medium">
                    إضافة صنف جديد للمخزن
                </div>
                 <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">اسم الصنف / المنتج</label>
                  <input
                    type="text"
                    value={itemName}
                    onChange={(e) => setItemName(e.target.value)}
                    className="w-full border border-slate-200 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-blue-500 focus:outline-none"
                    placeholder="مثال: أربو، علف بادي..."
                    required
                  />
                </div>

                {!targetSupplierId && (
                    <div>
                        <label className="block text-sm font-semibold text-slate-700 mb-1">المورد / الشركة المنتجة</label>
                        <select 
                            value={selectedSupplierId || ''} 
                            onChange={(e) => setSelectedSupplierId(Number(e.target.value))}
                            className="w-full border border-slate-200 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-blue-500 focus:outline-none bg-white"
                            required
                        >
                            <option value="">اختر المورد...</option>
                            {suppliers.map(s => (
                                <option key={s.id} value={s.id}>{s.name}</option>
                            ))}
                        </select>
                    </div>
                )}
                </>
            )}

            <div className="pt-4 flex gap-3">
              <button
                type="button"
                onClick={onClose}
                className="flex-1 py-3 text-slate-600 bg-slate-100 hover:bg-slate-200 rounded-xl font-bold transition-colors"
              >
                إلغاء
              </button>
              <button
                type="submit"
                className="flex-[2] py-3 text-white bg-blue-600 hover:bg-blue-700 rounded-xl font-bold transition-colors shadow-lg shadow-blue-200 flex items-center justify-center gap-2"
              >
                <Check size={20} />
                {initialData ? 'حفظ التعديلات' : 'حفظ البيانات'}
              </button>
            </div>
          </form>
        </div>
      </div>
    </div>
  );
};

export default AddModal;

import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import Clients from './components/Clients';
import Suppliers from './components/Suppliers';
import Items from './components/Items';
import AddModal from './components/AddModal';
import { ViewState, Transaction, Client, Supplier, Item, Stats, TransactionType, ModalMode } from './types';
import { 
    loadTransactions, saveTransactions, 
    loadClients, saveClients, 
    loadSuppliers, saveSuppliers, 
    loadItems, saveItems, 
    clearAllData 
} from './services/storage';
import { Plus, Printer, Bell, Search, Download } from 'lucide-react';

function App() {
  const [currentView, setCurrentView] = useState<ViewState>('dashboard');

  // Data State
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [clients, setClients] = useState<Client[]>([]);
  const [suppliers, setSuppliers] = useState<Supplier[]>([]);
  const [items, setItems] = useState<Item[]>([]);

  // Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [modalMode, setModalMode] = useState<ModalMode>('transaction');
  const [targetSupplierId, setTargetSupplierId] = useState<number | undefined>(undefined);
  const [targetClientId, setTargetClientId] = useState<number | undefined>(undefined);
  const [targetName, setTargetName] = useState<string>(''); // Name of client/supplier for modal title

  // Editing State
  const [editingId, setEditingId] = useState<number | null>(null);
  const [editingInitialData, setEditingInitialData] = useState<any>(null);

  // Search State
  const [searchTerm, setSearchTerm] = useState('');

  // Load data on mount
  useEffect(() => {
    setTransactions(loadTransactions());
    setClients(loadClients());
    setSuppliers(loadSuppliers());
    setItems(loadItems());
  }, []);

  // Calculate Stats
  const stats: Stats = useMemo(() => {
    let income = 0;
    let expense = 0;
    transactions.forEach(t => {
      if (t.type === 'income') income += t.amount;
      else expense += t.amount;
    });
    return { income, expense, balance: income - expense };
  }, [transactions]);

  // Filter Logic
  const filteredTransactions = useMemo(() => {
    if (!searchTerm) return transactions;
    return transactions.filter(t => 
      t.name.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [transactions, searchTerm]);

  const filteredClients = useMemo(() => {
    if (!searchTerm) return clients;
    return clients.filter(c => 
      c.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      c.phone.includes(searchTerm)
    );
  }, [clients, searchTerm]);

  const filteredSuppliers = useMemo(() => {
    if (!searchTerm) return suppliers;
    return suppliers.filter(s => {
        const nameMatch = s.name.toLowerCase().includes(searchTerm.toLowerCase());
        const phoneMatch = s.phone.includes(searchTerm);
        return nameMatch || phoneMatch;
    });
  }, [suppliers, searchTerm]);

  const filteredItems = useMemo(() => {
    if (!searchTerm) return items;
    return items.filter(i => {
        const itemMatch = i.name.toLowerCase().includes(searchTerm.toLowerCase());
        const supplierMatch = suppliers.find(s => s.id === i.supplierId)?.name.toLowerCase().includes(searchTerm.toLowerCase());
        return itemMatch || supplierMatch;
    });
  }, [items, suppliers, searchTerm]);

  // CSV Export Logic
  const handleExportCSV = () => {
    let csvContent = "data:text/csv;charset=utf-8,\uFEFF"; // BOM for Arabic
    let filename = "export.csv";

    if (currentView === 'clients') {
      csvContent += "ID,Name,Phone\n";
      filteredClients.forEach(c => {
         csvContent += `${c.id},"${c.name}","${c.phone}"\n`;
      });
      filename = "clients.csv";
    } else if (currentView === 'suppliers') {
      csvContent += "ID,Name,Phone\n";
      filteredSuppliers.forEach(s => {
         csvContent += `${s.id},"${s.name}","${s.phone}"\n`;
      });
      filename = "suppliers.csv";
    } else if (currentView === 'items') {
        csvContent += "ID,Name,Supplier\n";
        filteredItems.forEach(i => {
           const supplierName = suppliers.find(s => s.id === i.supplierId)?.name || 'Unknown';
           csvContent += `${i.id},"${i.name}","${supplierName}"\n`;
        });
        filename = "items.csv";
    } else {
      csvContent += "ID,Date,Description,Type,Amount\n";
      filteredTransactions.forEach(t => {
         const typeAr = t.type === 'income' ? 'قبض' : 'صرف';
         csvContent += `${t.id},${t.date},"${t.name}",${typeAr},${t.amount}\n`;
      });
      filename = "transactions.csv";
    }

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", filename);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // --- Handlers (Create & Update) ---

  const handleSaveTransaction = (data: { name: string; amount: number; type: TransactionType; clientId?: number; supplierId?: number }) => {
    const newTrx: Transaction = {
      id: Date.now(),
      name: data.name,
      amount: data.amount,
      type: data.type,
      date: new Date().toLocaleDateString('ar-EG'),
      clientId: data.clientId,
      supplierId: data.supplierId
    };
    const updated = [...transactions, newTrx];
    setTransactions(updated);
    saveTransactions(updated);
    closeModal();
  };

  const handleSaveClient = (data: { name: string; phone: string; image?: string }) => {
    let updated: Client[];

    if (editingId) {
        // Update existing
        updated = clients.map(c => c.id === editingId ? { ...c, ...data, image: data.image || c.image } : c);
    } else {
        // Create new
        const newClient: Client = {
          id: Date.now(),
          name: data.name,
          phone: data.phone,
          image: data.image
        };
        updated = [...clients, newClient];
    }
    setClients(updated);
    saveClients(updated);
    closeModal();
  };

  const handleSaveSupplier = (data: { name: string; phone: string; image?: string }) => {
      let updated: Supplier[];
      if (editingId) {
          updated = suppliers.map(s => s.id === editingId ? { ...s, ...data, image: data.image || s.image } : s);
      } else {
          const newSupplier: Supplier = {
              id: Date.now(),
              name: data.name,
              phone: data.phone,
              image: data.image
          };
          updated = [...suppliers, newSupplier];
      }
      setSuppliers(updated);
      saveSuppliers(updated);
      closeModal();
  };

  const handleSaveItem = (data: { name: string; supplierId: number; image?: string }) => {
      const newItem: Item = {
          id: Date.now(),
          name: data.name,
          supplierId: data.supplierId,
          image: data.image
      };
      const updated = [...items, newItem];
      setItems(updated);
      saveItems(updated);
      closeModal();
  };

  // --- Deletion Handlers ---

  const handleDeleteTransaction = (id: number) => {
    const updated = transactions.filter(t => t.id !== id);
    setTransactions(updated);
    saveTransactions(updated);
  };

  const handleDeleteClient = (id: number) => {
    const updated = clients.filter(c => c.id !== id);
    setClients(updated);
    saveClients(updated);
  };

  const handleDeleteSupplier = (id: number) => {
      const updatedSuppliers = suppliers.filter(s => s.id !== id);
      const updatedItems = items.filter(i => i.supplierId !== id); // Cascade delete items
      setSuppliers(updatedSuppliers);
      setItems(updatedItems);
      saveSuppliers(updatedSuppliers);
      saveItems(updatedItems);
  };

  const handleDeleteItem = (id: number) => {
      const updated = items.filter(i => i.id !== id);
      setItems(updated);
      saveItems(updated);
  };

  const handleClearData = () => {
    clearAllData();
    setTransactions([]);
    setClients([]);
    setSuppliers([]);
    setItems([]);
    window.location.reload();
  };

  // --- Modal & Editing Triggers ---

  const closeModal = () => {
      setIsModalOpen(false);
      setEditingId(null);
      setEditingInitialData(null);
      setTargetClientId(undefined);
      setTargetSupplierId(undefined);
      setTargetName('');
  };

  const openTransactionModal = () => {
      setModalMode('transaction');
      setIsModalOpen(true);
  };

  const openClientModal = () => {
      setModalMode('add-client');
      setIsModalOpen(true);
  };

  const openSupplierModal = () => {
      setModalMode('add-supplier');
      setIsModalOpen(true);
  };

  const openAddItemModal = (supplierId?: number) => {
      setTargetSupplierId(supplierId);
      setModalMode('add-item');
      setIsModalOpen(true);
  };

  // Action Triggers
  const handleClientAction = (clientId: number, clientName: string) => {
      setTargetClientId(clientId);
      setTargetName(clientName);
      setModalMode('client-action');
      setIsModalOpen(true);
  };

  const handleSupplierAction = (supplierId: number, supplierName: string) => {
      setTargetSupplierId(supplierId);
      setTargetName(supplierName);
      setModalMode('supplier-action');
      setIsModalOpen(true);
  };

  // Edit Triggers
  const handleEditClient = (client: Client) => {
      setEditingId(client.id);
      setEditingInitialData(client);
      setModalMode('add-client');
      setIsModalOpen(true);
  };

  const handleEditSupplier = (supplier: Supplier) => {
      setEditingId(supplier.id);
      setEditingInitialData(supplier);
      setModalMode('add-supplier');
      setIsModalOpen(true);
  };

  return (
    <div className="flex min-h-screen bg-slate-50 font-sans">
      <Sidebar 
        currentView={currentView} 
        onChangeView={setCurrentView} 
        onClearData={handleClearData} 
      />

      <main className="flex-1 flex flex-col relative overflow-hidden">
        {/* Header */}
        <header className="h-20 bg-white shadow-sm flex justify-between items-center px-8 z-20 no-print sticky top-0">
          <div>
            <h2 className="text-xl font-bold text-slate-800">
                {currentView === 'dashboard' && 'لوحة التحكم الرئيسية'}
                {currentView === 'clients' && 'إدارة العملاء'}
                {currentView === 'suppliers' && 'الموردين والشركات'}
                {currentView === 'items' && 'المخزن والأصناف'}
                {currentView === 'invoices' && 'سجل الفواتير'}
            </h2>
          </div>

          {/* Search Bar */}
          <div className="flex-1 mx-8 max-w-lg hidden md:block">
            <div className="relative group">
              <Search className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-blue-500 transition-colors" size={18} />
              <input 
                type="text" 
                placeholder="بحث..." 
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full bg-slate-100 border-none rounded-xl py-2.5 pr-10 pl-4 focus:ring-2 focus:ring-blue-500 outline-none transition-all text-sm"
              />
            </div>
          </div>

          <div className="flex items-center gap-3">
             <button 
                onClick={handleExportCSV}
                className="flex items-center gap-2 bg-emerald-600 text-white px-4 py-2 rounded-lg hover:bg-emerald-700 transition text-sm font-bold shadow-sm"
                title="تصدير إلى CSV"
             >
                <Download size={18} />
                <span className="hidden lg:inline">تصدير CSV</span>
             </button>

             <button 
                onClick={() => window.print()}
                className="flex items-center gap-2 bg-slate-800 text-white px-4 py-2 rounded-lg hover:bg-slate-700 transition text-sm font-bold shadow-sm"
             >
                <Printer size={18} />
                <span className="hidden lg:inline">طباعة</span>
             </button>

             <div className="relative cursor-pointer w-10 h-10 rounded-full bg-slate-100 flex items-center justify-center hover:bg-slate-200 transition ml-2">
                <Bell size={20} className="text-slate-600" />
                <span className="absolute top-2 right-2 w-2 h-2 bg-red-500 rounded-full border border-white"></span>
             </div>
          </div>
        </header>

        {/* Content */}
        <div className="flex-1 overflow-auto p-8 relative">
          <div className="max-w-7xl mx-auto">
            {/* Print Header */}
            <div className="hidden print-only mb-8 text-center border-b pb-4">
                <h1 className="text-3xl font-bold text-black mb-2">Al-Mohaseb Pro - تقرير مالي</h1>
                <p className="text-gray-600">تاريخ التقرير: {new Date().toLocaleDateString('ar-EG')}</p>
            </div>

            {currentView === 'dashboard' && (
              <Dashboard 
                stats={stats} 
                transactions={filteredTransactions} 
                onDeleteTransaction={handleDeleteTransaction} 
              />
            )}

            {currentView === 'invoices' && (
               <Dashboard 
                stats={stats} 
                transactions={filteredTransactions} 
                onDeleteTransaction={handleDeleteTransaction} 
              />
            )}

            {currentView === 'clients' && (
              <Clients 
                clients={filteredClients} 
                onDeleteClient={handleDeleteClient}
                onEditClient={handleEditClient}
                onOpenAddModal={openClientModal}
                onClientAction={handleClientAction}
              />
            )}

            {currentView === 'suppliers' && (
              <Suppliers 
                suppliers={filteredSuppliers}
                onDeleteSupplier={handleDeleteSupplier}
                onEditSupplier={handleEditSupplier}
                onOpenAddSupplierModal={openSupplierModal}
                onSupplierAction={handleSupplierAction}
              />
            )}

            {currentView === 'items' && (
              <Items 
                items={filteredItems}
                suppliers={suppliers}
                onDeleteItem={handleDeleteItem}
                onOpenAddItemModal={() => openAddItemModal()}
              />
            )}
          </div>
        </div>

        {/* FAB (Floating Action Button) */}
        <button
          onClick={() => {
              if (currentView === 'clients') openClientModal();
              else if (currentView === 'suppliers') openSupplierModal();
              else if (currentView === 'items') openAddItemModal();
              else openTransactionModal();
          }}
          className={`fixed bottom-8 left-8 text-white w-14 h-14 rounded-full shadow-2xl flex items-center justify-center transition-transform hover:scale-110 active:scale-95 z-40 no-print ${currentView === 'suppliers' ? 'bg-orange-600 hover:bg-orange-700' : currentView === 'items' ? 'bg-slate-700 hover:bg-slate-800' : 'bg-blue-600 hover:bg-blue-700'}`}
        >
          <Plus size={28} />
        </button>

        {/* Modal */}
        <AddModal 
          isOpen={isModalOpen}
          mode={modalMode}
          targetSupplierId={targetSupplierId}
          targetClientId={targetClientId}
          targetName={targetName}
          suppliers={suppliers}
          clients={clients}
          initialData={editingInitialData}
          onClose={closeModal}
          onSaveTransaction={handleSaveTransaction}
          onSaveClient={handleSaveClient}
          onSaveSupplier={handleSaveSupplier}
          onSaveItem={handleSaveItem}
        />

      </main>
    </div>
  );
}

export default App;

export type TransactionType = 'income' | 'expense';

export interface Transaction {
  id: number;
  name: string;
  amount: number;
  type: TransactionType;
  date: string;
  clientId?: number;
  supplierId?: number;
  // New fields for Trade
  itemId?: number;
  quantity?: number;
  unitPrice?: number;
  relatedTransactionId?: number; // To link the purchase and sale
}

export interface Client {
  id: number;
  name: string;
  phone: string;
  image?: string;
}

export interface Supplier {
  id: number;
  name: string;
  phone: string;
  image?: string;
}

export interface Item {
  id: number;
  name: string;
  supplierId: number;
  image?: string;
}

export type ViewState = 'dashboard' | 'clients' | 'suppliers' | 'items' | 'invoices';

export interface Stats {
  income: number;
  expense: number;
  balance: number;
}

export type ModalMode = 'transaction' | 'trade' | 'add-client' | 'add-supplier' | 'add-item' | 'client-action' | 'supplier-action';

import React, { useState, useEffect, useRef } from 'react';
import { X, Check, Upload, Image as ImageIcon, FileText, Banknote, ArrowRightLeft, ShoppingCart, Calculator } from 'lucide-react';
import { TransactionType, ModalMode, Supplier, Client, Item } from '../types';

interface AddModalProps {
  isOpen: boolean;
  mode: ModalMode;
  targetSupplierId?: number;
  targetClientId?: number;
  targetName?: string;
  suppliers?: Supplier[];
  clients?: Client[];
  items?: Item[]; // Added items prop
  initialData?: any;
  onClose: () => void;
  onSaveTransaction: (data: { name: string; amount: number; type: TransactionType; clientId?: number; supplierId?: number }) => void;
  onSaveTrade: (data: { 
      clientId: number; 
      supplierId: number; 
      itemId: number; 
      itemName: string;
      quantity: number; 
      buyPrice: number; 
      sellPrice: number; 
  }) => void; // New handler for trade
  onSaveClient: (data: { name: string; phone: string; image?: string }) => void;
  onSaveSupplier: (data: { name: string; phone: string; image?: string }) => void;
  onSaveItem: (data: { name: string; supplierId: number; image?: string }) => void;
}

const AddModal: React.FC<AddModalProps> = ({ 
    isOpen, 
    mode, 
    targetSupplierId, 
    targetClientId,
    targetName,
    suppliers = [],
    clients = [],
    items = [],
    initialData,
    onClose, 
    onSaveTransaction, 
    onSaveTrade,
    onSaveClient, 
    onSaveSupplier, 
    onSaveItem
}) => {

  // Transaction State
  const [trxName, setTrxName] = useState('');
  const [trxAmount, setTrxAmount] = useState('');
  const [trxType, setTrxType] = useState<TransactionType>('income');
  const [trxSubType, setTrxSubType] = useState<string>('');

  // Generic Selection State
  const [selectedClientId, setSelectedClientId] = useState<number | undefined>(undefined);
  const [selectedTxSupplierId, setSelectedTxSupplierId] = useState<number | undefined>(undefined);

  // Trade Specific State
  const [tradeClientId, setTradeClientId] = useState<number | undefined>(undefined);
  const [tradeSupplierId, setTradeSupplierId] = useState<number | undefined>(undefined);
  const [tradeItemId, setTradeItemId] = useState<number | undefined>(undefined);
  const [tradeQuantity, setTradeQuantity] = useState<string>('');
  const [tradeBuyPrice, setTradeBuyPrice] = useState<string>('');
  const [tradeSellPrice, setTradeSellPrice] = useState<string>('');

  // Entity Creation State
  const [entityName, setEntityName] = useState('');
  const [entityPhone, setEntityPhone] = useState('');

  // Item Creation State
  const [itemName, setItemName] = useState('');
  const [selectedSupplierId, setSelectedSupplierId] = useState<number | undefined>(undefined);

  // Image State
  const [selectedImage, setSelectedImage] = useState<string | undefined>(undefined);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedImage(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  useEffect(() => {
    if (isOpen) {
      if (initialData && (mode === 'add-client' || mode === 'add-supplier')) {
          setEntityName(initialData.name);
          setEntityPhone(initialData.phone);
          setSelectedImage(initialData.image);
      } else {
          // Reset All Forms
          setTrxName('');
          setTrxAmount('');
          setEntityName('');
          setEntityPhone('');
          setItemName('');
          setSelectedImage(undefined);

          // Reset Selections
          setSelectedSupplierId(targetSupplierId);
          setSelectedClientId(undefined);
          setSelectedTxSupplierId(undefined);

          // Reset Trade
          setTradeClientId(undefined);
          setTradeSupplierId(undefined);
          setTradeItemId(undefined);
          setTradeQuantity('');
          setTradeBuyPrice('');
          setTradeSellPrice('');

          // Set defaults for specific actions
          if (mode === 'client-action') {
              setTrxType('income');
              setTrxSubType('sales_invoice');
          } else if (mode === 'supplier-action') {
              setTrxType('expense');
              setTrxSubType('purchase_invoice');
          } else {
              setTrxType('income');
              setTrxSubType('');
          }
      }
    }
  }, [isOpen, mode, initialData, targetSupplierId]);

  // Update name based on sub-type
  useEffect(() => {
    if (mode === 'client-action' && targetName) {
        if (trxSubType === 'sales_invoice') setTrxName(`فاتورة بيع - ${targetName}`);
        else if (trxSubType === 'receipt') setTrxName(`سند قبض من ${targetName}`);
        else if (trxSubType === 'refund') setTrxName(`مرتجع نقدي لـ ${targetName}`);
    } else if (mode === 'supplier-action' && targetName) {
        if (trxSubType === 'purchase_invoice') setTrxName(`فاتورة شراء - ${targetName}`);
        else if (trxSubType === 'payment') setTrxName(`سند دفع لـ ${targetName}`);
        else if (trxSubType === 'refund') setTrxName(`مرتجع نقدي من ${targetName}`);
    }
  }, [trxSubType, mode, targetName]);

  // Filter items based on selected supplier in Trade mode
  const filteredTradeItems = items.filter(i => !tradeSupplierId || i.supplierId === tradeSupplierId);

  if (!isOpen) return null;

  const getTitle = () => {
      if (initialData) return 'تعديل البيانات';
      switch(mode) {
          case 'transaction': return 'إضافة عملية مالية سريعة';
          case 'trade': return 'فاتورة تجارية (شراء وبيع)';
          case 'client-action': return `تسجيل عملية لـ ${targetName}`;
          case 'supplier-action': return `تسجيل عملية لـ ${targetName}`;
          case 'add-client': return 'إضافة عميل جديد';
          case 'add-supplier': return 'إضافة مورد جديد';
          case 'add-item': return 'إضافة صنف جديد';
      }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (mode === 'trade') {
        if (!tradeClientId || !tradeSupplierId || !tradeItemId || !tradeQuantity || !tradeBuyPrice || !tradeSellPrice) {
            alert("يرجى إكمال جميع حقول الفاتورة التجارية");
            return;
        }
        const selectedItem = items.find(i => i.id === tradeItemId);
        onSaveTrade({
            clientId: tradeClientId,
            supplierId: tradeSupplierId,
            itemId: tradeItemId,
            itemName: selectedItem ? selectedItem.name : 'Unknown',
            quantity: parseFloat(tradeQuantity),
            buyPrice: parseFloat(tradeBuyPrice),
            sellPrice: parseFloat(tradeSellPrice)
        });
    }
    else if (mode === 'transaction' || mode === 'client-action' || mode === 'supplier-action') {
      if (!trxName || !trxAmount) return;

      let finalClientId = targetClientId;
      let finalSupplierId = targetSupplierId;

      if (mode === 'transaction') {
          if (trxType === 'income') finalClientId = selectedClientId;
          if (trxType === 'expense') finalSupplierId = selectedTxSupplierId;
      }

      onSaveTransaction({ 
          name: trxName, 
          amount: parseFloat(trxAmount), 
          type: trxType,
          clientId: finalClientId,
          supplierId: finalSupplierId
      });
    } 
    else if (mode === 'add-client') {
      if (!entityName) return;
      onSaveClient({ name: entityName, phone: entityPhone, image: selectedImage });
    }
    else if (mode === 'add-supplier') {
        if (!entityName) return;
        onSaveSupplier({ name: entityName, phone: entityPhone, image: selectedImage });
    }
    else if (mode === 'add-item') {
        const finalSupplierId = targetSupplierId || selectedSupplierId;
        if (!itemName || !finalSupplierId) {
            alert('يرجى كتابة اسم الصنف واختيار المورد');
            return;
        }
        onSaveItem({ name: itemName, supplierId: finalSupplierId, image: selectedImage });
    }
  };

  const renderNormalTransactionTypes = () => (
    <div className="grid grid-cols-2 gap-4">
      <button
        type="button"
        onClick={() => { setTrxType('income'); setSelectedTxSupplierId(undefined); }}
        className={`p-3 rounded-xl border-2 flex flex-col items-center justify-center gap-1 transition-all ${
          trxType === 'income' 
            ? 'border-emerald-500 bg-emerald-50 text-emerald-700' 
            : 'border-slate-100 hover:border-slate-300 text-slate-500'
        }`}
      >
        <span className="font-bold text-sm">قبض / فاتورة بيع 💵</span>
      </button>
      <button
        type="button"
        onClick={() => { setTrxType('expense'); setSelectedClientId(undefined); }}
        className={`p-3 rounded-xl border-2 flex flex-col items-center justify-center gap-1 transition-all ${
          trxType === 'expense' 
            ? 'border-red-500 bg-red-50 text-red-700' 
            : 'border-slate-100 hover:border-slate-300 text-slate-500'
        }`}
      >
        <span className="font-bold text-sm">صرف / شراء 💸</span>
      </button>
    </div>
  );

  return (
    <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex items-center justify-center p-4 fade-in no-print">
      <div className="bg-white rounded-2xl w-full max-w-md shadow-2xl overflow-hidden transform transition-all scale-100 max-h-[90vh] overflow-y-auto">
        <div className="bg-slate-50 px-6 py-4 border-b border-slate-100 flex justify-between items-center sticky top-0 z-10">
          <h3 className="font-bold text-lg text-slate-800">{getTitle()}</h3>
          <button onClick={onClose} className="text-slate-400 hover:text-red-500 transition-colors">
            <X size={24} />
          </button>
        </div>

        <div className="p-6">
          <form onSubmit={handleSubmit} className="space-y-4">

            {/* Image Upload for Client, Supplier, Item */}
            {(mode === 'add-client' || mode === 'add-supplier' || mode === 'add-item') && (
                <div className="flex justify-center mb-4">
                    <div 
                        onClick={() => fileInputRef.current?.click()}
                        className="w-24 h-24 rounded-full border-2 border-dashed border-slate-300 flex items-center justify-center cursor-pointer hover:border-blue-500 hover:bg-blue-50 transition-colors overflow-hidden relative group"
                    >
                        {selectedImage ? (
                            <img src={selectedImage} alt="Preview" className="w-full h-full object-cover" />
                        ) : (
                            <div className="text-center text-slate-400">
                                <Upload size={24} className="mx-auto mb-1" />
                                <span className="text-[10px]">صورة</span>
                            </div>
                        )}
                        <input type="file" ref={fileInputRef} onChange={handleImageChange} accept="image/*" className="hidden" />
                    </div>
                </div>
            )}

            {/* === TRADE MODE (COMMERCIAL INVOICE) === */}
            {mode === 'trade' && (
                <div className="space-y-4">
                    <div className="bg-blue-50 p-3 rounded-lg text-xs text-blue-800 mb-2">
                        هذه الفاتورة تقوم بإنشاء عملية توريد من المورد (دين عليك) وعملية بيع للعميل (دين لك) في آن واحد.
                    </div>

                    {/* Step 1: Who and From Whom */}
                    <div className="grid grid-cols-2 gap-3">
                        <div>
                            <label className="block text-xs font-bold text-slate-700 mb-1">المورد (مصدر الكتاكيت)</label>
                            <select 
                                value={tradeSupplierId || ''} 
                                onChange={(e) => setTradeSupplierId(Number(e.target.value))}
                                className="w-full border border-slate-300 rounded-lg p-2 text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                                required
                            >
                                <option value="">اختر المورد...</option>
                                {suppliers.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                            </select>
                        </div>
                        <div>
                            <label className="block text-xs font-bold text-slate-700 mb-1">العميل (المشتري)</label>
                            <select 
                                value={tradeClientId || ''} 
                                onChange={(e) => setTradeClientId(Number(e.target.value))}
                                className="w-full border border-slate-300 rounded-lg p-2 text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                                required
                            >
                                <option value="">اختر العميل...</option>
                                {clients.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                            </select>
                        </div>
                    </div>

                    {/* Step 2: What */}
                    <div>
                        <label className="block text-xs font-bold text-slate-700 mb-1">الصنف / النوع</label>
                        <select 
                            value={tradeItemId || ''} 
                            onChange={(e) => setTradeItemId(Number(e.target.value))}
                            className="w-full border border-slate-300 rounded-lg p-2 text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                            required
                        >
                            <option value="">
                                {tradeSupplierId ? 'اختر الصنف من هذا المورد...' : 'اختر المورد أولاً...'}
                            </option>
                            {filteredTradeItems.map(i => <option key={i.id} value={i.id}>{i.name}</option>)}
                        </select>
                    </div>

                    {/* Step 3: How many and Prices */}
                    <div>
                         <label className="block text-xs font-bold text-slate-700 mb-1">العدد / الكمية</label>
                         <input type="number" value={tradeQuantity} onChange={e => setTradeQuantity(e.target.value)} className="w-full border border-slate-300 rounded-lg p-2 text-center font-bold" placeholder="0" required />
                    </div>

                    <div className="grid grid-cols-2 gap-3 bg-slate-50 p-3 rounded-xl border border-slate-200">
                        <div>
                            <label className="block text-xs font-bold text-red-600 mb-1">سعر الشراء (اليوم)</label>
                            <input 
                                type="number" 
                                value={tradeBuyPrice} 
                                onChange={e => setTradeBuyPrice(e.target.value)} 
                                className="w-full border border-red-200 rounded-lg p-2 text-sm text-center focus:ring-red-500 outline-none" 
                                placeholder="0.00" 
                                step="0.01"
                                required 
                            />
                        </div>
                        <div>
                            <label className="block text-xs font-bold text-emerald-600 mb-1">سعر البيع (للعميل)</label>
                            <input 
                                type="number" 
                                value={tradeSellPrice} 
                                onChange={e => setTradeSellPrice(e.target.value)} 
                                className="w-full border border-emerald-200 rounded-lg p-2 text-sm text-center focus:ring-emerald-500 outline-none" 
                                placeholder="0.00" 
                                step="0.01"
                                required 
                            />
                        </div>
                    </div>

                    {/* Summary Calculation */}
                    {(tradeQuantity && tradeBuyPrice && tradeSellPrice) && (
                        <div className="bg-slate-800 text-white p-3 rounded-lg text-xs space-y-1">
                            <div className="flex justify-between">
                                <span>إجمالي التوريد (للمورد):</span>
                                <span className="font-bold text-red-300">{(parseFloat(tradeQuantity) * parseFloat(tradeBuyPrice)).toLocaleString()} ج.م</span>
                            </div>
                            <div className="flex justify-between border-b border-slate-600 pb-1">
                                <span>إجمالي البيع (للعميل):</span>
                                <span className="font-bold text-emerald-300">{(parseFloat(tradeQuantity) * parseFloat(tradeSellPrice)).toLocaleString()} ج.م</span>
                            </div>
                            <div className="flex justify-between pt-1 font-bold text-sm">
                                <span>الربح المتوقع:</span>
                                <span className="text-yellow-400">{((parseFloat(tradeQuantity) * parseFloat(tradeSellPrice)) - (parseFloat(tradeQuantity) * parseFloat(tradeBuyPrice))).toLocaleString()} ج.م</span>
                            </div>
                        </div>
                    )}
                </div>
            )}

            {/* Normal Modes */}
            {(mode === 'transaction' || mode === 'client-action' || mode === 'supplier-action') && (
              <>
                {mode === 'transaction' && renderNormalTransactionTypes()}

                {/* Simplified Client/Supplier Selects for quick actions */}
                {mode === 'transaction' && trxType === 'income' && (
                    <div className="bg-blue-50 p-3 rounded-lg border border-blue-100">
                        <label className="block text-xs font-bold text-blue-800 mb-1">تحديد العميل</label>
                        <select 
                            value={selectedClientId || ''}
                            onChange={(e) => setSelectedClientId(Number(e.target.value))}
                            className="w-full border border-blue-200 rounded-md p-2 text-sm bg-white focus:outline-none"
                        >
                            <option value="">-- عميل عام / نقدي --</option>
                            {clients.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                        </select>
                    </div>
                )}

                {mode === 'transaction' && trxType === 'expense' && (
                    <div className="bg-orange-50 p-3 rounded-lg border border-orange-100">
                         <label className="block text-xs font-bold text-orange-800 mb-1">تحديد المورد</label>
                        <select 
                            value={selectedTxSupplierId || ''}
                            onChange={(e) => setSelectedTxSupplierId(Number(e.target.value))}
                            className="w-full border border-orange-200 rounded-md p-2 text-sm bg-white focus:outline-none"
                        >
                            <option value="">-- مورد عام / مصروفات --</option>
                            {suppliers.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                        </select>
                    </div>
                )}

                {mode !== 'transaction' && mode !== 'client-action' && mode !== 'supplier-action' ? null : (
                  <>
                    <div>
                    <label className="block text-sm font-semibold text-slate-700 mb-1">البيان</label>
                    <input
                        type="text"
                        value={trxName}
                        onChange={(e) => setTrxName(e.target.value)}
                        className="w-full border border-slate-200 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-blue-500 focus:outline-none"
                        placeholder="وصف العملية..."
                        required
                    />
                    </div>
                    <div>
                    <label className="block text-sm font-semibold text-slate-700 mb-1">المبلغ (ج.م)</label>
                    <input
                        type="number"
                        value={trxAmount}
                        onChange={(e) => setTrxAmount(e.target.value)}
                        className="w-full border border-slate-200 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-blue-500 focus:outline-none font-bold text-lg"
                        placeholder="0.00"
                        min="0"
                        step="0.01"
                        required
                    />
                    </div>
                  </>
                )}
              </>
            )}

            {/* Add Entity Modes */}
            {(mode === 'add-client' || mode === 'add-supplier') && (
              <>
                <div className="bg-blue-50 text-blue-800 p-3 rounded-lg text-sm mb-2 font-medium">
                    {mode === 'add-client' ? (initialData ? 'تعديل بيانات العميل' : 'بيانات العميل الجديد') : (initialData ? 'تعديل بيانات المورد' : 'بيانات المورد / الشركة')}
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">الاسم بالكامل</label>
                  <input type="text" value={entityName} onChange={(e) => setEntityName(e.target.value)} className="w-full border border-slate-200 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-blue-500 focus:outline-none" required />
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">رقم الهاتف</label>
                  <input type="tel" value={entityPhone} onChange={(e) => setEntityPhone(e.target.value)} className="w-full border border-slate-200 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-blue-500 focus:outline-none" />
                </div>
              </>
            )}

            {/* Add Item Mode */}
            {mode === 'add-item' && (
                <>
                 <div className="bg-orange-50 text-orange-800 p-3 rounded-lg text-sm mb-2 font-medium">إضافة صنف جديد للمخزن</div>
                 <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">اسم الصنف / المنتج</label>
                  <input type="text" value={itemName} onChange={(e) => setItemName(e.target.value)} className="w-full border border-slate-200 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-blue-500 focus:outline-none" required />
                </div>
                {!targetSupplierId && (
                    <div>
                        <label className="block text-sm font-semibold text-slate-700 mb-1">المورد / الشركة المنتجة</label>
                        <select value={selectedSupplierId || ''} onChange={(e) => setSelectedSupplierId(Number(e.target.value))} className="w-full border border-slate-200 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-blue-500 focus:outline-none bg-white" required>
                            <option value="">اختر المورد...</option>
                            {suppliers.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                        </select>
                    </div>
                )}
                </>
            )}

            <div className="pt-4 flex gap-3">
              <button type="button" onClick={onClose} className="flex-1 py-3 text-slate-600 bg-slate-100 hover:bg-slate-200 rounded-xl font-bold transition-colors">إلغاء</button>
              <button type="submit" className="flex-[2] py-3 text-white bg-blue-600 hover:bg-blue-700 rounded-xl font-bold transition-colors shadow-lg shadow-blue-200 flex items-center justify-center gap-2">
                <Check size={20} />
                {initialData ? 'حفظ التعديلات' : 'حفظ البيانات'}
              </button>
            </div>
          </form>
        </div>
      </div>
    </div>
  );
};

export default AddModal;

import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import Clients from './components/Clients';
import Suppliers from './components/Suppliers';
import Items from './components/Items';
import AddModal from './components/AddModal';
import { ViewState, Transaction, Client, Supplier, Item, Stats, TransactionType, ModalMode } from './types';
import { 
    loadTransactions, saveTransactions, 
    loadClients, saveClients, 
    loadSuppliers, saveSuppliers, 
    loadItems, saveItems, 
    clearAllData 
} from './services/storage';
import { Plus, Printer, Bell, Search, Download, ShoppingCart } from 'lucide-react';

function App() {
  const [currentView, setCurrentView] = useState<ViewState>('dashboard');

  // Data State
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [clients, setClients] = useState<Client[]>([]);
  const [suppliers, setSuppliers] = useState<Supplier[]>([]);
  const [items, setItems] = useState<Item[]>([]);

  // Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [modalMode, setModalMode] = useState<ModalMode>('transaction');
  const [targetSupplierId, setTargetSupplierId] = useState<number | undefined>(undefined);
  const [targetClientId, setTargetClientId] = useState<number | undefined>(undefined);
  const [targetName, setTargetName] = useState<string>('');

  // Editing State
  const [editingId, setEditingId] = useState<number | null>(null);
  const [editingInitialData, setEditingInitialData] = useState<any>(null);

  // Search State
  const [searchTerm, setSearchTerm] = useState('');

  // Load data on mount
  useEffect(() => {
    setTransactions(loadTransactions());
    setClients(loadClients());
    setSuppliers(loadSuppliers());
    setItems(loadItems());
  }, []);

  // Calculate Stats
  const stats: Stats = useMemo(() => {
    let income = 0;
    let expense = 0;
    transactions.forEach(t => {
      if (t.type === 'income') income += t.amount;
      else expense += t.amount;
    });
    return { income, expense, balance: income - expense };
  }, [transactions]);

  // Filter Logic
  const filteredTransactions = useMemo(() => {
    if (!searchTerm) return transactions;
    return transactions.filter(t => 
      t.name.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [transactions, searchTerm]);

  const filteredClients = useMemo(() => {
    if (!searchTerm) return clients;
    return clients.filter(c => 
      c.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      c.phone.includes(searchTerm)
    );
  }, [clients, searchTerm]);

  const filteredSuppliers = useMemo(() => {
    if (!searchTerm) return suppliers;
    return suppliers.filter(s => {
        const nameMatch = s.name.toLowerCase().includes(searchTerm.toLowerCase());
        const phoneMatch = s.phone.includes(searchTerm);
        return nameMatch || phoneMatch;
    });
  }, [suppliers, searchTerm]);

  const filteredItems = useMemo(() => {
    if (!searchTerm) return items;
    return items.filter(i => {
        const itemMatch = i.name.toLowerCase().includes(searchTerm.toLowerCase());
        const supplierMatch = suppliers.find(s => s.id === i.supplierId)?.name.toLowerCase().includes(searchTerm.toLowerCase());
        return itemMatch || supplierMatch;
    });
  }, [items, suppliers, searchTerm]);

  // CSV Export Logic
  const handleExportCSV = () => {
    let csvContent = "data:text/csv;charset=utf-8,\uFEFF"; 
    let filename = "export.csv";

    if (currentView === 'clients') {
      csvContent += "ID,Name,Phone\n";
      filteredClients.forEach(c => { csvContent += `${c.id},"${c.name}","${c.phone}"\n`; });
      filename = "clients.csv";
    } else if (currentView === 'suppliers') {
      csvContent += "ID,Name,Phone\n";
      filteredSuppliers.forEach(s => { csvContent += `${s.id},"${s.name}","${s.phone}"\n`; });
      filename = "suppliers.csv";
    } else if (currentView === 'items') {
        csvContent += "ID,Name,Supplier\n";
        filteredItems.forEach(i => {
           const supplierName = suppliers.find(s => s.id === i.supplierId)?.name || 'Unknown';
           csvContent += `${i.id},"${i.name}","${supplierName}"\n`;
        });
        filename = "items.csv";
    } else {
      csvContent += "ID,Date,Description,Type,Amount\n";
      filteredTransactions.forEach(t => {
         const typeAr = t.type === 'income' ? 'قبض' : 'صرف';
         csvContent += `${t.id},${t.date},"${t.name}",${typeAr},${t.amount}\n`;
      });
      filename = "transactions.csv";
    }

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", filename);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // --- Handlers ---

  const handleSaveTransaction = (data: { name: string; amount: number; type: TransactionType; clientId?: number; supplierId?: number }) => {
    const newTrx: Transaction = {
      id: Date.now(),
      name: data.name,
      amount: data.amount,
      type: data.type,
      date: new Date().toLocaleDateString('ar-EG'),
      clientId: data.clientId,
      supplierId: data.supplierId
    };
    const updated = [...transactions, newTrx];
    setTransactions(updated);
    saveTransactions(updated);
    closeModal();
  };

  const handleSaveTrade = (data: { 
      clientId: number; 
      supplierId: number; 
      itemId: number; 
      itemName: string;
      quantity: number; 
      buyPrice: number; 
      sellPrice: number; 
  }) => {
      const now = Date.now();
      const dateStr = new Date().toLocaleDateString('ar-EG');

      // 1. Create Purchase Transaction (Expense) linked to Supplier
      // This represents the debt owed to supplier (Supply)
      const purchaseTrx: Transaction = {
          id: now,
          name: `توريد: ${data.itemName} (عدد ${data.quantity})`,
          amount: data.quantity * data.buyPrice,
          type: 'expense',
          date: dateStr,
          supplierId: data.supplierId,
          itemId: data.itemId,
          quantity: data.quantity,
          unitPrice: data.buyPrice
      };

      // 2. Create Sale Transaction (Income) linked to Client
      // This represents the debt owed by client (Sale not collected yet, but recorded)
      const saleTrx: Transaction = {
          id: now + 1,
          name: `بيع: ${data.itemName} (عدد ${data.quantity})`,
          amount: data.quantity * data.sellPrice,
          type: 'income',
          date: dateStr,
          clientId: data.clientId,
          itemId: data.itemId,
          quantity: data.quantity,
          unitPrice: data.sellPrice,
          relatedTransactionId: now // Link to purchase
      };

      const updated = [...transactions, purchaseTrx, saleTrx];
      setTransactions(updated);
      saveTransactions(updated);
      closeModal();
  };

  const handleSaveClient = (data: { name: string; phone: string; image?: string }) => {
    let updated: Client[];
    if (editingId) {
        updated = clients.map(c => c.id === editingId ? { ...c, ...data, image: data.image || c.image } : c);
    } else {
        const newClient: Client = { id: Date.now(), name: data.name, phone: data.phone, image: data.image };
        updated = [...clients, newClient];
    }
    setClients(updated);
    saveClients(updated);
    closeModal();
  };

  const handleSaveSupplier = (data: { name: string; phone: string; image?: string }) => {
      let updated: Supplier[];
      if (editingId) {
          updated = suppliers.map(s => s.id === editingId ? { ...s, ...data, image: data.image || s.image } : s);
      } else {
          const newSupplier: Supplier = { id: Date.now(), name: data.name, phone: data.phone, image: data.image };
          updated = [...suppliers, newSupplier];
      }
      setSuppliers(updated);
      saveSuppliers(updated);
      closeModal();
  };

  const handleSaveItem = (data: { name: string; supplierId: number; image?: string }) => {
      const newItem: Item = { id: Date.now(), name: data.name, supplierId: data.supplierId, image: data.image };
      const updated = [...items, newItem];
      setItems(updated);
      saveItems(updated);
      closeModal();
  };

  // --- Deletion Handlers ---
  const handleDeleteTransaction = (id: number) => {
    const updated = transactions.filter(t => t.id !== id);
    setTransactions(updated);
    saveTransactions(updated);
  };
  const handleDeleteClient = (id: number) => {
    const updated = clients.filter(c => c.id !== id);
    setClients(updated);
    saveClients(updated);
  };
  const handleDeleteSupplier = (id: number) => {
      const updatedSuppliers = suppliers.filter(s => s.id !== id);
      const updatedItems = items.filter(i => i.supplierId !== id); 
      setSuppliers(updatedSuppliers);
      setItems(updatedItems);
      saveSuppliers(updatedSuppliers);
      saveItems(updatedItems);
  };
  const handleDeleteItem = (id: number) => {
      const updated = items.filter(i => i.id !== id);
      setItems(updated);
      saveItems(updated);
  };
  const handleClearData = () => {
    clearAllData();
    setTransactions([]);
    setClients([]);
    setSuppliers([]);
    setItems([]);
    window.location.reload();
  };

  // --- Modal Triggers ---
  const closeModal = () => {
      setIsModalOpen(false);
      setEditingId(null);
      setEditingInitialData(null);
      setTargetClientId(undefined);
      setTargetSupplierId(undefined);
      setTargetName('');
  };

  const openTransactionModal = () => {
      setModalMode('transaction');
      setIsModalOpen(true);
  };

  const openTradeModal = () => {
      setModalMode('trade');
      setIsModalOpen(true);
  };

  const openClientModal = () => {
      setModalMode('add-client');
      setIsModalOpen(true);
  };
  const openSupplierModal = () => {
      setModalMode('add-supplier');
      setIsModalOpen(true);
  };
  const openAddItemModal = (supplierId?: number) => {
      setTargetSupplierId(supplierId);
      setModalMode('add-item');
      setIsModalOpen(true);
  };
  const handleClientAction = (clientId: number, clientName: string) => {
      setTargetClientId(clientId);
      setTargetName(clientName);
      setModalMode('client-action');
      setIsModalOpen(true);
  };
  const handleSupplierAction = (supplierId: number, supplierName: string) => {
      setTargetSupplierId(supplierId);
      setTargetName(supplierName);
      setModalMode('supplier-action');
      setIsModalOpen(true);
  };
  const handleEditClient = (client: Client) => {
      setEditingId(client.id);
      setEditingInitialData(client);
      setModalMode('add-client');
      setIsModalOpen(true);
  };
  const handleEditSupplier = (supplier: Supplier) => {
      setEditingId(supplier.id);
      setEditingInitialData(supplier);
      setModalMode('add-supplier');
      setIsModalOpen(true);
  };

  return (
    <div className="flex min-h-screen bg-slate-50 font-sans">
      <Sidebar 
        currentView={currentView} 
        onChangeView={setCurrentView} 
        onClearData={handleClearData} 
      />

      <main className="flex-1 flex flex-col relative overflow-hidden">
        {/* Header */}
        <header className="h-20 bg-white shadow-sm flex justify-between items-center px-8 z-20 no-print sticky top-0">
          <div>
            <h2 className="text-xl font-bold text-slate-800">
                {currentView === 'dashboard' && 'لوحة التحكم الرئيسية'}
                {currentView === 'clients' && 'إدارة العملاء'}
                {currentView === 'suppliers' && 'الموردين والشركات'}
                {currentView === 'items' && 'المخزن والأصناف'}
                {currentView === 'invoices' && 'سجل الفواتير'}
            </h2>
          </div>

          <div className="flex-1 mx-8 max-w-lg hidden md:block">
            <div className="relative group">
              <Search className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-blue-500 transition-colors" size={18} />
              <input 
                type="text" 
                placeholder="بحث..." 
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full bg-slate-100 border-none rounded-xl py-2.5 pr-10 pl-4 focus:ring-2 focus:ring-blue-500 outline-none transition-all text-sm"
              />
            </div>
          </div>

          <div className="flex items-center gap-3">
             {/* New Trade Button in Header */}
             <button 
                onClick={openTradeModal}
                className="hidden lg:flex items-center gap-2 bg-slate-900 text-white px-4 py-2 rounded-lg hover:bg-slate-700 transition text-sm font-bold shadow-sm"
                title="فاتورة تجارية جديدة (بيع وشراء)"
             >
                <ShoppingCart size={18} />
                <span>فاتورة تجارية</span>
             </button>

             <button onClick={handleExportCSV} className="flex items-center gap-2 bg-emerald-600 text-white px-4 py-2 rounded-lg hover:bg-emerald-700 transition text-sm font-bold shadow-sm" title="تصدير إلى CSV">
                <Download size={18} />
                <span className="hidden xl:inline">تصدير CSV</span>
             </button>
             <button onClick={() => window.print()} className="flex items-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition text-sm font-bold shadow-sm">
                <Printer size={18} />
                <span className="hidden xl:inline">طباعة</span>
             </button>
          </div>
        </header>

        {/* Content */}
        <div className="flex-1 overflow-auto p-8 relative">
          <div className="max-w-7xl mx-auto">
            <div className="hidden print-only mb-8 text-center border-b pb-4">
                <h1 className="text-3xl font-bold text-black mb-2">Al-Mohaseb Pro - تقرير مالي</h1>
                <p className="text-gray-600">تاريخ التقرير: {new Date().toLocaleDateString('ar-EG')}</p>
            </div>

            {currentView === 'dashboard' && <Dashboard stats={stats} transactions={filteredTransactions} onDeleteTransaction={handleDeleteTransaction} />}
            {currentView === 'invoices' && <Dashboard stats={stats} transactions={filteredTransactions} onDeleteTransaction={handleDeleteTransaction} />}
            {currentView === 'clients' && <Clients clients={filteredClients} onDeleteClient={handleDeleteClient} onEditClient={handleEditClient} onOpenAddModal={openClientModal} onClientAction={handleClientAction} />}
            {currentView === 'suppliers' && <Suppliers suppliers={filteredSuppliers} onDeleteSupplier={handleDeleteSupplier} onEditSupplier={handleEditSupplier} onOpenAddSupplierModal={openSupplierModal} onSupplierAction={handleSupplierAction} />}
            {currentView === 'items' && <Items items={filteredItems} suppliers={suppliers} onDeleteItem={handleDeleteItem} onOpenAddItemModal={() => openAddItemModal()} />}
          </div>
        </div>

        {/* FAB */}
        <button
          onClick={() => {
              if (currentView === 'clients') openClientModal();
              else if (currentView === 'suppliers') openSupplierModal();
              else if (currentView === 'items') openAddItemModal();
              else openTransactionModal();
          }}
          className={`fixed bottom-8 left-8 text-white w-14 h-14 rounded-full shadow-2xl flex items-center justify-center transition-transform hover:scale-110 active:scale-95 z-40 no-print ${currentView === 'suppliers' ? 'bg-orange-600 hover:bg-orange-700' : currentView === 'items' ? 'bg-slate-700 hover:bg-slate-800' : 'bg-blue-600 hover:bg-blue-700'}`}
        >
          <Plus size={28} />
        </button>

        <AddModal 
          isOpen={isModalOpen}
          mode={modalMode}
          targetSupplierId={targetSupplierId}
          targetClientId={targetClientId}
          targetName={targetName}
          suppliers={suppliers}
          clients={clients}
          items={items}
          initialData={editingInitialData}
          onClose={closeModal}
          onSaveTransaction={handleSaveTransaction}
          onSaveTrade={handleSaveTrade}
          onSaveClient={handleSaveClient}
          onSaveSupplier={handleSaveSupplier}
          onSaveItem={handleSaveItem}
        />
      </main>
    </div>
  );
}

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { X, Check, Upload, Image as ImageIcon, FileText, Banknote, ArrowRightLeft, ShoppingCart, Calculator } from 'lucide-react';
import { TransactionType, ModalMode, Supplier, Client, Item } from '../types';

interface AddModalProps {
  isOpen: boolean;
  mode: ModalMode;
  targetSupplierId?: number;
  targetClientId?: number;
  targetName?: string;
  suppliers?: Supplier[];
  clients?: Client[];
  items?: Item[]; // Added items prop
  initialData?: any;
  onClose: () => void;
  onSaveTransaction: (data: { name: string; amount: number; type: TransactionType; clientId?: number; supplierId?: number }) => void;
  onSaveTrade: (data: { 
      clientId: number; 
      supplierId: number; 
      itemId: number; 
      itemName: string;
      quantity: number; 
      buyPrice: number; 
      sellPrice: number; 
  }) => void; // New handler for trade
  onSaveClient: (data: { name: string; phone: string; image?: string }) => void;
  onSaveSupplier: (data: { name: string; phone: string; image?: string }) => void;
  onSaveItem: (data: { name: string; supplierId: number; image?: string }) => void;
}

const AddModal: React.FC<AddModalProps> = ({ 
    isOpen, 
    mode, 
    targetSupplierId, 
    targetClientId,
    targetName,
    suppliers = [],
    clients = [],
    items = [],
    initialData,
    onClose, 
    onSaveTransaction, 
    onSaveTrade,
    onSaveClient, 
    onSaveSupplier, 
    onSaveItem
}) => {

  // Transaction State
  const [trxName, setTrxName] = useState('');
  const [trxAmount, setTrxAmount] = useState('');
  const [trxType, setTrxType] = useState<TransactionType>('income');
  const [trxSubType, setTrxSubType] = useState<string>('');

  // Generic Selection State
  const [selectedClientId, setSelectedClientId] = useState<number | undefined>(undefined);
  const [selectedTxSupplierId, setSelectedTxSupplierId] = useState<number | undefined>(undefined);

  // Trade Specific State
  const [tradeClientId, setTradeClientId] = useState<number | undefined>(undefined);
  const [tradeSupplierId, setTradeSupplierId] = useState<number | undefined>(undefined);
  const [tradeItemId, setTradeItemId] = useState<number | undefined>(undefined);
  const [tradeQuantity, setTradeQuantity] = useState<string>('');
  const [tradeBuyPrice, setTradeBuyPrice] = useState<string>('');
  const [tradeSellPrice, setTradeSellPrice] = useState<string>('');

  // Entity Creation State
  const [entityName, setEntityName] = useState('');
  const [entityPhone, setEntityPhone] = useState('');

  // Item Creation State
  const [itemName, setItemName] = useState('');
  const [selectedSupplierId, setSelectedSupplierId] = useState<number | undefined>(undefined);

  // Image State
  const [selectedImage, setSelectedImage] = useState<string | undefined>(undefined);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedImage(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  useEffect(() => {
    if (isOpen) {
      if (initialData) {
          // Pre-fill based on mode
          if (mode === 'add-client' || mode === 'add-supplier') {
            setEntityName(initialData.name);
            setEntityPhone(initialData.phone);
            setSelectedImage(initialData.image);
          } else if (mode === 'transaction') {
            setTrxName(initialData.name);
            setTrxAmount(initialData.amount.toString());
            setTrxType(initialData.type);
            // Pre-select client/supplier if exists
            setSelectedClientId(initialData.clientId);
            setSelectedTxSupplierId(initialData.supplierId);
          } else if (mode === 'add-item') {
            setItemName(initialData.name);
            setSelectedSupplierId(initialData.supplierId);
            setSelectedImage(initialData.image);
          }
      } else {
          // Reset All Forms for New Entry
          setTrxName('');
          setTrxAmount('');
          setEntityName('');
          setEntityPhone('');
          setItemName('');
          setSelectedImage(undefined);

          // Reset Selections
          setSelectedSupplierId(targetSupplierId);
          setSelectedClientId(undefined);
          setSelectedTxSupplierId(undefined);

          // Reset Trade
          setTradeClientId(undefined);
          setTradeSupplierId(undefined);
          setTradeItemId(undefined);
          setTradeQuantity('');
          setTradeBuyPrice('');
          setTradeSellPrice('');

          // Set defaults for specific actions
          if (mode === 'client-action') {
              setTrxType('income');
              setTrxSubType('sales_invoice');
          } else if (mode === 'supplier-action') {
              setTrxType('expense');
              setTrxSubType('purchase_invoice');
          } else {
              setTrxType('income');
              setTrxSubType('');
          }
      }
    }
  }, [isOpen, mode, initialData, targetSupplierId]);

  // Update name based on sub-type (Only if not editing existing data)
  useEffect(() => {
    if (!initialData) {
        if (mode === 'client-action' && targetName) {
            if (trxSubType === 'sales_invoice') setTrxName(`فاتورة بيع - ${targetName}`);
            else if (trxSubType === 'receipt') setTrxName(`سند قبض من ${targetName}`);
            else if (trxSubType === 'refund') setTrxName(`مرتجع نقدي لـ ${targetName}`);
        } else if (mode === 'supplier-action' && targetName) {
            if (trxSubType === 'purchase_invoice') setTrxName(`فاتورة شراء - ${targetName}`);
            else if (trxSubType === 'payment') setTrxName(`سند دفع لـ ${targetName}`);
            else if (trxSubType === 'refund') setTrxName(`مرتجع نقدي من ${targetName}`);
        }
    }
  }, [trxSubType, mode, targetName, initialData]);

  // Filter items based on selected supplier in Trade mode
  const filteredTradeItems = items.filter(i => !tradeSupplierId || i.supplierId === tradeSupplierId);

  if (!isOpen) return null;

  const getTitle = () => {
      if (initialData) return 'تعديل البيانات';
      switch(mode) {
          case 'transaction': return 'إضافة عملية مالية سريعة';
          case 'trade': return 'فاتورة تجارية (شراء وبيع)';
          case 'client-action': return `تسجيل عملية لـ ${targetName}`;
          case 'supplier-action': return `تسجيل عملية لـ ${targetName}`;
          case 'add-client': return 'إضافة عميل جديد';
          case 'add-supplier': return 'إضافة مورد جديد';
          case 'add-item': return 'إضافة صنف جديد';
      }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (mode === 'trade') {
        if (!tradeClientId || !tradeSupplierId || !tradeItemId || !tradeQuantity || !tradeBuyPrice || !tradeSellPrice) {
            alert("يرجى إكمال جميع حقول الفاتورة التجارية");
            return;
        }
        const selectedItem = items.find(i => i.id === tradeItemId);
        onSaveTrade({
            clientId: tradeClientId,
            supplierId: tradeSupplierId,
            itemId: tradeItemId,
            itemName: selectedItem ? selectedItem.name : 'Unknown',
            quantity: parseFloat(tradeQuantity),
            buyPrice: parseFloat(tradeBuyPrice),
            sellPrice: parseFloat(tradeSellPrice)
        });
    }
    else if (mode === 'transaction' || mode === 'client-action' || mode === 'supplier-action') {
      if (!trxName || !trxAmount) return;

      let finalClientId = targetClientId;
      let finalSupplierId = targetSupplierId;

      if (mode === 'transaction') {
          if (trxType === 'income') finalClientId = selectedClientId;
          if (trxType === 'expense') finalSupplierId = selectedTxSupplierId;
      }

      onSaveTransaction({ 
          name: trxName, 
          amount: parseFloat(trxAmount), 
          type: trxType,
          clientId: finalClientId,
          supplierId: finalSupplierId
      });
    } 
    else if (mode === 'add-client') {
      if (!entityName) return;
      onSaveClient({ name: entityName, phone: entityPhone, image: selectedImage });
    }
    else if (mode === 'add-supplier') {
        if (!entityName) return;
        onSaveSupplier({ name: entityName, phone: entityPhone, image: selectedImage });
    }
    else if (mode === 'add-item') {
        const finalSupplierId = targetSupplierId || selectedSupplierId;
        if (!itemName || !finalSupplierId) {
            alert('يرجى كتابة اسم الصنف واختيار المورد');
            return;
        }
        onSaveItem({ name: itemName, supplierId: finalSupplierId, image: selectedImage });
    }
  };

  const renderNormalTransactionTypes = () => (
    <div className="grid grid-cols-2 gap-4">
      <button
        type="button"
        onClick={() => { setTrxType('income'); setSelectedTxSupplierId(undefined); }}
        className={`p-3 rounded-xl border-2 flex flex-col items-center justify-center gap-1 transition-all ${
          trxType === 'income' 
            ? 'border-emerald-500 bg-emerald-50 text-emerald-700' 
            : 'border-slate-100 hover:border-slate-300 text-slate-500'
        }`}
      >
        <span className="font-bold text-sm">قبض / فاتورة بيع 💵</span>
      </button>
      <button
        type="button"
        onClick={() => { setTrxType('expense'); setSelectedClientId(undefined); }}
        className={`p-3 rounded-xl border-2 flex flex-col items-center justify-center gap-1 transition-all ${
          trxType === 'expense' 
            ? 'border-red-500 bg-red-50 text-red-700' 
            : 'border-slate-100 hover:border-slate-300 text-slate-500'
        }`}
      >
        <span className="font-bold text-sm">صرف / شراء 💸</span>
      </button>
    </div>
  );

  return (
    <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex items-center justify-center p-4 fade-in no-print">
      <div className="bg-white rounded-2xl w-full max-w-md shadow-2xl overflow-hidden transform transition-all scale-100 max-h-[90vh] overflow-y-auto">
        <div className="bg-slate-50 px-6 py-4 border-b border-slate-100 flex justify-between items-center sticky top-0 z-10">
          <h3 className="font-bold text-lg text-slate-800">{getTitle()}</h3>
          <button onClick={onClose} className="text-slate-400 hover:text-red-500 transition-colors">
            <X size={24} />
          </button>
        </div>

        <div className="p-6">
          <form onSubmit={handleSubmit} className="space-y-4">

            {/* Image Upload for Client, Supplier, Item */}
            {(mode === 'add-client' || mode === 'add-supplier' || mode === 'add-item') && (
                <div className="flex justify-center mb-4">
                    <div 
                        onClick={() => fileInputRef.current?.click()}
                        className="w-24 h-24 rounded-full border-2 border-dashed border-slate-300 flex items-center justify-center cursor-pointer hover:border-blue-500 hover:bg-blue-50 transition-colors overflow-hidden relative group"
                    >
                        {selectedImage ? (
                            <img src={selectedImage} alt="Preview" className="w-full h-full object-cover" />
                        ) : (
                            <div className="text-center text-slate-400">
                                <Upload size={24} className="mx-auto mb-1" />
                                <span className="text-[10px]">صورة</span>
                            </div>
                        )}
                        <input type="file" ref={fileInputRef} onChange={handleImageChange} accept="image/*" className="hidden" />
                    </div>
                </div>
            )}

            {/* === TRADE MODE (COMMERCIAL INVOICE) === */}
            {mode === 'trade' && (
                <div className="space-y-4">
                    <div className="bg-blue-50 p-3 rounded-lg text-xs text-blue-800 mb-2">
                        هذه الفاتورة تقوم بإنشاء عملية توريد من المورد (دين عليك) وعملية بيع للعميل (دين لك) في آن واحد.
                    </div>

                    {/* Step 1: Who and From Whom */}
                    <div className="grid grid-cols-2 gap-3">
                        <div>
                            <label className="block text-xs font-bold text-slate-700 mb-1">المورد (مصدر الكتاكيت)</label>
                            <select 
                                value={tradeSupplierId || ''} 
                                onChange={(e) => setTradeSupplierId(Number(e.target.value))}
                                className="w-full border border-slate-300 rounded-lg p-2 text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                                required
                            >
                                <option value="">اختر المورد...</option>
                                {suppliers.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                            </select>
                        </div>
                        <div>
                            <label className="block text-xs font-bold text-slate-700 mb-1">العميل (المشتري)</label>
                            <select 
                                value={tradeClientId || ''} 
                                onChange={(e) => setTradeClientId(Number(e.target.value))}
                                className="w-full border border-slate-300 rounded-lg p-2 text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                                required
                            >
                                <option value="">اختر العميل...</option>
                                {clients.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                            </select>
                        </div>
                    </div>

                    {/* Step 2: What */}
                    <div>
                        <label className="block text-xs font-bold text-slate-700 mb-1">الصنف / النوع</label>
                        <select 
                            value={tradeItemId || ''} 
                            onChange={(e) => setTradeItemId(Number(e.target.value))}
                            className="w-full border border-slate-300 rounded-lg p-2 text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                            required
                        >
                            <option value="">
                                {tradeSupplierId ? 'اختر الصنف من هذا المورد...' : 'اختر المورد أولاً...'}
                            </option>
                            {filteredTradeItems.map(i => <option key={i.id} value={i.id}>{i.name}</option>)}
                        </select>
                    </div>

                    {/* Step 3: How many and Prices */}
                    <div>
                         <label className="block text-xs font-bold text-slate-700 mb-1">العدد / الكمية</label>
                         <input type="number" value={tradeQuantity} onChange={e => setTradeQuantity(e.target.value)} className="w-full border border-slate-300 rounded-lg p-2 text-center font-bold" placeholder="0" required />
                    </div>

                    <div className="grid grid-cols-2 gap-3 bg-slate-50 p-3 rounded-xl border border-slate-200">
                        <div>
                            <label className="block text-xs font-bold text-red-600 mb-1">سعر الشراء (اليوم)</label>
                            <input 
                                type="number" 
                                value={tradeBuyPrice} 
                                onChange={e => setTradeBuyPrice(e.target.value)} 
                                className="w-full border border-red-200 rounded-lg p-2 text-sm text-center focus:ring-red-500 outline-none" 
                                placeholder="0.00" 
                                step="0.01"
                                required 
                            />
                        </div>
                        <div>
                            <label className="block text-xs font-bold text-emerald-600 mb-1">سعر البيع (للعميل)</label>
                            <input 
                                type="number" 
                                value={tradeSellPrice} 
                                onChange={e => setTradeSellPrice(e.target.value)} 
                                className="w-full border border-emerald-200 rounded-lg p-2 text-sm text-center focus:ring-emerald-500 outline-none" 
                                placeholder="0.00" 
                                step="0.01"
                                required 
                            />
                        </div>
                    </div>

                    {/* Summary Calculation */}
                    {(tradeQuantity && tradeBuyPrice && tradeSellPrice) && (
                        <div className="bg-slate-800 text-white p-3 rounded-lg text-xs space-y-1">
                            <div className="flex justify-between">
                                <span>إجمالي التوريد (للمورد):</span>
                                <span className="font-bold text-red-300">{(parseFloat(tradeQuantity) * parseFloat(tradeBuyPrice)).toLocaleString()} ج.م</span>
                            </div>
                            <div className="flex justify-between border-b border-slate-600 pb-1">
                                <span>إجمالي البيع (للعميل):</span>
                                <span className="font-bold text-emerald-300">{(parseFloat(tradeQuantity) * parseFloat(tradeSellPrice)).toLocaleString()} ج.م</span>
                            </div>
                            <div className="flex justify-between pt-1 font-bold text-sm">
                                <span>الربح المتوقع:</span>
                                <span className="text-yellow-400">{((parseFloat(tradeQuantity) * parseFloat(tradeSellPrice)) - (parseFloat(tradeQuantity) * parseFloat(tradeBuyPrice))).toLocaleString()} ج.م</span>
                            </div>
                        </div>
                    )}
                </div>
            )}

            {/* Normal Modes */}
            {(mode === 'transaction' || mode === 'client-action' || mode === 'supplier-action') && (
              <>
                {mode === 'transaction' && renderNormalTransactionTypes()}

                {/* Simplified Client/Supplier Selects for quick actions */}
                {mode === 'transaction' && trxType === 'income' && (
                    <div className="bg-blue-50 p-3 rounded-lg border border-blue-100">
                        <label className="block text-xs font-bold text-blue-800 mb-1">تحديد العميل</label>
                        <select 
                            value={selectedClientId || ''}
                            onChange={(e) => setSelectedClientId(Number(e.target.value))}
                            className="w-full border border-blue-200 rounded-md p-2 text-sm bg-white focus:outline-none"
                        >
                            <option value="">-- عميل عام / نقدي --</option>
                            {clients.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                        </select>
                    </div>
                )}

                {mode === 'transaction' && trxType === 'expense' && (
                    <div className="bg-orange-50 p-3 rounded-lg border border-orange-100">
                         <label className="block text-xs font-bold text-orange-800 mb-1">تحديد المورد</label>
                        <select 
                            value={selectedTxSupplierId || ''}
                            onChange={(e) => setSelectedTxSupplierId(Number(e.target.value))}
                            className="w-full border border-orange-200 rounded-md p-2 text-sm bg-white focus:outline-none"
                        >
                            <option value="">-- مورد عام / مصروفات --</option>
                            {suppliers.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                        </select>
                    </div>
                )}

                {mode !== 'transaction' && mode !== 'client-action' && mode !== 'supplier-action' ? null : (
                  <>
                    <div>
                    <label className="block text-sm font-semibold text-slate-700 mb-1">البيان</label>
                    <input
                        type="text"
                        value={trxName}
                        onChange={(e) => setTrxName(e.target.value)}
                        className="w-full border border-slate-200 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-blue-500 focus:outline-none"
                        placeholder="وصف العملية..."
                        required
                    />
                    </div>
                    <div>
                    <label className="block text-sm font-semibold text-slate-700 mb-1">المبلغ (ج.م)</label>
                    <input
                        type="number"
                        value={trxAmount}
                        onChange={(e) => setTrxAmount(e.target.value)}
                        className="w-full border border-slate-200 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-blue-500 focus:outline-none font-bold text-lg"
                        placeholder="0.00"
                        min="0"
                        step="0.01"
                        required
                    />
                    </div>
                  </>
                )}
              </>
            )}

            {/* Add Entity Modes */}
            {(mode === 'add-client' || mode === 'add-supplier') && (
              <>
                <div className="bg-blue-50 text-blue-800 p-3 rounded-lg text-sm mb-2 font-medium">
                    {mode === 'add-client' ? (initialData ? 'تعديل بيانات العميل' : 'بيانات العميل الجديد') : (initialData ? 'تعديل بيانات المورد' : 'بيانات المورد / الشركة')}
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">الاسم بالكامل</label>
                  <input type="text" value={entityName} onChange={(e) => setEntityName(e.target.value)} className="w-full border border-slate-200 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-blue-500 focus:outline-none" required />
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">رقم الهاتف</label>
                  <input type="tel" value={entityPhone} onChange={(e) => setEntityPhone(e.target.value)} className="w-full border border-slate-200 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-blue-500 focus:outline-none" />
                </div>
              </>
            )}

            {/* Add Item Mode */}
            {mode === 'add-item' && (
                <>
                 <div className="bg-orange-50 text-orange-800 p-3 rounded-lg text-sm mb-2 font-medium">إضافة صنف جديد للمخزن</div>
                 <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">اسم الصنف / المنتج</label>
                  <input type="text" value={itemName} onChange={(e) => setItemName(e.target.value)} className="w-full border border-slate-200 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-blue-500 focus:outline-none" required />
                </div>
                {!targetSupplierId && (
                    <div>
                        <label className="block text-sm font-semibold text-slate-700 mb-1">المورد / الشركة المنتجة</label>
                        <select value={selectedSupplierId || ''} onChange={(e) => setSelectedSupplierId(Number(e.target.value))} className="w-full border border-slate-200 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-blue-500 focus:outline-none bg-white" required>
                            <option value="">اختر المورد...</option>
                            {suppliers.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                        </select>
                    </div>
                )}
                </>
            )}

            <div className="pt-4 flex gap-3">
              <button type="button" onClick={onClose} className="flex-1 py-3 text-slate-600 bg-slate-100 hover:bg-slate-200 rounded-xl font-bold transition-colors">إلغاء</button>
              <button type="submit" className="flex-[2] py-3 text-white bg-blue-600 hover:bg-blue-700 rounded-xl font-bold transition-colors shadow-lg shadow-blue-200 flex items-center justify-center gap-2">
                <Check size={20} />
                {initialData ? 'حفظ التعديلات' : 'حفظ البيانات'}
              </button>
            </div>
          </form>
        </div>
      </div>
    </div>
  );
};

export default AddModal;

import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import Clients from './components/Clients';
import Suppliers from './components/Suppliers';
import Items from './components/Items';
import AddModal from './components/AddModal';
import { ViewState, Transaction, Client, Supplier, Item, Stats, TransactionType, ModalMode } from './types';
import { 
    loadTransactions, saveTransactions, 
    loadClients, saveClients, 
    loadSuppliers, saveSuppliers, 
    loadItems, saveItems, 
    clearAllData 
} from './services/storage';
import { Plus, Printer, Bell, Search, Download, ShoppingCart } from 'lucide-react';

function App() {
  const [currentView, setCurrentView] = useState<ViewState>('dashboard');

  // Data State
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [clients, setClients] = useState<Client[]>([]);
  const [suppliers, setSuppliers] = useState<Supplier[]>([]);
  const [items, setItems] = useState<Item[]>([]);

  // Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [modalMode, setModalMode] = useState<ModalMode>('transaction');
  const [targetSupplierId, setTargetSupplierId] = useState<number | undefined>(undefined);
  const [targetClientId, setTargetClientId] = useState<number | undefined>(undefined);
  const [targetName, setTargetName] = useState<string>('');

  // Editing State
  const [editingId, setEditingId] = useState<number | null>(null);
  const [editingInitialData, setEditingInitialData] = useState<any>(null);

  // Search State
  const [searchTerm, setSearchTerm] = useState('');

  // Load data on mount
  useEffect(() => {
    setTransactions(loadTransactions());
    setClients(loadClients());
    setSuppliers(loadSuppliers());
    setItems(loadItems());
  }, []);

  // Calculate Stats
  const stats: Stats = useMemo(() => {
    let income = 0;
    let expense = 0;
    transactions.forEach(t => {
      if (t.type === 'income') income += t.amount;
      else expense += t.amount;
    });
    return { income, expense, balance: income - expense };
  }, [transactions]);

  // Filter Logic
  const filteredTransactions = useMemo(() => {
    if (!searchTerm) return transactions;
    return transactions.filter(t => 
      t.name.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [transactions, searchTerm]);

  const filteredClients = useMemo(() => {
    if (!searchTerm) return clients;
    return clients.filter(c => 
      c.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      c.phone.includes(searchTerm)
    );
  }, [clients, searchTerm]);

  const filteredSuppliers = useMemo(() => {
    if (!searchTerm) return suppliers;
    return suppliers.filter(s => {
        const nameMatch = s.name.toLowerCase().includes(searchTerm.toLowerCase());
        const phoneMatch = s.phone.includes(searchTerm);
        return nameMatch || phoneMatch;
    });
  }, [suppliers, searchTerm]);

  const filteredItems = useMemo(() => {
    if (!searchTerm) return items;
    return items.filter(i => {
        const itemMatch = i.name.toLowerCase().includes(searchTerm.toLowerCase());
        const supplierMatch = suppliers.find(s => s.id === i.supplierId)?.name.toLowerCase().includes(searchTerm.toLowerCase());
        return itemMatch || supplierMatch;
    });
  }, [items, suppliers, searchTerm]);

  // CSV Export Logic
  const handleExportCSV = () => {
    let csvContent = "data:text/csv;charset=utf-8,\uFEFF"; 
    let filename = "export.csv";

    if (currentView === 'clients') {
      csvContent += "ID,Name,Phone\n";
      filteredClients.forEach(c => { csvContent += `${c.id},"${c.name}","${c.phone}"\n`; });
      filename = "clients.csv";
    } else if (currentView === 'suppliers') {
      csvContent += "ID,Name,Phone\n";
      filteredSuppliers.forEach(s => { csvContent += `${s.id},"${s.name}","${s.phone}"\n`; });
      filename = "suppliers.csv";
    } else if (currentView === 'items') {
        csvContent += "ID,Name,Supplier\n";
        filteredItems.forEach(i => {
           const supplierName = suppliers.find(s => s.id === i.supplierId)?.name || 'Unknown';
           csvContent += `${i.id},"${i.name}","${supplierName}"\n`;
        });
        filename = "items.csv";
    } else {
      csvContent += "ID,Date,Description,Type,Amount\n";
      filteredTransactions.forEach(t => {
         const typeAr = t.type === 'income' ? 'قبض' : 'صرف';
         csvContent += `${t.id},${t.date},"${t.name}",${typeAr},${t.amount}\n`;
      });
      filename = "transactions.csv";
    }

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", filename);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // --- Handlers ---

  const handleSaveTransaction = (data: { name: string; amount: number; type: TransactionType; clientId?: number; supplierId?: number }) => {
    if (editingId) {
        // Edit Existing Transaction
        const updated = transactions.map(t => t.id === editingId ? { ...t, ...data } : t);
        setTransactions(updated);
        saveTransactions(updated);
    } else {
        // Create New Transaction
        const newTrx: Transaction = {
          id: Date.now(),
          name: data.name,
          amount: data.amount,
          type: data.type,
          date: new Date().toLocaleDateString('ar-EG'),
          clientId: data.clientId,
          supplierId: data.supplierId
        };
        const updated = [...transactions, newTrx];
        setTransactions(updated);
        saveTransactions(updated);
    }
    closeModal();
  };

  const handleSaveTrade = (data: { 
      clientId: number; 
      supplierId: number; 
      itemId: number; 
      itemName: string;
      quantity: number; 
      buyPrice: number; 
      sellPrice: number; 
  }) => {
      const now = Date.now();
      const dateStr = new Date().toLocaleDateString('ar-EG');

      const purchaseTrx: Transaction = {
          id: now,
          name: `توريد: ${data.itemName} (عدد ${data.quantity})`,
          amount: data.quantity * data.buyPrice,
          type: 'expense',
          date: dateStr,
          supplierId: data.supplierId,
          itemId: data.itemId,
          quantity: data.quantity,
          unitPrice: data.buyPrice
      };

      const saleTrx: Transaction = {
          id: now + 1,
          name: `بيع: ${data.itemName} (عدد ${data.quantity})`,
          amount: data.quantity * data.sellPrice,
          type: 'income',
          date: dateStr,
          clientId: data.clientId,
          itemId: data.itemId,
          quantity: data.quantity,
          unitPrice: data.sellPrice,
          relatedTransactionId: now
      };

      const updated = [...transactions, purchaseTrx, saleTrx];
      setTransactions(updated);
      saveTransactions(updated);
      closeModal();
  };

  const handleSaveClient = (data: { name: string; phone: string; image?: string }) => {
    let updated: Client[];
    if (editingId) {
        updated = clients.map(c => c.id === editingId ? { ...c, ...data, image: data.image || c.image } : c);
    } else {
        const newClient: Client = { id: Date.now(), name: data.name, phone: data.phone, image: data.image };
        updated = [...clients, newClient];
    }
    setClients(updated);
    saveClients(updated);
    closeModal();
  };

  const handleSaveSupplier = (data: { name: string; phone: string; image?: string }) => {
      let updated: Supplier[];
      if (editingId) {
          updated = suppliers.map(s => s.id === editingId ? { ...s, ...data, image: data.image || s.image } : s);
      } else {
          const newSupplier: Supplier = { id: Date.now(), name: data.name, phone: data.phone, image: data.image };
          updated = [...suppliers, newSupplier];
      }
      setSuppliers(updated);
      saveSuppliers(updated);
      closeModal();
  };

  const handleSaveItem = (data: { name: string; supplierId: number; image?: string }) => {
      let updated: Item[];
      if (editingId) {
          updated = items.map(i => i.id === editingId ? { ...i, ...data, image: data.image || i.image } : i);
      } else {
          const newItem: Item = { id: Date.now(), name: data.name, supplierId: data.supplierId, image: data.image };
          updated = [...items, newItem];
      }
      setItems(updated);
      saveItems(updated);
      closeModal();
  };

  // --- Deletion Handlers ---
  const handleDeleteTransaction = (id: number) => {
    const updated = transactions.filter(t => t.id !== id);
    setTransactions(updated);
    saveTransactions(updated);
  };
  const handleDeleteClient = (id: number) => {
    const updated = clients.filter(c => c.id !== id);
    setClients(updated);
    saveClients(updated);
  };
  const handleDeleteSupplier = (id: number) => {
      const updatedSuppliers = suppliers.filter(s => s.id !== id);
      const updatedItems = items.filter(i => i.supplierId !== id); 
      setSuppliers(updatedSuppliers);
      setItems(updatedItems);
      saveSuppliers(updatedSuppliers);
      saveItems(updatedItems);
  };
  const handleDeleteItem = (id: number) => {
      const updated = items.filter(i => i.id !== id);
      setItems(updated);
      saveItems(updated);
  };
  const handleClearData = () => {
    clearAllData();
    setTransactions([]);
    setClients([]);
    setSuppliers([]);
    setItems([]);
    window.location.reload();
  };

  // --- Modal Triggers ---
  const closeModal = () => {
      setIsModalOpen(false);
      setEditingId(null);
      setEditingInitialData(null);
      setTargetClientId(undefined);
      setTargetSupplierId(undefined);
      setTargetName('');
  };

  const openTransactionModal = () => {
      setModalMode('transaction');
      setIsModalOpen(true);
  };

  const openTradeModal = () => {
      setModalMode('trade');
      setIsModalOpen(true);
  };

  const openClientModal = () => {
      setModalMode('add-client');
      setIsModalOpen(true);
  };
  const openSupplierModal = () => {
      setModalMode('add-supplier');
      setIsModalOpen(true);
  };
  const openAddItemModal = (supplierId?: number) => {
      setTargetSupplierId(supplierId);
      setModalMode('add-item');
      setIsModalOpen(true);
  };
  const handleClientAction = (clientId: number, clientName: string) => {
      setTargetClientId(clientId);
      setTargetName(clientName);
      setModalMode('client-action');
      setIsModalOpen(true);
  };
  const handleSupplierAction = (supplierId: number, supplierName: string) => {
      setTargetSupplierId(supplierId);
      setTargetName(supplierName);
      setModalMode('supplier-action');
      setIsModalOpen(true);
  };

  // Edit Triggers
  const handleEditClient = (client: Client) => {
      setEditingId(client.id);
      setEditingInitialData(client);
      setModalMode('add-client');
      setIsModalOpen(true);
  };
  const handleEditSupplier = (supplier: Supplier) => {
      setEditingId(supplier.id);
      setEditingInitialData(supplier);
      setModalMode('add-supplier');
      setIsModalOpen(true);
  };
  const handleEditTransaction = (trx: Transaction) => {
      setEditingId(trx.id);
      setEditingInitialData(trx);
      setModalMode('transaction');
      setIsModalOpen(true);
  };
  const handleEditItem = (item: Item) => {
      setEditingId(item.id);
      setEditingInitialData(item);
      setModalMode('add-item');
      setIsModalOpen(true);
  };

  return (
    <div className="flex min-h-screen bg-slate-50 font-sans">
      <Sidebar 
        currentView={currentView} 
        onChangeView={setCurrentView} 
        onClearData={handleClearData} 
      />

      <main className="flex-1 flex flex-col relative overflow-hidden">
        {/* Header */}
        <header className="h-20 bg-white shadow-sm flex justify-between items-center px-8 z-20 no-print sticky top-0">
          <div>
            <h2 className="text-xl font-bold text-slate-800">
                {currentView === 'dashboard' && 'لوحة التحكم الرئيسية'}
                {currentView === 'clients' && 'إدارة العملاء'}
                {currentView === 'suppliers' && 'الموردين والشركات'}
                {currentView === 'items' && 'المخزن والأصناف'}
                {currentView === 'invoices' && 'سجل الفواتير'}
            </h2>
          </div>

          <div className="flex-1 mx-8 max-w-lg hidden md:block">
            <div className="relative group">
              <Search className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-blue-500 transition-colors" size={18} />
              <input 
                type="text" 
                placeholder="بحث..." 
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full bg-slate-100 border-none rounded-xl py-2.5 pr-10 pl-4 focus:ring-2 focus:ring-blue-500 outline-none transition-all text-sm"
              />
            </div>
          </div>

          <div className="flex items-center gap-3">
             {/* New Trade Button in Header */}
             <button 
                onClick={openTradeModal}
                className="hidden lg:flex items-center gap-2 bg-slate-900 text-white px-4 py-2 rounded-lg hover:bg-slate-700 transition text-sm font-bold shadow-sm"
                title="فاتورة تجارية جديدة (بيع وشراء)"
             >
                <ShoppingCart size={18} />
                <span>فاتورة تجارية</span>
             </button>

             <button onClick={handleExportCSV} className="flex items-center gap-2 bg-emerald-600 text-white px-4 py-2 rounded-lg hover:bg-emerald-700 transition text-sm font-bold shadow-sm" title="تصدير إلى CSV">
                <Download size={18} />
                <span className="hidden xl:inline">تصدير CSV</span>
             </button>
             <button onClick={() => window.print()} className="flex items-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition text-sm font-bold shadow-sm">
                <Printer size={18} />
                <span className="hidden xl:inline">طباعة</span>
             </button>
          </div>
        </header>

        {/* Content */}
        <div className="flex-1 overflow-auto p-8 relative">
          <div className="max-w-7xl mx-auto">
            <div className="hidden print-only mb-8 text-center border-b pb-4">
                <h1 className="text-3xl font-bold text-black mb-2">Al-Mohaseb Pro - تقرير مالي</h1>
                <p className="text-gray-600">تاريخ التقرير: {new Date().toLocaleDateString('ar-EG')}</p>
            </div>

            {currentView === 'dashboard' && <Dashboard stats={stats} transactions={filteredTransactions} onDeleteTransaction={handleDeleteTransaction} onEditTransaction={handleEditTransaction} />}
            {currentView === 'invoices' && <Dashboard stats={stats} transactions={filteredTransactions} onDeleteTransaction={handleDeleteTransaction} onEditTransaction={handleEditTransaction} />}
            {currentView === 'clients' && <Clients clients={filteredClients} onDeleteClient={handleDeleteClient} onEditClient={handleEditClient} onOpenAddModal={openClientModal} onClientAction={handleClientAction} />}
            {currentView === 'suppliers' && <Suppliers suppliers={filteredSuppliers} onDeleteSupplier={handleDeleteSupplier} onEditSupplier={handleEditSupplier} onOpenAddSupplierModal={openSupplierModal} onSupplierAction={handleSupplierAction} />}
            {currentView === 'items' && <Items items={filteredItems} suppliers={suppliers} onDeleteItem={handleDeleteItem} onEditItem={handleEditItem} onOpenAddItemModal={() => openAddItemModal()} />}
          </div>
        </div>

        {/* FAB */}
        <button
          onClick={() => {
              if (currentView === 'clients') openClientModal();
              else if (currentView === 'suppliers') openSupplierModal();
              else if (currentView === 'items') openAddItemModal();
              else openTransactionModal();
          }}
          className={`fixed bottom-8 left-8 text-white w-14 h-14 rounded-full shadow-2xl flex items-center justify-center transition-transform hover:scale-110 active:scale-95 z-40 no-print ${currentView === 'suppliers' ? 'bg-orange-600 hover:bg-orange-700' : currentView === 'items' ? 'bg-slate-700 hover:bg-slate-800' : 'bg-blue-600 hover:bg-blue-700'}`}
        >
          <Plus size={28} />
        </button>

        <AddModal 
          isOpen={isModalOpen}
          mode={modalMode}
          targetSupplierId={targetSupplierId}
          targetClientId={targetClientId}
          targetName={targetName}
          suppliers={suppliers}
          clients={clients}
          items={items}
          initialData={editingInitialData}
          onClose={closeModal}
          onSaveTransaction={handleSaveTransaction}
          onSaveTrade={handleSaveTrade}
          onSaveClient={handleSaveClient}
          onSaveSupplier={handleSaveSupplier}
          onSaveItem={handleSaveItem}
        />
      </main>
    </div>
  );
}

export default App;

import React from 'react';
import { Item, Supplier } from '../types';
import { Trash2, Package, Plus, Truck, Pencil } from 'lucide-react';

interface ItemsProps {
  items: Item[];
  suppliers: Supplier[];
  onDeleteItem: (id: number) => void;
  onEditItem: (item: Item) => void;
  onOpenAddItemModal: () => void;
}

const Items: React.FC<ItemsProps> = ({ 
    items, 
    suppliers,
    onDeleteItem,
    onEditItem,
    onOpenAddItemModal 
}) => {

  const getSupplierName = (id: number) => {
      return suppliers.find(s => s.id === id)?.name || 'مورد غير معروف';
  };

  return (
    <div className="space-y-6 fade-in pb-20">

      {/* Persistent Add Button Header */}
      <div className="flex justify-between items-center bg-white p-4 rounded-xl shadow-sm border border-slate-100">
        <h3 className="font-bold text-slate-800 text-lg">أصناف المخزن ({items.length})</h3>
        <button 
            onClick={onOpenAddItemModal}
            className="flex items-center gap-2 bg-slate-800 text-white px-4 py-2 rounded-lg hover:bg-slate-700 transition font-bold text-sm shadow-md"
        >
            <Plus size={18} />
            إضافة صنف جديد
        </button>
      </div>

      {items.length === 0 ? (
         <div className="text-center py-20 text-slate-400">
            <div className="bg-slate-100 p-4 rounded-full inline-block mb-4">
                <Package size={32} className="text-slate-400" />
            </div>
            <p>لا توجد أصناف مسجلة في المخزن</p>
         </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
            {items.map((item) => (
                <div key={item.id} className="bg-white rounded-xl shadow-sm border border-slate-100 p-4 hover:shadow-md transition-all group">
                    <div className="flex items-start gap-4">
                        <div className="w-16 h-16 bg-slate-100 rounded-lg flex items-center justify-center overflow-hidden flex-shrink-0">
                             {item.image ? (
                                <img src={item.image} className="w-full h-full object-cover" alt="" />
                             ) : (
                                <Package size={24} className="text-slate-400" />
                             )}
                        </div>
                        <div className="flex-1 min-w-0">
                            <h4 className="font-bold text-slate-800 mb-1 truncate" title={item.name}>{item.name}</h4>
                            <div className="flex items-center gap-1 text-xs text-orange-600 bg-orange-50 px-2 py-1 rounded w-fit">
                                <Truck size={10} />
                                <span className="truncate max-w-[100px]">{getSupplierName(item.supplierId)}</span>
                            </div>
                        </div>
                        <div className="flex flex-col gap-1">
                            <button 
                                onClick={() => onEditItem(item)}
                                className="text-slate-300 hover:text-blue-500 transition-colors"
                            >
                                <Pencil size={16} />
                            </button>
                            <button 
                                onClick={() => {
                                    if(confirm(`حذف الصنف "${item.name}"؟`)) onDeleteItem(item.id);
                                }}
                                className="text-slate-300 hover:text-red-500 transition-colors"
                            >
                                <Trash2 size={16} />
                            </button>
                        </div>
                    </div>
                </div>
            ))}
        </div>
      )}
    </div>
  );
};

