                      <button 
                        onClick={() => onDeleteTransaction(trx.id)}
                        className="text-slate-300 hover:text-red-500 transition-colors p-2 rounded-full hover:bg-red-50"
                        title="حذف"
                      >
                        <Trash2 size={18} />
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
};

export default Invoices;

import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import Clients from './components/Clients';
import Suppliers from './components/Suppliers';
import Items from './components/Items';
import Invoices from './components/Invoices';
import AddModal from './components/AddModal';
import { ViewState, Transaction, Client, Supplier, Item, Stats, TransactionType, ModalMode } from './types';
import { 
    loadTransactions, saveTransactions, 
    loadClients, saveClients, 
    loadSuppliers, saveSuppliers, 
    loadItems, saveItems, 
    clearAllData 
} from './services/storage';
import { Plus, Printer, Bell, Search, Download, ShoppingCart } from 'lucide-react';

function App() {
  const [currentView, setCurrentView] = useState<ViewState>('dashboard');

  // Data State
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [clients, setClients] = useState<Client[]>([]);
  const [suppliers, setSuppliers] = useState<Supplier[]>([]);
  const [items, setItems] = useState<Item[]>([]);

  // Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [modalMode, setModalMode] = useState<ModalMode>('transaction');
  const [targetSupplierId, setTargetSupplierId] = useState<number | undefined>(undefined);
  const [targetClientId, setTargetClientId] = useState<number | undefined>(undefined);
  const [targetName, setTargetName] = useState<string>('');

  // Editing State
  const [editingId, setEditingId] = useState<number | null>(null);
  const [editingInitialData, setEditingInitialData] = useState<any>(null);

  // Search State
  const [searchTerm, setSearchTerm] = useState('');

  // Load data on mount
  useEffect(() => {
    setTransactions(loadTransactions());
    setClients(loadClients());
    setSuppliers(loadSuppliers());
    setItems(loadItems());
  }, []);

  // Calculate Stats
  const stats: Stats = useMemo(() => {
    let income = 0;
    let expense = 0;
    transactions.forEach(t => {
      if (t.type === 'income') income += t.amount;
      else expense += t.amount;
    });
    return { income, expense, balance: income - expense };
  }, [transactions]);

  // Filter Logic
  const filteredTransactions = useMemo(() => {
    if (!searchTerm) return transactions;
    return transactions.filter(t => 
      t.name.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [transactions, searchTerm]);

  const filteredClients = useMemo(() => {
    if (!searchTerm) return clients;
    return clients.filter(c => 
      c.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      c.phone.includes(searchTerm)
    );
  }, [clients, searchTerm]);

  const filteredSuppliers = useMemo(() => {
    if (!searchTerm) return suppliers;
    return suppliers.filter(s => {
        const nameMatch = s.name.toLowerCase().includes(searchTerm.toLowerCase());
        const phoneMatch = s.phone.includes(searchTerm);
        return nameMatch || phoneMatch;
    });
  }, [suppliers, searchTerm]);

  const filteredItems = useMemo(() => {
    if (!searchTerm) return items;
    return items.filter(i => {
        const itemMatch = i.name.toLowerCase().includes(searchTerm.toLowerCase());
        const supplierMatch = suppliers.find(s => s.id === i.supplierId)?.name.toLowerCase().includes(searchTerm.toLowerCase());
        return itemMatch || supplierMatch;
    });
  }, [items, suppliers, searchTerm]);

  // CSV Export Logic
  const handleExportCSV = () => {
    let csvContent = "data:text/csv;charset=utf-8,\uFEFF"; 
    let filename = "export.csv";

    if (currentView === 'clients') {
      csvContent += "ID,Name,Phone\n";
      filteredClients.forEach(c => { csvContent += `${c.id},"${c.name}","${c.phone}"\n`; });
      filename = "clients.csv";
    } else if (currentView === 'suppliers') {
      csvContent += "ID,Name,Phone\n";
      filteredSuppliers.forEach(s => { csvContent += `${s.id},"${s.name}","${s.phone}"\n`; });
      filename = "suppliers.csv";
    } else if (currentView === 'items') {
        csvContent += "ID,Name,Supplier\n";
        filteredItems.forEach(i => {
           const supplierName = suppliers.find(s => s.id === i.supplierId)?.name || 'Unknown';
           csvContent += `${i.id},"${i.name}","${supplierName}"\n`;
        });
        filename = "items.csv";
    } else {
      csvContent += "ID,Date,Description,Type,Amount\n";
      filteredTransactions.forEach(t => {
         const typeAr = t.type === 'income' ? 'قبض' : 'صرف';
         csvContent += `${t.id},${t.date},"${t.name}",${typeAr},${t.amount}\n`;
      });
      filename = "transactions.csv";
    }

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", filename);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // --- Handlers ---

  const handleSaveTransaction = (data: { name: string; amount: number; type: TransactionType; clientId?: number; supplierId?: number }) => {
    if (editingId) {
        // Edit Existing Transaction
        const updated = transactions.map(t => t.id === editingId ? { ...t, ...data } : t);
        setTransactions(updated);
        saveTransactions(updated);
    } else {
        // Create New Transaction
        const newTrx: Transaction = {
          id: Date.now(),
          name: data.name,
          amount: data.amount,
          type: data.type,
          date: new Date().toLocaleDateString('ar-EG'),
          clientId: data.clientId,
          supplierId: data.supplierId
        };
        const updated = [...transactions, newTrx];
        setTransactions(updated);
        saveTransactions(updated);
    }
    closeModal();
  };

  const handleSaveTrade = (data: { 
      clientId: number; 
      supplierId: number; 
      itemId: number; 
      itemName: string;
      quantity: number; 
      buyPrice: number; 
      sellPrice: number; 
  }) => {
      const now = Date.now();
      const dateStr = new Date().toLocaleDateString('ar-EG');

      const purchaseTrx: Transaction = {
          id: now,
          name: `توريد: ${data.itemName} (عدد ${data.quantity})`,
          amount: data.quantity * data.buyPrice,
          type: 'expense',
          date: dateStr,
          supplierId: data.supplierId,
          itemId: data.itemId,
          quantity: data.quantity,
          unitPrice: data.buyPrice
      };

      const saleTrx: Transaction = {
          id: now + 1,
          name: `بيع: ${data.itemName} (عدد ${data.quantity})`,
          amount: data.quantity * data.sellPrice,
          type: 'income',
          date: dateStr,
          clientId: data.clientId,
          itemId: data.itemId,
          quantity: data.quantity,
          unitPrice: data.sellPrice,
          relatedTransactionId: now
      };

      const updated = [...transactions, purchaseTrx, saleTrx];
      setTransactions(updated);
      saveTransactions(updated);
      closeModal();
  };

  const handleSaveClient = (data: { name: string; phone: string; image?: string }) => {
    let updated: Client[];
    if (editingId) {
        updated = clients.map(c => c.id === editingId ? { ...c, ...data, image: data.image || c.image } : c);
    } else {
        const newClient: Client = { id: Date.now(), name: data.name, phone: data.phone, image: data.image };
        updated = [...clients, newClient];
    }
    setClients(updated);
    saveClients(updated);
    closeModal();
  };

  const handleSaveSupplier = (data: { name: string; phone: string; image?: string }) => {
      let updated: Supplier[];
      if (editingId) {
          updated = suppliers.map(s => s.id === editingId ? { ...s, ...data, image: data.image || s.image } : s);
      } else {
          const newSupplier: Supplier = { id: Date.now(), name: data.name, phone: data.phone, image: data.image };
          updated = [...suppliers, newSupplier];
      }
      setSuppliers(updated);
      saveSuppliers(updated);
      closeModal();
  };

  const handleSaveItem = (data: { name: string; supplierId: number; image?: string }) => {
      let updated: Item[];
      if (editingId) {
          updated = items.map(i => i.id === editingId ? { ...i, ...data, image: data.image || i.image } : i);
      } else {
          const newItem: Item = { id: Date.now(), name: data.name, supplierId: data.supplierId, image: data.image };
          updated = [...items, newItem];
      }
      setItems(updated);
      saveItems(updated);
      closeModal();
  };

  // --- Deletion Handlers ---
  const handleDeleteTransaction = (id: number) => {
    const updated = transactions.filter(t => t.id !== id);
    setTransactions(updated);
    saveTransactions(updated);
  };
  const handleDeleteClient = (id: number) => {
    const updated = clients.filter(c => c.id !== id);
    setClients(updated);
    saveClients(updated);
  };
  const handleDeleteSupplier = (id: number) => {
      const updatedSuppliers = suppliers.filter(s => s.id !== id);
      const updatedItems = items.filter(i => i.supplierId !== id); 
      setSuppliers(updatedSuppliers);
      setItems(updatedItems);
      saveSuppliers(updatedSuppliers);
      saveItems(updatedItems);
  };
  const handleDeleteItem = (id: number) => {
      const updated = items.filter(i => i.id !== id);
      setItems(updated);
      saveItems(updated);
  };
  const handleClearData = () => {
    clearAllData();
    setTransactions([]);
    setClients([]);
    setSuppliers([]);
    setItems([]);
    window.location.reload();
  };

  // --- Modal Triggers ---
  const closeModal = () => {
      setIsModalOpen(false);
      setEditingId(null);
      setEditingInitialData(null);
      setTargetClientId(undefined);
      setTargetSupplierId(undefined);
      setTargetName('');
  };

  const openTransactionModal = () => {
      setModalMode('transaction');
      setIsModalOpen(true);
  };

  const openTradeModal = () => {
      setModalMode('trade');
      setIsModalOpen(true);
  };

  const openClientModal = () => {
      setModalMode('add-client');
      setIsModalOpen(true);
  };
  const openSupplierModal = () => {
      setModalMode('add-supplier');
      setIsModalOpen(true);
  };
  const openAddItemModal = (supplierId?: number) => {
      setTargetSupplierId(supplierId);
      setModalMode('add-item');
      setIsModalOpen(true);
  };
  const handleClientAction = (clientId: number, clientName: string) => {
      setTargetClientId(clientId);
      setTargetName(clientName);
      setModalMode('client-action');
      setIsModalOpen(true);
  };
  const handleSupplierAction = (supplierId: number, supplierName: string) => {
      setTargetSupplierId(supplierId);
      setTargetName(supplierName);
      setModalMode('supplier-action');
      setIsModalOpen(true);
  };

  // Edit Triggers
  const handleEditClient = (client: Client) => {
      setEditingId(client.id);
      setEditingInitialData(client);
      setModalMode('add-client');
      setIsModalOpen(true);
  };
  const handleEditSupplier = (supplier: Supplier) => {
      setEditingId(supplier.id);
      setEditingInitialData(supplier);
      setModalMode('add-supplier');
      setIsModalOpen(true);
  };
  const handleEditTransaction = (trx: Transaction) => {
      setEditingId(trx.id);
      setEditingInitialData(trx);
      setModalMode('transaction');
      setIsModalOpen(true);
  };
  const handleEditItem = (item: Item) => {
      setEditingId(item.id);
      setEditingInitialData(item);
      setModalMode('add-item');
      setIsModalOpen(true);
  };

  return (
    <div className="flex min-h-screen bg-slate-50 font-sans">
      <Sidebar 
        currentView={currentView} 
        onChangeView={setCurrentView} 
        onClearData={handleClearData} 
      />

      <main className="flex-1 flex flex-col relative overflow-hidden">
        {/* Header */}
        <header className="h-20 bg-white shadow-sm flex justify-between items-center px-8 z-20 no-print sticky top-0">
          <div>
            <h2 className="text-xl font-bold text-slate-800">
                {currentView === 'dashboard' && 'لوحة التحكم الرئيسية'}
                {currentView === 'clients' && 'إدارة العملاء'}
                {currentView === 'suppliers' && 'الموردين والشركات'}
                {currentView === 'items' && 'المخزن والأصناف'}
                {currentView === 'invoices' && 'سجل الفواتير'}
            </h2>
          </div>

          <div className="flex-1 mx-8 max-w-lg hidden md:block">
            <div className="relative group">
              <Search className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-blue-500 transition-colors" size={18} />
              <input 
                type="text" 
                placeholder="بحث..." 
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full bg-slate-100 border-none rounded-xl py-2.5 pr-10 pl-4 focus:ring-2 focus:ring-blue-500 outline-none transition-all text-sm"
              />
            </div>
          </div>

          <div className="flex items-center gap-3">
             {/* New Trade Button in Header */}
             <button 
                onClick={openTradeModal}
                className="hidden lg:flex items-center gap-2 bg-slate-900 text-white px-4 py-2 rounded-lg hover:bg-slate-700 transition text-sm font-bold shadow-sm"
                title="فاتورة تجارية جديدة (بيع وشراء)"
             >
                <ShoppingCart size={18} />
                <span>فاتورة تجارية</span>
             </button>

             <button onClick={handleExportCSV} className="flex items-center gap-2 bg-emerald-600 text-white px-4 py-2 rounded-lg hover:bg-emerald-700 transition text-sm font-bold shadow-sm" title="تصدير إلى CSV">
                <Download size={18} />
                <span className="hidden xl:inline">تصدير CSV</span>
             </button>
             <button onClick={() => window.print()} className="flex items-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition text-sm font-bold shadow-sm">
                <Printer size={18} />
                <span className="hidden xl:inline">طباعة</span>
             </button>
          </div>
        </header>

        {/* Content */}
        <div className="flex-1 overflow-auto p-8 relative">
          <div className="max-w-7xl mx-auto">
            <div className="hidden print-only mb-8 text-center border-b pb-4">
                <h1 className="text-3xl font-bold text-black mb-2">Al-Mohaseb Pro - تقرير مالي</h1>
                <p className="text-gray-600">تاريخ التقرير: {new Date().toLocaleDateString('ar-EG')}</p>
            </div>

            {currentView === 'dashboard' && <Dashboard stats={stats} transactions={filteredTransactions} onDeleteTransaction={handleDeleteTransaction} onEditTransaction={handleEditTransaction} />}
            {currentView === 'invoices' && <Invoices transactions={filteredTransactions} onDeleteTransaction={handleDeleteTransaction} onEditTransaction={handleEditTransaction} searchTerm={searchTerm} onSearchChange={setSearchTerm} />}
            {currentView === 'clients' && <Clients clients={filteredClients} onDeleteClient={handleDeleteClient} onEditClient={handleEditClient} onOpenAddModal={openClientModal} onClientAction={handleClientAction} />}
            {currentView === 'suppliers' && <Suppliers suppliers={filteredSuppliers} onDeleteSupplier={handleDeleteSupplier} onEditSupplier={handleEditSupplier} onOpenAddSupplierModal={openSupplierModal} onSupplierAction={handleSupplierAction} />}
            {currentView === 'items' && <Items items={filteredItems} suppliers={suppliers} onDeleteItem={handleDeleteItem} onEditItem={handleEditItem} onOpenAddItemModal={() => openAddItemModal()} />}
          </div>
        </div>

        {/* FAB */}
        <button
          onClick={() => {
              if (currentView === 'clients') openClientModal();
              else if (currentView === 'suppliers') openSupplierModal();
              else if (currentView === 'items') openAddItemModal();
              else openTransactionModal();
          }}
          className={`fixed bottom-8 left-8 text-white w-14 h-14 rounded-full shadow-2xl flex items-center justify-center transition-transform hover:scale-110 active:scale-95 z-40 no-print ${currentView === 'suppliers' ? 'bg-orange-600 hover:bg-orange-700' : currentView === 'items' ? 'bg-slate-700 hover:bg-slate-800' : 'bg-blue-600 hover:bg-blue-700'}`}
        >
          <Plus size={28} />
        </button>

        <AddModal 
          isOpen={isModalOpen}
          mode={modalMode}
          targetSupplierId={targetSupplierId}
          targetClientId={targetClientId}
          targetName={targetName}
          suppliers={suppliers}
          clients={clients}
          items={items}
          initialData={editingInitialData}
          onClose={closeModal}
          onSaveTransaction={handleSaveTransaction}
          onSaveTrade={handleSaveTrade}
          onSaveClient={handleSaveClient}
          onSaveSupplier={handleSaveSupplier}
          onSaveItem={handleSaveItem}
        />
      </main>
    </div>
  );
}

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { Share2, FileText, MessageCircle, X } from 'lucide-react';
import { ViewState, Stats } from '../types';

interface ShareButtonProps {
  currentView: ViewState;
  stats: Stats;
  counts: {
    clients: number;
    suppliers: number;
    items: number;
    transactions: number;
  };
}

const ShareButton: React.FC<ShareButtonProps> = ({ currentView, stats, counts }) => {
  const [isOpen, setIsOpen] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);

  // Close dropdown when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handlePDF = () => {
    setIsOpen(false);
    window.print();
  };

  const handleWhatsApp = () => {
    setIsOpen(false);

    let message = `*تقرير المحاسب الذكي - مكتب بهاء*\n`;
    message += `التاريخ: ${new Date().toLocaleDateString('ar-EG')}\n\n`;

    if (currentView === 'dashboard' || currentView === 'invoices') {
      message += `*الوضع المالي الحالي:*\n`;
      message += `📈 إجمالي الدخل: ${stats.income.toLocaleString()} ج.م\n`;
      message += `📉 إجمالي المصروفات: ${stats.expense.toLocaleString()} ج.م\n`;
      message += `💰 صافي الرصيد: ${stats.balance.toLocaleString()} ج.م\n`;
      message += `📊 عدد العمليات المسجلة: ${counts.transactions}\n`;
    } else if (currentView === 'clients') {
      message += `*تقرير العملاء:*\n`;
      message += `عدد العملاء المسجلين: ${counts.clients}\n`;
    } else if (currentView === 'suppliers') {
      message += `*تقرير الموردين:*\n`;
      message += `عدد الموردين: ${counts.suppliers}\n`;
    } else if (currentView === 'items') {
      message += `*تقرير المخزن:*\n`;
      message += `عدد الأصناف: ${counts.items}\n`;
    }

    message += `\nتم الانشاء بواسطة نظام المحاسب الذكي`;

    const url = `https://wa.me/?text=${encodeURIComponent(message)}`;
    window.open(url, '_blank');
  };

  return (
    <div className="relative" ref={dropdownRef}>
      <button 
        onClick={() => setIsOpen(!isOpen)}
        className="flex items-center gap-2 bg-indigo-600 text-white px-4 py-2 rounded-lg hover:bg-indigo-700 transition text-sm font-bold shadow-sm"
      >
        <Share2 size={18} />
        <span className="hidden xl:inline">مشاركة</span>
      </button>

      {isOpen && (
        <div className="absolute left-0 mt-2 w-48 bg-white rounded-xl shadow-xl border border-slate-100 z-50 overflow-hidden fade-in">
          <div className="p-2 border-b border-slate-100 bg-slate-50 flex justify-between items-center">
            <span className="text-xs font-bold text-slate-500">خيارات المشاركة</span>
            <button onClick={() => setIsOpen(false)} className="text-slate-400 hover:text-red-500">
                <X size={14} />
            </button>
          </div>
          <div className="p-1">
            <button 
              onClick={handleWhatsApp}
              className="w-full flex items-center gap-3 px-3 py-2.5 text-sm font-medium text-slate-700 hover:bg-green-50 hover:text-green-700 rounded-lg transition-colors"
            >
              <MessageCircle size={18} className="text-green-500" />
              إرسال عبر واتساب
            </button>
            <button 
              onClick={handlePDF}
              className="w-full flex items-center gap-3 px-3 py-2.5 text-sm font-medium text-slate-700 hover:bg-red-50 hover:text-red-700 rounded-lg transition-colors"
            >
              <FileText size={18} className="text-red-500" />
              حفظ كملف PDF
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default ShareButton;

import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import Clients from './components/Clients';
import Suppliers from './components/Suppliers';
import Items from './components/Items';
import Invoices from './components/Invoices';
import AddModal from './components/AddModal';
import ShareButton from './components/ShareButton';
import { ViewState, Transaction, Client, Supplier, Item, Stats, TransactionType, ModalMode } from './types';
import { 
    loadTransactions, saveTransactions, 
    loadClients, saveClients, 
    loadSuppliers, saveSuppliers, 
    loadItems, saveItems, 
    clearAllData 
} from './services/storage';
import { Plus, Printer, Bell, Search, Download, ShoppingCart } from 'lucide-react';

function App() {
  const [currentView, setCurrentView] = useState<ViewState>('dashboard');

  // Data State
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [clients, setClients] = useState<Client[]>([]);
  const [suppliers, setSuppliers] = useState<Supplier[]>([]);
  const [items, setItems] = useState<Item[]>([]);

  // Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [modalMode, setModalMode] = useState<ModalMode>('transaction');
  const [targetSupplierId, setTargetSupplierId] = useState<number | undefined>(undefined);
  const [targetClientId, setTargetClientId] = useState<number | undefined>(undefined);
  const [targetName, setTargetName] = useState<string>('');

  // Editing State
  const [editingId, setEditingId] = useState<number | null>(null);
  const [editingInitialData, setEditingInitialData] = useState<any>(null);

  // Search State
  const [searchTerm, setSearchTerm] = useState('');

  // Load data on mount
  useEffect(() => {
    setTransactions(loadTransactions());
    setClients(loadClients());
    setSuppliers(loadSuppliers());
    setItems(loadItems());
  }, []);

  // Calculate Stats
  const stats: Stats = useMemo(() => {
    let income = 0;
    let expense = 0;
    transactions.forEach(t => {
      if (t.type === 'income') income += t.amount;
      else expense += t.amount;
    });
    return { income, expense, balance: income - expense };
  }, [transactions]);

  // Filter Logic
  const filteredTransactions = useMemo(() => {
    if (!searchTerm) return transactions;
    return transactions.filter(t => 
      t.name.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [transactions, searchTerm]);

  const filteredClients = useMemo(() => {
    if (!searchTerm) return clients;
    return clients.filter(c => 
      c.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      c.phone.includes(searchTerm)
    );
  }, [clients, searchTerm]);

  const filteredSuppliers = useMemo(() => {
    if (!searchTerm) return suppliers;
    return suppliers.filter(s => {
        const nameMatch = s.name.toLowerCase().includes(searchTerm.toLowerCase());
        const phoneMatch = s.phone.includes(searchTerm);
        return nameMatch || phoneMatch;
    });
  }, [suppliers, searchTerm]);

  const filteredItems = useMemo(() => {
    if (!searchTerm) return items;
    return items.filter(i => {
        const itemMatch = i.name.toLowerCase().includes(searchTerm.toLowerCase());
        const supplierMatch = suppliers.find(s => s.id === i.supplierId)?.name.toLowerCase().includes(searchTerm.toLowerCase());
        return itemMatch || supplierMatch;
    });
  }, [items, suppliers, searchTerm]);

  // CSV Export Logic
  const handleExportCSV = () => {
    let csvContent = "data:text/csv;charset=utf-8,\uFEFF"; 
    let filename = "export.csv";

    if (currentView === 'clients') {
      csvContent += "ID,Name,Phone\n";
      filteredClients.forEach(c => { csvContent += `${c.id},"${c.name}","${c.phone}"\n`; });
      filename = "clients.csv";
    } else if (currentView === 'suppliers') {
      csvContent += "ID,Name,Phone\n";
      filteredSuppliers.forEach(s => { csvContent += `${s.id},"${s.name}","${s.phone}"\n`; });
      filename = "suppliers.csv";
    } else if (currentView === 'items') {
        csvContent += "ID,Name,Supplier\n";
        filteredItems.forEach(i => {
           const supplierName = suppliers.find(s => s.id === i.supplierId)?.name || 'Unknown';
           csvContent += `${i.id},"${i.name}","${supplierName}"\n`;
        });
        filename = "items.csv";
    } else {
      csvContent += "ID,Date,Description,Type,Amount\n";
      filteredTransactions.forEach(t => {
         const typeAr = t.type === 'income' ? 'قبض' : 'صرف';
         csvContent += `${t.id},${t.date},"${t.name}",${typeAr},${t.amount}\n`;
      });
      filename = "transactions.csv";
    }

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", filename);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // --- Handlers ---

  const handleSaveTransaction = (data: { name: string; amount: number; type: TransactionType; clientId?: number; supplierId?: number }) => {
    if (editingId) {
        // Edit Existing Transaction
        const updated = transactions.map(t => t.id === editingId ? { ...t, ...data } : t);
        setTransactions(updated);
        saveTransactions(updated);
    } else {
        // Create New Transaction
        const newTrx: Transaction = {
          id: Date.now(),
          name: data.name,
          amount: data.amount,
          type: data.type,
          date: new Date().toLocaleDateString('ar-EG'),
          clientId: data.clientId,
          supplierId: data.supplierId
        };
        const updated = [...transactions, newTrx];
        setTransactions(updated);
        saveTransactions(updated);
    }
    closeModal();
  };

  const handleSaveTrade = (data: { 
      clientId: number; 
      supplierId: number; 
      itemId: number; 
      itemName: string;
      quantity: number; 
      buyPrice: number; 
      sellPrice: number; 
  }) => {
      const now = Date.now();
      const dateStr = new Date().toLocaleDateString('ar-EG');

      const purchaseTrx: Transaction = {
          id: now,
          name: `توريد: ${data.itemName} (عدد ${data.quantity})`,
          amount: data.quantity * data.buyPrice,
          type: 'expense',
          date: dateStr,
          supplierId: data.supplierId,
          itemId: data.itemId,
          quantity: data.quantity,
          unitPrice: data.buyPrice
      };

      const saleTrx: Transaction = {
          id: now + 1,
          name: `بيع: ${data.itemName} (عدد ${data.quantity})`,
          amount: data.quantity * data.sellPrice,
          type: 'income',
          date: dateStr,
          clientId: data.clientId,
          itemId: data.itemId,
          quantity: data.quantity,
          unitPrice: data.sellPrice,
          relatedTransactionId: now
      };

      const updated = [...transactions, purchaseTrx, saleTrx];
      setTransactions(updated);
      saveTransactions(updated);
      closeModal();
  };

  const handleSaveClient = (data: { name: string; phone: string; image?: string }) => {
    let updated: Client[];
    if (editingId) {
        updated = clients.map(c => c.id === editingId ? { ...c, ...data, image: data.image || c.image } : c);
    } else {
        const newClient: Client = { id: Date.now(), name: data.name, phone: data.phone, image: data.image };
        updated = [...clients, newClient];
    }
    setClients(updated);
    saveClients(updated);
    closeModal();
  };

  const handleSaveSupplier = (data: { name: string; phone: string; image?: string }) => {
      let updated: Supplier[];
      if (editingId) {
          updated = suppliers.map(s => s.id === editingId ? { ...s, ...data, image: data.image || s.image } : s);
      } else {
          const newSupplier: Supplier = { id: Date.now(), name: data.name, phone: data.phone, image: data.image };
          updated = [...suppliers, newSupplier];
      }
      setSuppliers(updated);
      saveSuppliers(updated);
      closeModal();
  };

  const handleSaveItem = (data: { name: string; supplierId: number; image?: string }) => {
      let updated: Item[];
      if (editingId) {
          updated = items.map(i => i.id === editingId ? { ...i, ...data, image: data.image || i.image } : i);
      } else {
          const newItem: Item = { id: Date.now(), name: data.name, supplierId: data.supplierId, image: data.image };
          updated = [...items, newItem];
      }
      setItems(updated);
      saveItems(updated);
      closeModal();
  };

  // --- Deletion Handlers ---
  const handleDeleteTransaction = (id: number) => {
    const updated = transactions.filter(t => t.id !== id);
    setTransactions(updated);
    saveTransactions(updated);
  };
  const handleDeleteClient = (id: number) => {
    const updated = clients.filter(c => c.id !== id);
    setClients(updated);
    saveClients(updated);
  };
  const handleDeleteSupplier = (id: number) => {
      const updatedSuppliers = suppliers.filter(s => s.id !== id);
      const updatedItems = items.filter(i => i.supplierId !== id); 
      setSuppliers(updatedSuppliers);
      setItems(updatedItems);
      saveSuppliers(updatedSuppliers);
      saveItems(updatedItems);
  };
  const handleDeleteItem = (id: number) => {
      const updated = items.filter(i => i.id !== id);
      setItems(updated);
      saveItems(updated);
  };
  const handleClearData = () => {
    clearAllData();
    setTransactions([]);
    setClients([]);
    setSuppliers([]);
    setItems([]);
    window.location.reload();
  };

  // --- Modal Triggers ---
  const closeModal = () => {
      setIsModalOpen(false);
      setEditingId(null);
      setEditingInitialData(null);
      setTargetClientId(undefined);
      setTargetSupplierId(undefined);
      setTargetName('');
  };

  const openTransactionModal = () => {
      setModalMode('transaction');
      setIsModalOpen(true);
  };

  const openTradeModal = () => {
      setModalMode('trade');
      setIsModalOpen(true);
  };

  const openClientModal = () => {
      setModalMode('add-client');
      setIsModalOpen(true);
  };
  const openSupplierModal = () => {
      setModalMode('add-supplier');
      setIsModalOpen(true);
  };
  const openAddItemModal = (supplierId?: number) => {
      setTargetSupplierId(supplierId);
      setModalMode('add-item');
      setIsModalOpen(true);
  };
  const handleClientAction = (clientId: number, clientName: string) => {
      setTargetClientId(clientId);
      setTargetName(clientName);
      setModalMode('client-action');
      setIsModalOpen(true);
  };
  const handleSupplierAction = (supplierId: number, supplierName: string) => {
      setTargetSupplierId(supplierId);
      setTargetName(supplierName);
      setModalMode('supplier-action');
      setIsModalOpen(true);
  };

  // Edit Triggers
  const handleEditClient = (client: Client) => {
      setEditingId(client.id);
      setEditingInitialData(client);
      setModalMode('add-client');
      setIsModalOpen(true);
  };
  const handleEditSupplier = (supplier: Supplier) => {
      setEditingId(supplier.id);
      setEditingInitialData(supplier);
      setModalMode('add-supplier');
      setIsModalOpen(true);
  };
  const handleEditTransaction = (trx: Transaction) => {
      setEditingId(trx.id);
      setEditingInitialData(trx);
      setModalMode('transaction');
      setIsModalOpen(true);
  };
  const handleEditItem = (item: Item) => {
      setEditingId(item.id);
      setEditingInitialData(item);
      setModalMode('add-item');
      setIsModalOpen(true);
  };

  return (
    <div className="flex min-h-screen bg-slate-50 font-sans">
      <Sidebar 
        currentView={currentView} 
        onChangeView={setCurrentView} 
        onClearData={handleClearData} 
      />

      <main className="flex-1 flex flex-col relative overflow-hidden">
        {/* Header */}
        <header className="h-20 bg-white shadow-sm flex justify-between items-center px-8 z-20 no-print sticky top-0">
          <div>
            <h2 className="text-xl font-bold text-slate-800">
                {currentView === 'dashboard' && 'لوحة التحكم الرئيسية'}
                {currentView === 'clients' && 'إدارة العملاء'}
                {currentView === 'suppliers' && 'الموردين والشركات'}
                {currentView === 'items' && 'المخزن والأصناف'}
                {currentView === 'invoices' && 'سجل الفواتير'}
            </h2>
          </div>

          <div className="flex-1 mx-8 max-w-lg hidden md:block">
            <div className="relative group">
              <Search className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-blue-500 transition-colors" size={18} />
              <input 
                type="text" 
                placeholder="بحث..." 
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full bg-slate-100 border-none rounded-xl py-2.5 pr-10 pl-4 focus:ring-2 focus:ring-blue-500 outline-none transition-all text-sm"
              />
            </div>
          </div>

          <div className="flex items-center gap-3">
             {/* New Trade Button in Header */}
             <button 
                onClick={openTradeModal}
                className="hidden lg:flex items-center gap-2 bg-slate-900 text-white px-4 py-2 rounded-lg hover:bg-slate-700 transition text-sm font-bold shadow-sm"
                title="فاتورة تجارية جديدة (بيع وشراء)"
             >
                <ShoppingCart size={18} />
                <span>فاتورة تجارية</span>
             </button>

             <ShareButton 
                currentView={currentView} 
                stats={stats} 
                counts={{
                    clients: clients.length,
                    suppliers: suppliers.length,
                    items: items.length,
                    transactions: transactions.length
                }}
             />

             <button onClick={handleExportCSV} className="flex items-center gap-2 bg-emerald-600 text-white px-4 py-2 rounded-lg hover:bg-emerald-700 transition text-sm font-bold shadow-sm" title="تصدير إلى CSV">
                <Download size={18} />
                <span className="hidden xl:inline">تصدير CSV</span>
             </button>
             <button onClick={() => window.print()} className="flex items-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition text-sm font-bold shadow-sm">
                <Printer size={18} />
                <span className="hidden xl:inline">طباعة</span>
             </button>
          </div>
        </header>

        {/* Content */}
        <div className="flex-1 overflow-auto p-8 relative">
          <div className="max-w-7xl mx-auto">
            <div className="hidden print-only mb-8 text-center border-b pb-4">
                <h1 className="text-3xl font-bold text-black mb-2">Al-Mohaseb Pro - تقرير مالي</h1>
                <p className="text-gray-600">تاريخ التقرير: {new Date().toLocaleDateString('ar-EG')}</p>
            </div>

            {currentView === 'dashboard' && <Dashboard stats={stats} transactions={filteredTransactions} onDeleteTransaction={handleDeleteTransaction} onEditTransaction={handleEditTransaction} />}
            {currentView === 'invoices' && <Invoices transactions={filteredTransactions} onDeleteTransaction={handleDeleteTransaction} onEditTransaction={handleEditTransaction} searchTerm={searchTerm} onSearchChange={setSearchTerm} />}
            {currentView === 'clients' && <Clients clients={filteredClients} onDeleteClient={handleDeleteClient} onEditClient={handleEditClient} onOpenAddModal={openClientModal} onClientAction={handleClientAction} />}
            {currentView === 'suppliers' && <Suppliers suppliers={filteredSuppliers} onDeleteSupplier={handleDeleteSupplier} onEditSupplier={handleEditSupplier} onOpenAddSupplierModal={openSupplierModal} onSupplierAction={handleSupplierAction} />}
            {currentView === 'items' && <Items items={filteredItems} suppliers={suppliers} onDeleteItem={handleDeleteItem} onEditItem={handleEditItem} onOpenAddItemModal={() => openAddItemModal()} />}
          </div>
        </div>

        {/* FAB */}
        <button
          onClick={() => {
              if (currentView === 'clients') openClientModal();
              else if (currentView === 'suppliers') openSupplierModal();
              else if (currentView === 'items') openAddItemModal();
              else openTransactionModal();
          }}
          className={`fixed bottom-8 left-8 text-white w-14 h-14 rounded-full shadow-2xl flex items-center justify-center transition-transform hover:scale-110 active:scale-95 z-40 no-print ${currentView === 'suppliers' ? 'bg-orange-600 hover:bg-orange-700' : currentView === 'items' ? 'bg-slate-700 hover:bg-slate-800' : 'bg-blue-600 hover:bg-blue-700'}`}
        >
          <Plus size={28} />
        </button>

        <AddModal 
          isOpen={isModalOpen}
          mode={modalMode}
          targetSupplierId={targetSupplierId}
          targetClientId={targetClientId}
          targetName={targetName}
          suppliers={suppliers}
          clients={clients}
          items={items}
          initialData={editingInitialData}
          onClose={closeModal}
          onSaveTransaction={handleSaveTransaction}
          onSaveTrade={handleSaveTrade}
          onSaveClient={handleSaveClient}
          onSaveSupplier={handleSaveSupplier}
          onSaveItem={handleSaveItem}
        />
      </main>
    </div>
  );
}

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { Share2, FileText, MessageCircle, X, Smartphone } from 'lucide-react';
import { ViewState, Stats } from '../types';

interface ShareButtonProps {
  currentView: ViewState;
  stats: Stats;
  counts: {
    clients: number;
    suppliers: number;
    items: number;
    transactions: number;
  };
}

const ShareButton: React.FC<ShareButtonProps> = ({ currentView, stats, counts }) => {
  const [isOpen, setIsOpen] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);

  // Close dropdown when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handlePrint = () => {
    setIsOpen(false);
    setTimeout(() => window.print(), 100);
  };

  const generateReportText = () => {
    const date = new Date().toLocaleDateString('ar-EG');
    let message = `📊 *تقرير المحاسب الذكي - مكتب بهاء*\n`;
    message += `📅 التاريخ: ${date}\n`;
    message += `------------------------\n`;

    if (currentView === 'dashboard' || currentView === 'invoices') {
      message += `*الوضع المالي الحالي:*\n`;
      message += `✅ إجمالي الدخل: ${stats.income.toLocaleString()} ج.م\n`;
      message += `❌ إجمالي المصروفات: ${stats.expense.toLocaleString()} ج.م\n`;
      message += `💰 صافي الرصيد: ${stats.balance.toLocaleString()} ج.م\n`;
      message += `🔢 عدد العمليات: ${counts.transactions}\n`;
    } else if (currentView === 'clients') {
      message += `*تقرير العملاء:*\n`;
      message += `👥 عدد العملاء المسجلين: ${counts.clients}\n`;
    } else if (currentView === 'suppliers') {
      message += `*تقرير الموردين:*\n`;
      message += `🚛 عدد الموردين: ${counts.suppliers}\n`;
    } else if (currentView === 'items') {
      message += `*تقرير المخزن:*\n`;
      message += `📦 عدد الأصناف: ${counts.items}\n`;
    }

    message += `------------------------\n`;
    message += `تم الاستخراج بواسطة نظام المحاسب الذكي`;
    return message;
  };

  const handleWhatsApp = () => {
    setIsOpen(false);
    const message = generateReportText();
    const url = `https://wa.me/?text=${encodeURIComponent(message)}`;
    window.open(url, '_blank');
  };

  const handleNativeShare = async () => {
    setIsOpen(false);
    const message = generateReportText();
    if (navigator.share) {
      try {
        await navigator.share({
          title: 'تقرير المحاسب الذكي',
          text: message,
        });
      } catch (err) {
        console.error('Error sharing:', err);
      }
    } else {
      handleWhatsApp();
    }
  };

  return (
    <div className="relative no-print" ref={dropdownRef}>
      <button 
        onClick={() => setIsOpen(!isOpen)}
        className="flex items-center gap-2 bg-indigo-600 text-white px-4 py-2 rounded-lg hover:bg-indigo-700 transition text-sm font-bold shadow-sm"
      >
        <Share2 size={18} />
        <span className="hidden xl:inline">مشاركة / طباعة</span>
      </button>

      {isOpen && (
        <div className="absolute left-0 mt-2 w-56 bg-white rounded-xl shadow-xl border border-slate-100 z-50 overflow-hidden fade-in">
          <div className="p-3 border-b border-slate-100 bg-slate-50 flex justify-between items-center">
            <span className="text-xs font-bold text-slate-500">اختر طريقة المشاركة</span>
            <button onClick={() => setIsOpen(false)} className="text-slate-400 hover:text-red-500">
                <X size={14} />
            </button>
          </div>
          <div className="p-2 space-y-1">
            <button 
              onClick={handleWhatsApp}
              className="w-full flex items-center gap-3 px-3 py-2.5 text-sm font-medium text-slate-700 hover:bg-green-50 hover:text-green-700 rounded-lg transition-colors"
            >
              <MessageCircle size={18} className="text-green-500" />
              <span>إرسال تقرير واتساب</span>
            </button>

            <button 
              onClick={handlePrint}
              className="w-full flex items-center gap-3 px-3 py-2.5 text-sm font-medium text-slate-700 hover:bg-red-50 hover:text-red-700 rounded-lg transition-colors"
            >
              <FileText size={18} className="text-red-500" />
              <span>طباعة / حفظ كـ PDF</span>
            </button>

            {/* زر المشاركة العامة يظهر فقط في المتصفحات التي تدعمه (الموبايل غالباً) */}
            {typeof navigator !== 'undefined' && navigator.share && (
                <button 
                onClick={handleNativeShare}
                className="w-full flex items-center gap-3 px-3 py-2.5 text-sm font-medium text-slate-700 hover:bg-blue-50 hover:text-blue-700 rounded-lg transition-colors"
                >
                <Smartphone size={18} className="text-blue-500" />
                <span>مشاركة (تطبيقات أخرى)</span>
                </button>
            )}
          </div>
          <div className="p-2 bg-yellow-50 text-[10px] text-yellow-800 text-center border-t border-yellow-100">
             لمشاركة ملف PDF عبر واتساب: اضغط "حفظ كـ PDF" أولاً، ثم أرسل الملف يدوياً.
          </div>
        </div>
      )}
    </div>
  );
};

export default ShareButton;

import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import Clients from './components/Clients';
import Suppliers from './components/Suppliers';
import Items from './components/Items';
import Invoices from './components/Invoices';
import AddModal from './components/AddModal';
import ShareButton from './components/ShareButton';
import { ViewState, Transaction, Client, Supplier, Item, Stats, TransactionType, ModalMode } from './types';
import { 
    loadTransactions, saveTransactions, 
    loadClients, saveClients, 
    loadSuppliers, saveSuppliers, 
    loadItems, saveItems, 
    clearAllData 
} from './services/storage';
import { Plus, Printer, Bell, Search, Download, ShoppingCart } from 'lucide-react';

function App() {
  const [currentView, setCurrentView] = useState<ViewState>('dashboard');

  // Data State
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [clients, setClients] = useState<Client[]>([]);
  const [suppliers, setSuppliers] = useState<Supplier[]>([]);
  const [items, setItems] = useState<Item[]>([]);

  // Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [modalMode, setModalMode] = useState<ModalMode>('transaction');
  const [targetSupplierId, setTargetSupplierId] = useState<number | undefined>(undefined);
  const [targetClientId, setTargetClientId] = useState<number | undefined>(undefined);
  const [targetName, setTargetName] = useState<string>('');

  // Editing State
  const [editingId, setEditingId] = useState<number | null>(null);
  const [editingInitialData, setEditingInitialData] = useState<any>(null);

  // Search State
  const [searchTerm, setSearchTerm] = useState('');

  // Load data on mount
  useEffect(() => {
    setTransactions(loadTransactions());
    setClients(loadClients());
    setSuppliers(loadSuppliers());
    setItems(loadItems());
  }, []);

  // Calculate Stats
  const stats: Stats = useMemo(() => {
    let income = 0;
    let expense = 0;
    transactions.forEach(t => {
      if (t.type === 'income') income += t.amount;
      else expense += t.amount;
    });
    return { income, expense, balance: income - expense };
  }, [transactions]);

  // Filter Logic
  const filteredTransactions = useMemo(() => {
    if (!searchTerm) return transactions;
    return transactions.filter(t => 
      t.name.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [transactions, searchTerm]);

  const filteredClients = useMemo(() => {
    if (!searchTerm) return clients;
    return clients.filter(c => 
      c.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      c.phone.includes(searchTerm)
    );
  }, [clients, searchTerm]);

  const filteredSuppliers = useMemo(() => {
    if (!searchTerm) return suppliers;
    return suppliers.filter(s => {
        const nameMatch = s.name.toLowerCase().includes(searchTerm.toLowerCase());
        const phoneMatch = s.phone.includes(searchTerm);
        return nameMatch || phoneMatch;
    });
  }, [suppliers, searchTerm]);

  const filteredItems = useMemo(() => {
    if (!searchTerm) return items;
    return items.filter(i => {
        const itemMatch = i.name.toLowerCase().includes(searchTerm.toLowerCase());
        const supplierMatch = suppliers.find(s => s.id === i.supplierId)?.name.toLowerCase().includes(searchTerm.toLowerCase());
        return itemMatch || supplierMatch;
    });
  }, [items, suppliers, searchTerm]);

  // CSV Export Logic
  const handleExportCSV = () => {
    let csvContent = "data:text/csv;charset=utf-8,\uFEFF"; 
    let filename = "export.csv";

    if (currentView === 'clients') {
      csvContent += "ID,Name,Phone\n";
      filteredClients.forEach(c => { csvContent += `${c.id},"${c.name}","${c.phone}"\n`; });
      filename = "clients.csv";
    } else if (currentView === 'suppliers') {
      csvContent += "ID,Name,Phone\n";
      filteredSuppliers.forEach(s => { csvContent += `${s.id},"${s.name}","${s.phone}"\n`; });
      filename = "suppliers.csv";
    } else if (currentView === 'items') {
        csvContent += "ID,Name,Supplier\n";
        filteredItems.forEach(i => {
           const supplierName = suppliers.find(s => s.id === i.supplierId)?.name || 'Unknown';
           csvContent += `${i.id},"${i.name}","${supplierName}"\n`;
        });
        filename = "items.csv";
    } else {
      csvContent += "ID,Date,Description,Type,Amount\n";
      filteredTransactions.forEach(t => {
         const typeAr = t.type === 'income' ? 'قبض' : 'صرف';
         csvContent += `${t.id},${t.date},"${t.name}",${typeAr},${t.amount}\n`;
      });
      filename = "transactions.csv";
    }

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", filename);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // --- Handlers ---

  const handleSaveTransaction = (data: { name: string; amount: number; type: TransactionType; clientId?: number; supplierId?: number }) => {
    if (editingId) {
        // Edit Existing Transaction
        const updated = transactions.map(t => t.id === editingId ? { ...t, ...data } : t);
        setTransactions(updated);
        saveTransactions(updated);
    } else {
        // Create New Transaction
        const newTrx: Transaction = {
          id: Date.now(),
          name: data.name,
          amount: data.amount,
          type: data.type,
          date: new Date().toLocaleDateString('ar-EG'),
          clientId: data.clientId,
          supplierId: data.supplierId
        };
        const updated = [...transactions, newTrx];
        setTransactions(updated);
        saveTransactions(updated);
    }
    closeModal();
  };

  const handleSaveTrade = (data: { 
      clientId: number; 
      supplierId: number; 
      itemId: number; 
      itemName: string;
      quantity: number; 
      buyPrice: number; 
      sellPrice: number; 
  }) => {
      const now = Date.now();
      const dateStr = new Date().toLocaleDateString('ar-EG');

      const purchaseTrx: Transaction = {
          id: now,
          name: `توريد: ${data.itemName} (عدد ${data.quantity})`,
          amount: data.quantity * data.buyPrice,
          type: 'expense',
          date: dateStr,
          supplierId: data.supplierId,
          itemId: data.itemId,
          quantity: data.quantity,
          unitPrice: data.buyPrice
      };

      const saleTrx: Transaction = {
          id: now + 1,
          name: `بيع: ${data.itemName} (عدد ${data.quantity})`,
          amount: data.quantity * data.sellPrice,
          type: 'income',
          date: dateStr,
          clientId: data.clientId,
          itemId: data.itemId,
          quantity: data.quantity,
          unitPrice: data.sellPrice,
          relatedTransactionId: now
      };

      const updated = [...transactions, purchaseTrx, saleTrx];
      setTransactions(updated);
      saveTransactions(updated);
      closeModal();
  };

  const handleSaveClient = (data: { name: string; phone: string; image?: string }) => {
    let updated: Client[];
    if (editingId) {
        updated = clients.map(c => c.id === editingId ? { ...c, ...data, image: data.image || c.image } : c);
    } else {
        const newClient: Client = { id: Date.now(), name: data.name, phone: data.phone, image: data.image };
        updated = [...clients, newClient];
    }
    setClients(updated);
    saveClients(updated);
    closeModal();
  };

  const handleSaveSupplier = (data: { name: string; phone: string; image?: string }) => {
      let updated: Supplier[];
      if (editingId) {
          updated = suppliers.map(s => s.id === editingId ? { ...s, ...data, image: data.image || s.image } : s);
      } else {
          const newSupplier: Supplier = { id: Date.now(), name: data.name, phone: data.phone, image: data.image };
          updated = [...suppliers, newSupplier];
      }
      setSuppliers(updated);
      saveSuppliers(updated);
      closeModal();
  };

  const handleSaveItem = (data: { name: string; supplierId: number; image?: string }) => {
      let updated: Item[];
      if (editingId) {
          updated = items.map(i => i.id === editingId ? { ...i, ...data, image: data.image || i.image } : i);
      } else {
          const newItem: Item = { id: Date.now(), name: data.name, supplierId: data.supplierId, image: data.image };
          updated = [...items, newItem];
      }
      setItems(updated);
      saveItems(updated);
      closeModal();
  };

  // --- Deletion Handlers ---
  const handleDeleteTransaction = (id: number) => {
    const updated = transactions.filter(t => t.id !== id);
    setTransactions(updated);
    saveTransactions(updated);
  };
  const handleDeleteClient = (id: number) => {
    const updated = clients.filter(c => c.id !== id);
    setClients(updated);
    saveClients(updated);
  };
  const handleDeleteSupplier = (id: number) => {
      const updatedSuppliers = suppliers.filter(s => s.id !== id);
      const updatedItems = items.filter(i => i.supplierId !== id); 
      setSuppliers(updatedSuppliers);
      setItems(updatedItems);
      saveSuppliers(updatedSuppliers);
      saveItems(updatedItems);
  };
  const handleDeleteItem = (id: number) => {
      const updated = items.filter(i => i.id !== id);
      setItems(updated);
      saveItems(updated);
  };
  const handleClearData = () => {
    clearAllData();
    setTransactions([]);
    setClients([]);
    setSuppliers([]);
    setItems([]);
    window.location.reload();
  };

  // --- Modal Triggers ---
  const closeModal = () => {
      setIsModalOpen(false);
      setEditingId(null);
      setEditingInitialData(null);
      setTargetClientId(undefined);
      setTargetSupplierId(undefined);
      setTargetName('');
  };

  const openTransactionModal = () => {
      setModalMode('transaction');
      setIsModalOpen(true);
  };

  const openTradeModal = () => {
      setModalMode('trade');
      setIsModalOpen(true);
  };

  const openClientModal = () => {
      setModalMode('add-client');
      setIsModalOpen(true);
  };
  const openSupplierModal = () => {
      setModalMode('add-supplier');
      setIsModalOpen(true);
  };
  const openAddItemModal = (supplierId?: number) => {
      setTargetSupplierId(supplierId);
      setModalMode('add-item');
      setIsModalOpen(true);
  };
  const handleClientAction = (clientId: number, clientName: string) => {
      setTargetClientId(clientId);
      setTargetName(clientName);
      setModalMode('client-action');
      setIsModalOpen(true);
  };
  const handleSupplierAction = (supplierId: number, supplierName: string) => {
      setTargetSupplierId(supplierId);
      setTargetName(supplierName);
      setModalMode('supplier-action');
      setIsModalOpen(true);
  };

  // Edit Triggers
  const handleEditClient = (client: Client) => {
      setEditingId(client.id);
      setEditingInitialData(client);
      setModalMode('add-client');
      setIsModalOpen(true);
  };
  const handleEditSupplier = (supplier: Supplier) => {
      setEditingId(supplier.id);
      setEditingInitialData(supplier);
      setModalMode('add-supplier');
      setIsModalOpen(true);
  };
  const handleEditTransaction = (trx: Transaction) => {
      setEditingId(trx.id);
      setEditingInitialData(trx);
      setModalMode('transaction');
      setIsModalOpen(true);
  };
  const handleEditItem = (item: Item) => {
      setEditingId(item.id);
      setEditingInitialData(item);
      setModalMode('add-item');
      setIsModalOpen(true);
  };

  return (
    <div className="flex min-h-screen bg-slate-50 font-sans">
      <Sidebar 
        currentView={currentView} 
        onChangeView={setCurrentView} 
        onClearData={handleClearData} 
      />

      <main className="flex-1 flex flex-col relative overflow-hidden">
        {/* Header */}
        <header className="h-20 bg-white shadow-sm flex justify-between items-center px-8 z-20 no-print sticky top-0">
          <div>
            <h2 className="text-xl font-bold text-slate-800">
                {currentView === 'dashboard' && 'لوحة التحكم الرئيسية'}
                {currentView === 'clients' && 'إدارة العملاء'}
                {currentView === 'suppliers' && 'الموردين والشركات'}
                {currentView === 'items' && 'المخزن والأصناف'}
                {currentView === 'invoices' && 'سجل الفواتير'}
            </h2>
          </div>

          <div className="flex-1 mx-8 max-w-lg hidden md:block">
            <div className="relative group">
              <Search className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-blue-500 transition-colors" size={18} />
              <input 
                type="text" 
                placeholder="بحث..." 
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full bg-slate-100 border-none rounded-xl py-2.5 pr-10 pl-4 focus:ring-2 focus:ring-blue-500 outline-none transition-all text-sm"
              />
            </div>
          </div>

          <div className="flex items-center gap-3">
             {/* New Trade Button in Header */}
             <button 
                onClick={openTradeModal}
                className="hidden lg:flex items-center gap-2 bg-slate-900 text-white px-4 py-2 rounded-lg hover:bg-slate-700 transition text-sm font-bold shadow-sm"
                title="فاتورة تجارية جديدة (بيع وشراء)"
             >
                <ShoppingCart size={18} />
                <span>فاتورة تجارية</span>
             </button>

             <ShareButton 
                currentView={currentView} 
                stats={stats} 
                counts={{
                    clients: clients.length,
                    suppliers: suppliers.length,
                    items: items.length,
                    transactions: transactions.length
                }}
             />

             <button onClick={handleExportCSV} className="flex items-center gap-2 bg-emerald-600 text-white px-4 py-2 rounded-lg hover:bg-emerald-700 transition text-sm font-bold shadow-sm" title="تصدير إلى CSV">
                <Download size={18} />
                <span className="hidden xl:inline">تصدير CSV</span>
             </button>
             <button onClick={() => window.print()} className="flex items-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition text-sm font-bold shadow-sm">
                <Printer size={18} />
                <span className="hidden xl:inline">طباعة</span>
             </button>
          </div>
        </header>

        {/* Content */}
        <div className="flex-1 overflow-auto p-8 relative">
          <div className="max-w-7xl mx-auto">
            {/* Print Header */}
            <div className="hidden print-only mb-8 border-b-2 border-slate-800 pb-4">
                <div className="flex justify-between items-center">
                    <div>
                        <h1 className="text-4xl font-extrabold text-black mb-1">المحاسب الذكي</h1>
                        <p className="text-gray-600 font-bold text-lg">مكتب بهاء للتجارة والتوزيع</p>
                    </div>
                    <div className="text-left">
                        <p className="text-gray-500 text-sm">تاريخ التقرير</p>
                        <p className="font-bold text-xl">{new Date().toLocaleDateString('ar-EG', { year: 'numeric', month: 'long', day: 'numeric' })}</p>
                    </div>
                </div>
            </div>

            {currentView === 'dashboard' && <Dashboard stats={stats} transactions={filteredTransactions} onDeleteTransaction={handleDeleteTransaction} onEditTransaction={handleEditTransaction} />}
            {currentView === 'invoices' && <Invoices transactions={filteredTransactions} onDeleteTransaction={handleDeleteTransaction} onEditTransaction={handleEditTransaction} searchTerm={searchTerm} onSearchChange={setSearchTerm} />}
            {currentView === 'clients' && <Clients clients={filteredClients} onDeleteClient={handleDeleteClient} onEditClient={handleEditClient} onOpenAddModal={openClientModal} onClientAction={handleClientAction} />}
            {currentView === 'suppliers' && <Suppliers suppliers={filteredSuppliers} onDeleteSupplier={handleDeleteSupplier} onEditSupplier={handleEditSupplier} onOpenAddSupplierModal={openSupplierModal} onSupplierAction={handleSupplierAction} />}
            {currentView === 'items' && <Items items={filteredItems} suppliers={suppliers} onDeleteItem={handleDeleteItem} onEditItem={handleEditItem} onOpenAddItemModal={() => openAddItemModal()} />}
          </div>
        </div>

        {/* FAB */}
        <button
          onClick={() => {
              if (currentView === 'clients') openClientModal();
              else if (currentView === 'suppliers') openSupplierModal();
              else if (currentView === 'items') openAddItemModal();
              else openTransactionModal();
          }}
          className={`fixed bottom-8 left-8 text-white w-14 h-14 rounded-full shadow-2xl flex items-center justify-center transition-transform hover:scale-110 active:scale-95 z-40 no-print ${currentView === 'suppliers' ? 'bg-orange-600 hover:bg-orange-700' : currentView === 'items' ? 'bg-slate-700 hover:bg-slate-800' : 'bg-blue-600 hover:bg-blue-700'}`}
        >
          <Plus size={28} />
        </button>

        <AddModal 
          isOpen={isModalOpen}
          mode={modalMode}
          targetSupplierId={targetSupplierId}
          targetClientId={targetClientId}
          targetName={targetName}
          suppliers={suppliers}
          clients={clients}
          items={items}
          initialData={editingInitialData}
          onClose={closeModal}
          onSaveTransaction={handleSaveTransaction}
          onSaveTrade={handleSaveTrade}
          onSaveClient={handleSaveClient}
          onSaveSupplier={handleSaveSupplier}
          onSaveItem={handleSaveItem}
        />
      </main>
    </div>
  );
}

