import React, { useMemo } from 'react';
import { Client, Transaction } from '../types';
import { ArrowRight, Printer, User, Phone, Calendar, DollarSign, FileText } from 'lucide-react';

interface ClientDetailsProps {
  client: Client;
  transactions: Transaction[];
  onBack: () => void;
}

const ClientDetails: React.FC<ClientDetailsProps> = ({ client, transactions, onBack }) => {

  // تصفية العمليات الخاصة بهذا العميل فقط
  const clientTransactions = useMemo(() => {
    return transactions
      .filter(t => t.clientId === client.id)
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()); // الأحدث أولاً
  }, [transactions, client.id]);

  // حساب الإجماليات
  const totals = useMemo(() => {
    let totalPaid = 0; // مقبوضات (دخل)
    let totalInvoiced = 0; // عمليات أخرى (يمكن اعتبارها مديونية إذا كان النظام يدعم الآجل)

    // في هذا النظام البسيط، سنعرض إجمالي التعاملات
    // يمكن تطوير المنطق هنا ليعكس "الديون" مقابل "السداد" إذا تم إضافة حقل فرعي للعملية
    clientTransactions.forEach(t => {
       if (t.type === 'income') totalPaid += t.amount;
       else totalInvoiced += t.amount;
    });

    return { totalPaid, totalInvoiced, net: totalPaid - totalInvoiced };
  }, [clientTransactions]);

  return (
    <div className="space-y-6 fade-in pb-20">

      {/* Header & Navigation */}
      <div className="flex items-center justify-between no-print">
        <button 
            onClick={onBack}
            className="flex items-center gap-2 text-slate-500 hover:text-blue-600 transition font-bold"
        >
            <ArrowRight size={20} />
            العودة للعملاء
        </button>
        <button 
            onClick={() => window.print()}
            className="flex items-center gap-2 bg-slate-800 text-white px-4 py-2 rounded-lg hover:bg-slate-700 transition shadow-sm"
        >
            <Printer size={18} />
            طباعة كشف الحساب
        </button>
      </div>

      {/* Client Profile Card */}
      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 p-6 relative overflow-hidden">
        <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-blue-500 to-indigo-600"></div>
        <div className="flex flex-col md:flex-row items-center md:items-start gap-6">
            <div className="w-24 h-24 rounded-full bg-slate-100 border-4 border-white shadow-lg flex items-center justify-center overflow-hidden">
                {client.image ? (
                    <img src={client.image} alt={client.name} className="w-full h-full object-cover" />
                ) : (
                    <User size={40} className="text-slate-400" />
                )}
            </div>
            <div className="text-center md:text-right flex-1">
                <h2 className="text-2xl font-bold text-slate-800 mb-2">{client.name}</h2>
                <div className="flex flex-wrap gap-4 justify-center md:justify-start text-sm text-slate-500">
                    <div className="flex items-center gap-1 bg-slate-50 px-3 py-1 rounded-full">
                        <Phone size={14} />
                        <span className="dir-ltr">{client.phone || 'لا يوجد رقم'}</span>
                    </div>
                    <div className="flex items-center gap-1 bg-slate-50 px-3 py-1 rounded-full">
                        <Calendar size={14} />
                        <span>تاريخ التسجيل: {new Date(client.id).toLocaleDateString('ar-EG')}</span>
                    </div>
                </div>
            </div>

            {/* Summary Cards */}
            <div className="flex gap-4 mt-4 md:mt-0">
                <div className="text-center px-6 py-2 bg-emerald-50 rounded-xl border border-emerald-100">
                    <p className="text-xs text-emerald-600 font-bold mb-1">إجمالي التعاملات</p>
                    <p className="text-xl font-bold text-emerald-800">{totals.totalPaid.toLocaleString()}</p>
                </div>
                <div className="text-center px-6 py-2 bg-blue-50 rounded-xl border border-blue-100">
                    <p className="text-xs text-blue-600 font-bold mb-1">عدد العمليات</p>
                    <p className="text-xl font-bold text-blue-800">{clientTransactions.length}</p>
                </div>
            </div>
        </div>
      </div>

      {/* Transactions History */}
      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <div className="p-6 border-b border-slate-100 flex justify-between items-center">
            <h3 className="font-bold text-lg text-slate-800 flex items-center gap-2">
                <FileText className="text-blue-500" />
                سجل الحركات (كشف حساب)
            </h3>
        </div>

        {clientTransactions.length === 0 ? (
            <div className="text-center py-12 text-slate-400">
                <p>لا توجد حركات مسجلة لهذا العميل حتى الآن.</p>
            </div>
        ) : (
            <div className="overflow-x-auto">
                <table className="w-full text-right text-sm">
                    <thead className="bg-slate-50 text-slate-500 uppercase">
                        <tr>
                            <th className="px-6 py-4 font-semibold">التاريخ</th>
                            <th className="px-6 py-4 font-semibold">البيان / تفاصيل العملية</th>
                            <th className="px-6 py-4 font-semibold">نوع الحركة</th>
                            <th className="px-6 py-4 font-semibold">القيمة</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-100">
                        {clientTransactions.map((trx) => (
                            <tr key={trx.id} className="hover:bg-slate-50">
                                <td className="px-6 py-4 text-slate-500 whitespace-nowrap">{trx.date}</td>
                                <td className="px-6 py-4 font-medium text-slate-700">{trx.name}</td>
                                <td className="px-6 py-4">
                                    <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium ${
                                        trx.type === 'income' 
                                        ? 'bg-emerald-100 text-emerald-800' 
                                        : 'bg-red-100 text-red-800'
                                    }`}>
                                        {trx.type === 'income' ? 'قبض / شراء' : 'مرتجع / صرف'}
                                    </span>
                                </td>
                                <td className="px-6 py-4 font-bold text-slate-800 dir-ltr text-right">
                                    {trx.amount.toLocaleString()} ج.م
                                </td>
                            </tr>
                        ))}
                    </tbody>
                    <tfoot className="bg-slate-50 font-bold text-slate-800 border-t border-slate-200">
                        <tr>
                            <td colSpan={3} className="px-6 py-4 text-left pl-10">الإجمالـــي</td>
                            <td className="px-6 py-4 dir-ltr text-right text-lg">{totals.totalPaid.toLocaleString()} ج.م</td>
                        </tr>
                    </tfoot>
                </table>
            </div>
        )}
      </div>

      <div className="hidden print-only text-center mt-8 text-sm text-slate-500">
        <p>تم استخراج هذا الكشف من نظام المحاسب الذكي - مكتب بهاء</p>
      </div>

    </div>
  );
};

