            <h1 className="text-3xl font-extrabold text-white mb-2">المحاسب الذكي</h1>
            <p className="text-blue-100">نظام إدارة مكتب بهاء للتجارة</p>
        </div>

        <div className="p-8">
            <h2 className="text-xl font-bold text-slate-800 mb-6 text-center">تسجيل الدخول</h2>

            <form onSubmit={handleLogin} className="space-y-4">
                {error && (
                    <div className="bg-red-50 text-red-600 p-3 rounded-lg text-sm text-center font-bold border border-red-100">
                        {error}
                    </div>
                )}

                <div>
                    <label className="block text-sm font-bold text-slate-700 mb-1">البريد الإلكتروني</label>
                    <div className="relative">
                        <Mail className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                        <input 
                            type="email" 
                            value={email}
                            onChange={(e) => setEmail(e.target.value)}
