import { Client, Supplier, Item, Transaction, User } from '../types';

const TRX_KEY = 'almohaseb_transactions';
const CLIENTS_KEY = 'almohaseb_clients';
const SUPPLIERS_KEY = 'almohaseb_suppliers';
const ITEMS_KEY = 'almohaseb_items';
const USERS_KEY = 'almohaseb_users';
const SESSION_KEY = 'almohaseb_session';

// Users & Auth
export const loadUsers = (): User[] => {
  try {
    const data = localStorage.getItem(USERS_KEY);
    if (data) {
        const parsedUsers: User[] = JSON.parse(data);
        // Ensure all users have isActive flag (migration for existing data)
        return parsedUsers.map(u => ({ ...u, isActive: u.isActive !== undefined ? u.isActive : true }));
    }

    // Default Admin requested by user
    const defaultAdmin: User = {
        id: 1,
        name: 'mahmoud',
        email: 'admin@bahaa.com', // Keeping email for recovery reference
        password: 'Mahmoud@2025',
        role: 'admin',
        isActive: true
    };
    saveUsers([defaultAdmin]);
    return [defaultAdmin];
  } catch (e) {
    return [];
  }
};

export const saveUsers = (data: User[]) => {
  try {
    localStorage.setItem(USERS_KEY, JSON.stringify(data));
  } catch (e) {
    console.error("Failed to save users", e);
  }
};

export const getCurrentUser = (): User | null => {
    try {
        const data = localStorage.getItem(SESSION_KEY);
        return data ? JSON.parse(data) : null;
    } catch {
        return null;
    }
};

export const setCurrentUser = (user: User | null) => {
    if (user) {
        localStorage.setItem(SESSION_KEY, JSON.stringify(user));
    } else {
        localStorage.removeItem(SESSION_KEY);
    }
};

// Transactions
export const loadTransactions = (): Transaction[] => {
  try {
    const data = localStorage.getItem(TRX_KEY);
    return data ? JSON.parse(data) : [];
  } catch (e) {
