                            className="text-slate-300 hover:text-red-500 p-2 rounded-full hover:bg-red-50 transition"
                            title="حذف المستخدم نهائياً"
                        >
                            <Trash2 size={20} />
                        </button>
                    </div>
                )}
            </div>
        ))}
      </div>
    </div>
  );
};

export default Team;

import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import Clients from './components/Clients';
import Suppliers from './components/Suppliers';
import Items from './components/Items';
import Invoices from './components/Invoices';
import Team from './components/Team'; // New
import AddModal from './components/AddModal';
import ShareButton from './components/ShareButton';
import ClientDetails from './components/ClientDetails';
import InvoiceDetails from './components/InvoiceDetails';
import SettingsModal from './components/SettingsModal';
import Login from './components/Login'; // New
import { ViewState, Transaction, Client, Supplier, Item, Stats, TransactionType, ModalMode, User, UserRole } from './types';
import { 
    loadTransactions, saveTransactions, 
    loadClients, saveClients, 
    loadSuppliers, saveSuppliers, 
    loadItems, saveItems, 
    loadUsers, saveUsers, getCurrentUser, setCurrentUser, // New imports
    clearAllData 
} from './services/storage';
import { Plus, Printer, Bell, Search, Download, ShoppingCart } from 'lucide-react';

function App() {
  // Auth State
  const [currentUser, setAuthUser] = useState<User | null>(null);

  const [currentView, setCurrentView] = useState<ViewState>('dashboard');

  // Data State
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [clients, setClients] = useState<Client[]>([]);
  const [suppliers, setSuppliers] = useState<Supplier[]>([]);
  const [items, setItems] = useState<Item[]>([]);
  const [users, setUsers] = useState<User[]>([]); // New

  // Selected Details State
  const [selectedClient, setSelectedClient] = useState<Client | null>(null);
  const [selectedInvoice, setSelectedInvoice] = useState<Transaction | null>(null);

  // Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);

  const [modalMode, setModalMode] = useState<ModalMode>('transaction');
  const [targetSupplierId, setTargetSupplierId] = useState<number | undefined>(undefined);
  const [targetClientId, setTargetClientId] = useState<number | undefined>(undefined);
  const [targetName, setTargetName] = useState<string>('');

  // Editing State
  const [editingId, setEditingId] = useState<number | null>(null);
  const [editingInitialData, setEditingInitialData] = useState<any>(null);

  // Search State
  const [searchTerm, setSearchTerm] = useState('');

  // Load data
  const refreshData = () => {
    setTransactions(loadTransactions());
    setClients(loadClients());
    setSuppliers(loadSuppliers());
    setItems(loadItems());
    setUsers(loadUsers());
  };

  useEffect(() => {
    const sessionUser = getCurrentUser();
    if (sessionUser) {
        setAuthUser(sessionUser);
        refreshData();
    }
  }, []);

  // Calculate Stats
  const stats: Stats = useMemo(() => {
    let income = 0;
    let expense = 0;
    transactions.forEach(t => {
      if (t.type === 'income') income += t.amount;
      else expense += t.amount;
    });
    return { income, expense, balance: income - expense };
  }, [transactions]);

  // Filter Logic
  const filteredTransactions = useMemo(() => {
    if (!searchTerm) return transactions;
    return transactions.filter(t => 
      t.name.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [transactions, searchTerm]);

  const filteredClients = useMemo(() => {
    if (!searchTerm) return clients;
    return clients.filter(c => 
      c.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      c.phone.includes(searchTerm)
    );
  }, [clients, searchTerm]);

  const filteredSuppliers = useMemo(() => {
    if (!searchTerm) return suppliers;
    return suppliers.filter(s => {
        const nameMatch = s.name.toLowerCase().includes(searchTerm.toLowerCase());
        const phoneMatch = s.phone.includes(searchTerm);
        return nameMatch || phoneMatch;
    });
  }, [suppliers, searchTerm]);

  const filteredItems = useMemo(() => {
    if (!searchTerm) return items;
    return items.filter(i => {
        const itemMatch = i.name.toLowerCase().includes(searchTerm.toLowerCase());
        const supplierMatch = suppliers.find(s => s.id === i.supplierId)?.name.toLowerCase().includes(searchTerm.toLowerCase());
        return itemMatch || supplierMatch;
    });
  }, [items, suppliers, searchTerm]);

  // CSV Export Logic
  const handleExportCSV = () => {
    let csvContent = "data:text/csv;charset=utf-8,\uFEFF"; 
    let filename = "export.csv";

    if (currentView === 'clients') {
      csvContent += "ID,Name,Phone\n";
      filteredClients.forEach(c => { csvContent += `${c.id},"${c.name}","${c.phone}"\n`; });
      filename = "clients.csv";
    } else if (currentView === 'suppliers') {
      csvContent += "ID,Name,Phone\n";
      filteredSuppliers.forEach(s => { csvContent += `${s.id},"${s.name}","${s.phone}"\n`; });
      filename = "suppliers.csv";
    } else {
      csvContent += "ID,Date,Description,Type,Amount\n";
      filteredTransactions.forEach(t => {
         const typeAr = t.type === 'income' ? 'قبض' : 'صرف';
         csvContent += `${t.id},${t.date},"${t.name}",${typeAr},${t.amount}\n`;
      });
      filename = "transactions.csv";
    }

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", filename);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // --- Handlers ---

  const handleSaveTransaction = (data: { name: string; amount: number; type: TransactionType; clientId?: number; supplierId?: number }) => {
    if (editingId) {
        const updated = transactions.map(t => t.id === editingId ? { ...t, ...data } : t);
        setTransactions(updated);
        saveTransactions(updated);
    } else {
        const newTrx: Transaction = {
          id: Date.now(),
          name: data.name,
          amount: data.amount,
          type: data.type,
          date: new Date().toLocaleDateString('ar-EG'),
          clientId: data.clientId,
          supplierId: data.supplierId
        };
        const updated = [...transactions, newTrx];
        setTransactions(updated);
        saveTransactions(updated);
    }
    closeModal();
  };

  const handleSaveTrade = (data: { clientId: number; supplierId: number; itemId: number; itemName: string; quantity: number; buyPrice: number; sellPrice: number; }) => {
      const now = Date.now();
      const dateStr = new Date().toLocaleDateString('ar-EG');
      const purchaseTrx: Transaction = { id: now, name: `توريد: ${data.itemName} (عدد ${data.quantity})`, amount: data.quantity * data.buyPrice, type: 'expense', date: dateStr, supplierId: data.supplierId, itemId: data.itemId, quantity: data.quantity, unitPrice: data.buyPrice };
      const saleTrx: Transaction = { id: now + 1, name: `بيع: ${data.itemName} (عدد ${data.quantity})`, amount: data.quantity * data.sellPrice, type: 'income', date: dateStr, clientId: data.clientId, itemId: data.itemId, quantity: data.quantity, unitPrice: data.sellPrice, relatedTransactionId: now };
      const updated = [...transactions, purchaseTrx, saleTrx];
      setTransactions(updated);
      saveTransactions(updated);
      closeModal();
  };

  const handleSaveClient = (data: { name: string; phone: string; image?: string }) => {
    let updated: Client[];
    if (editingId) {
        updated = clients.map(c => c.id === editingId ? { ...c, ...data, image: data.image || c.image } : c);
    } else {
        updated = [...clients, { id: Date.now(), name: data.name, phone: data.phone, image: data.image }];
    }
    setClients(updated);
    saveClients(updated);
    closeModal();
  };

  const handleSaveSupplier = (data: { name: string; phone: string; image?: string }) => {
      let updated: Supplier[];
      if (editingId) {
          updated = suppliers.map(s => s.id === editingId ? { ...s, ...data, image: data.image || s.image } : s);
      } else {
          updated = [...suppliers, { id: Date.now(), name: data.name, phone: data.phone, image: data.image }];
      }
      setSuppliers(updated);
      saveSuppliers(updated);
      closeModal();
  };

  const handleSaveItem = (data: { name: string; supplierId: number; image?: string }) => {
      let updated: Item[];
      if (editingId) {
          updated = items.map(i => i.id === editingId ? { ...i, ...data, image: data.image || i.image } : i);
      } else {
          updated = [...items, { id: Date.now(), name: data.name, supplierId: data.supplierId, image: data.image }];
      }
      setItems(updated);
      saveItems(updated);
      closeModal();
  };

  const handleSaveUser = (data: { name: string; email: string; password: string; role: UserRole }) => {
      const newUser: User = { id: Date.now(), ...data, isActive: true };
      const updated = [...users, newUser];
      setUsers(updated);
      saveUsers(updated);
      closeModal();
  };

  // --- User Management Handlers ---
  const handleDeleteUser = (id: number) => {
      const updated = users.filter(u => u.id !== id);
      setUsers(updated);
      saveUsers(updated);
  };

  const handleToggleUserStatus = (id: number) => {
      const updated = users.map(u => {
          if (u.id === id) return { ...u, isActive: !u.isActive };
          return u;
      });
      setUsers(updated);
      saveUsers(updated);
  };

  // --- Deletion Handlers ---
  const handleDeleteTransaction = (id: number) => {
    const updated = transactions.filter(t => t.id !== id);
    setTransactions(updated);
    saveTransactions(updated);
  };
  const handleDeleteClient = (id: number) => {
    const updated = clients.filter(c => c.id !== id);
    setClients(updated);
    saveClients(updated);
    if (selectedClient && selectedClient.id === id) {
        setCurrentView('clients');
        setSelectedClient(null);
    }
  };
  const handleDeleteSupplier = (id: number) => {
      const updatedSuppliers = suppliers.filter(s => s.id !== id);
      const updatedItems = items.filter(i => i.supplierId !== id); 
      setSuppliers(updatedSuppliers);
      setItems(updatedItems);
      saveSuppliers(updatedSuppliers);
      saveItems(updatedItems);
  };
  const handleDeleteItem = (id: number) => {
      const updated = items.filter(i => i.id !== id);
      setItems(updated);
      saveItems(updated);
  };

  const handleClearData = () => {
    clearAllData();
    refreshData();
  };

  const handleLogout = () => {
      setCurrentUser(null);
      setAuthUser(null);
      setCurrentView('dashboard');
  };

  const handleLoginSuccess = (user: User) => {
      setAuthUser(user);
      refreshData();
  };

  // --- Modal Triggers ---
  const closeModal = () => {
      setIsModalOpen(false);
      setEditingId(null);
      setEditingInitialData(null);
      setTargetClientId(undefined);
      setTargetSupplierId(undefined);
      setTargetName('');
  };

  const openTransactionModal = () => { setModalMode('transaction'); setIsModalOpen(true); };
  const openTradeModal = () => { setModalMode('trade'); setIsModalOpen(true); };
  const openClientModal = () => { setModalMode('add-client'); setIsModalOpen(true); };
  const openSupplierModal = () => { setModalMode('add-supplier'); setIsModalOpen(true); };
  const openAddItemModal = () => { setModalMode('add-item'); setIsModalOpen(true); };
  const openAddUserModal = () => { setModalMode('add-user'); setIsModalOpen(true); };

  const handleClientAction = (clientId: number, clientName: string) => { setTargetClientId(clientId); setTargetName(clientName); setModalMode('client-action'); setIsModalOpen(true); };
  const handleSupplierAction = (supplierId: number, supplierName: string) => { setTargetSupplierId(supplierId); setTargetName(supplierName); setModalMode('supplier-action'); setIsModalOpen(true); };

  const handleEditClient = (client: Client) => { setEditingId(client.id); setEditingInitialData(client); setModalMode('add-client'); setIsModalOpen(true); };
  const handleEditSupplier = (supplier: Supplier) => { setEditingId(supplier.id); setEditingInitialData(supplier); setModalMode('add-supplier'); setIsModalOpen(true); };
  const handleEditTransaction = (trx: Transaction) => { setEditingId(trx.id); setEditingInitialData(trx); setModalMode('transaction'); setIsModalOpen(true); };
  const handleEditItem = (item: Item) => { setEditingId(item.id); setEditingInitialData(item); setModalMode('add-item'); setIsModalOpen(true); };

  const handleViewClientDetails = (client: Client) => { setSelectedClient(client); setCurrentView('client-details'); };
  const handleViewInvoice = (trx: Transaction) => { setSelectedInvoice(trx); setCurrentView('invoice-details'); };

  // === RENDER ===

  if (!currentUser) {
      return <Login onLoginSuccess={handleLoginSuccess} />;
  }

  return (
    <div className="flex min-h-screen bg-slate-50 font-sans">
      <Sidebar 
        currentView={currentView} 
        currentUser={currentUser}
        onChangeView={(view) => {
            setCurrentView(view);
            if (view !== 'client-details') setSelectedClient(null);
            if (view !== 'invoice-details') setSelectedInvoice(null);
        }} 
        onClearData={handleClearData} 
        onOpenSettings={() => setIsSettingsOpen(true)}
        onLogout={handleLogout}
      />

      <main className="flex-1 flex flex-col relative overflow-hidden">
        {/* Header */}
        <header className="h-20 bg-white shadow-sm flex justify-between items-center px-8 z-20 no-print sticky top-0">
          <div>
            <h2 className="text-xl font-bold text-slate-800">
                {currentView === 'dashboard' && 'لوحة التحكم الرئيسية'}
                {currentView === 'clients' && 'إدارة العملاء'}
                {currentView === 'suppliers' && 'الموردين والشركات'}
                {currentView === 'items' && 'المخزن والأصناف'}
                {currentView === 'invoices' && 'سجل الفواتير'}
                {currentView === 'team' && 'إدارة الصلاحيات والمستخدمين'}
                {currentView === 'client-details' && selectedClient && `كشف حساب: ${selectedClient.name}`}
                {currentView === 'invoice-details' && selectedInvoice && `تفاصيل الفاتورة #${selectedInvoice.id.toString().slice(-4)}`}
            </h2>
          </div>

          <div className="flex-1 mx-8 max-w-lg hidden md:block">
            {['dashboard', 'clients', 'suppliers', 'invoices'].includes(currentView) && (
                <div className="relative group">
                <Search className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-blue-500 transition-colors" size={18} />
                <input 
                    type="text" 
                    placeholder="بحث..." 
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="w-full bg-slate-100 border-none rounded-xl py-2.5 pr-10 pl-4 focus:ring-2 focus:ring-blue-500 outline-none transition-all text-sm"
                />
                </div>
            )}
          </div>

          <div className="flex items-center gap-3">
             <button 
                onClick={openTradeModal}
                className="hidden lg:flex items-center gap-2 bg-slate-900 text-white px-4 py-2 rounded-lg hover:bg-slate-700 transition text-sm font-bold shadow-sm"
                title="فاتورة تجارية جديدة (بيع وشراء)"
             >
                <ShoppingCart size={18} />
                <span>فاتورة تجارية</span>
             </button>

             <ShareButton 
                currentView={currentView} 
                stats={stats} 
                counts={{
                    clients: clients.length,
                    suppliers: suppliers.length,
                    items: items.length,
                    transactions: transactions.length
                }}
             />

             <button onClick={handleExportCSV} className="flex items-center gap-2 bg-emerald-600 text-white px-4 py-2 rounded-lg hover:bg-emerald-700 transition text-sm font-bold shadow-sm" title="تصدير إلى CSV">
                <Download size={18} />
                <span className="hidden xl:inline">تصدير CSV</span>
             </button>
             <button onClick={() => window.print()} className="flex items-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition text-sm font-bold shadow-sm">
                <Printer size={18} />
                <span className="hidden xl:inline">طباعة</span>
             </button>
          </div>
        </header>

        {/* Content */}
        <div className="flex-1 overflow-auto p-8 relative">
          <div className="max-w-7xl mx-auto">
            <div className="hidden print-only mb-8 border-b-2 border-slate-800 pb-4">
                <div className="flex justify-between items-center">
                    <div>
                        <h1 className="text-4xl font-extrabold text-black mb-1">المحاسب الذكي</h1>
                        <p className="text-gray-600 font-bold text-lg">مكتب بهاء للتجارة والتوزيع</p>
                    </div>
                    <div className="text-left">
                        <p className="text-gray-500 text-sm">تاريخ التقرير</p>
                        <p className="font-bold text-xl">{new Date().toLocaleDateString('ar-EG', { year: 'numeric', month: 'long', day: 'numeric' })}</p>
                    </div>
                </div>
            </div>

            {currentView === 'dashboard' && <Dashboard stats={stats} transactions={filteredTransactions} onDeleteTransaction={handleDeleteTransaction} onEditTransaction={handleEditTransaction} />}
            {currentView === 'invoices' && <Invoices transactions={filteredTransactions} onDeleteTransaction={handleDeleteTransaction} onEditTransaction={handleEditTransaction} onViewInvoice={handleViewInvoice} searchTerm={searchTerm} onSearchChange={setSearchTerm} />}
            {currentView === 'clients' && <Clients clients={filteredClients} onDeleteClient={handleDeleteClient} onEditClient={handleEditClient} onOpenAddModal={openClientModal} onClientAction={handleClientAction} onViewDetails={handleViewClientDetails} />}
            {currentView === 'suppliers' && <Suppliers suppliers={filteredSuppliers} onDeleteSupplier={handleDeleteSupplier} onEditSupplier={handleEditSupplier} onOpenAddSupplierModal={openSupplierModal} onSupplierAction={handleSupplierAction} />}
            {currentView === 'items' && <Items items={filteredItems} suppliers={suppliers} onDeleteItem={handleDeleteItem} onEditItem={handleEditItem} onOpenAddItemModal={() => openAddItemModal()} />}
            {currentView === 'team' && currentUser.role === 'admin' && <Team users={users} currentUser={currentUser} onDeleteUser={handleDeleteUser} onToggleUserStatus={handleToggleUserStatus} onOpenAddUserModal={openAddUserModal} />}
            {currentView === 'client-details' && selectedClient && <ClientDetails client={selectedClient} transactions={transactions} onBack={() => { setCurrentView('clients'); setSelectedClient(null); }} />}

            {currentView === 'invoice-details' && selectedInvoice && (
                <InvoiceDetails 
                    transaction={selectedInvoice} 
                    client={clients.find(c => c.id === selectedInvoice.clientId)}
                    supplier={suppliers.find(s => s.id === selectedInvoice.supplierId)}
                    onBack={() => { setCurrentView('invoices'); setSelectedInvoice(null); }} 
                />
            )}
          </div>
        </div>

        {/* FAB */}
        {!['client-details', 'invoice-details', 'team'].includes(currentView) && (
            <button
            onClick={() => {
                if (currentView === 'clients') openClientModal();
                else if (currentView === 'suppliers') openSupplierModal();
                else if (currentView === 'items') openAddItemModal();
                else openTransactionModal();
            }}
            className={`fixed bottom-8 left-8 text-white w-14 h-14 rounded-full shadow-2xl flex items-center justify-center transition-transform hover:scale-110 active:scale-95 z-40 no-print ${currentView === 'suppliers' ? 'bg-orange-600 hover:bg-orange-700' : currentView === 'items' ? 'bg-slate-700 hover:bg-slate-800' : 'bg-blue-600 hover:bg-blue-700'}`}
            >
            <Plus size={28} />
            </button>
        )}

        <AddModal 
          isOpen={isModalOpen}
          mode={modalMode}
          targetSupplierId={targetSupplierId}
          targetClientId={targetClientId}
          targetName={targetName}
          suppliers={suppliers}
          clients={clients}
          items={items}
          initialData={editingInitialData}
          onClose={closeModal}
          onSaveTransaction={handleSaveTransaction}
          onSaveTrade={handleSaveTrade}
          onSaveClient={handleSaveClient}
          onSaveSupplier={handleSaveSupplier}
          onSaveItem={handleSaveItem}
          onSaveUser={handleSaveUser}
        />

        <SettingsModal 
            isOpen={isSettingsOpen}
            onClose={() => setIsSettingsOpen(false)}
            onDataRestored={() => {
                refreshData();
                setAuthUser(getCurrentUser()); // Refresh user if overwritten
            }}
        />
      </main>
    </div>
  );
}

export default App;

export type TransactionType = 'income' | 'expense';
export type UserRole = 'admin' | 'accountant';

export interface User {
  id: number;
  name: string;
  email: string;
  password: string; // Stored locally for demo purposes
  role: UserRole;
  image?: string;
  isActive?: boolean; // New field for account status
}

export interface Transaction {
  id: number;
  name: string;
  amount: number;
  type: TransactionType;
  date: string;
  clientId?: number;
  supplierId?: number;
  // New fields for Trade
  itemId?: number;
  quantity?: number;
  unitPrice?: number;
  relatedTransactionId?: number; // To link the purchase and sale

  // New Fields for Driver & Returns
  driverName?: string;
  driverPhone?: string;
  isReturn?: boolean; // True if this transaction is a refund/return
  originalTransactionId?: number; // Links the return to the original invoice
}

export interface Client {
  id: number;
  name: string;
  phone: string;
  image?: string;
}

export interface Supplier {
  id: number;
  name: string;
  phone: string;
  image?: string;
}

export interface Item {
  id: number;
  name: string;
  supplierId: number;
  image?: string;
}

export type ViewState = 'dashboard' | 'clients' | 'suppliers' | 'items' | 'invoices' | 'client-details' | 'invoice-details' | 'team';

export interface Stats {
  income: number;
  expense: number;
  balance: number;
}

export type ModalMode = 'transaction' | 'trade' | 'add-client' | 'add-supplier' | 'add-item' | 'client-action' | 'supplier-action' | 'add-user' | 'add-return';

import React, { useState, useEffect, useRef } from 'react';
import { X, Check, Upload, Image as ImageIcon, FileText, Banknote, ArrowRightLeft, ShoppingCart, Calculator, UserPlus, Lock, Truck, RefreshCw } from 'lucide-react';
import { TransactionType, ModalMode, Supplier, Client, Item, UserRole } from '../types';

interface AddModalProps {
  isOpen: boolean;
  mode: ModalMode;
  targetSupplierId?: number;
  targetClientId?: number;
  targetName?: string;
  suppliers?: Supplier[];
  clients?: Client[];
  items?: Item[];
  initialData?: any;
  onClose: () => void;
  onSaveTransaction: (data: { name: string; amount: number; type: TransactionType; clientId?: number; supplierId?: number; driverName?: string; driverPhone?: string }) => void;
  onSaveTrade: (data: { 
      clientId: number; 
      supplierId: number; 
      itemId: number; 
      itemName: string;
      quantity: number; 
      buyPrice: number; 
      sellPrice: number;
      driverName?: string;
      driverPhone?: string; 
  }) => void;
  onSaveClient: (data: { name: string; phone: string; image?: string }) => void;
  onSaveSupplier: (data: { name: string; phone: string; image?: string }) => void;
  onSaveItem: (data: { name: string; supplierId: number; image?: string }) => void;
  onSaveUser?: (data: { name: string; email: string; password: string; role: UserRole }) => void;
  onSaveReturn?: (data: { quantity: number; amount: number; notes: string }) => void; // New handler for returns
}

const AddModal: React.FC<AddModalProps> = ({ 
    isOpen, 
    mode, 
    targetSupplierId, 
    targetClientId,
    targetName,
    suppliers = [],
    clients = [],
    items = [],
    initialData,
    onClose, 
    onSaveTransaction, 
    onSaveTrade,
    onSaveClient, 
    onSaveSupplier, 
    onSaveItem,
    onSaveUser,
    onSaveReturn
}) => {

  // Transaction State
  const [trxName, setTrxName] = useState('');
  const [trxAmount, setTrxAmount] = useState('');
  const [trxType, setTrxType] = useState<TransactionType>('income');
  const [trxSubType, setTrxSubType] = useState<string>('');

  // Driver State
  const [driverName, setDriverName] = useState('');
  const [driverPhone, setDriverPhone] = useState('');

  // Generic Selection State
  const [selectedClientId, setSelectedClientId] = useState<number | undefined>(undefined);
  const [selectedTxSupplierId, setSelectedTxSupplierId] = useState<number | undefined>(undefined);

  // Trade Specific State
  const [tradeClientId, setTradeClientId] = useState<number | undefined>(undefined);
  const [tradeSupplierId, setTradeSupplierId] = useState<number | undefined>(undefined);
  const [tradeItemId, setTradeItemId] = useState<number | undefined>(undefined);
  const [tradeQuantity, setTradeQuantity] = useState<string>('');
  const [tradeBuyPrice, setTradeBuyPrice] = useState<string>('');
  const [tradeSellPrice, setTradeSellPrice] = useState<string>('');

  // Return Specific State
  const [returnQty, setReturnQty] = useState('');
  const [returnPrice, setReturnPrice] = useState('');
  const [returnNotes, setReturnNotes] = useState('');

  // Entity Creation State
  const [entityName, setEntityName] = useState('');
  const [entityPhone, setEntityPhone] = useState('');

  // Item Creation State
  const [itemName, setItemName] = useState('');
  const [selectedSupplierId, setSelectedSupplierId] = useState<number | undefined>(undefined);

  // User Creation State
  const [userEmail, setUserEmail] = useState('');
  const [userPassword, setUserPassword] = useState('');
  const [userRole, setUserRole] = useState<UserRole>('accountant');

  // Image State
  const [selectedImage, setSelectedImage] = useState<string | undefined>(undefined);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedImage(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  useEffect(() => {
    if (isOpen) {
      if (initialData && mode !== 'add-return') {
          // Pre-fill logic...
          if (mode === 'add-client' || mode === 'add-supplier') {
            setEntityName(initialData.name);
            setEntityPhone(initialData.phone);
            setSelectedImage(initialData.image);
          } else if (mode === 'transaction') {
            setTrxName(initialData.name);
            setTrxAmount(initialData.amount.toString());
            setTrxType(initialData.type);
            setSelectedClientId(initialData.clientId);
            setSelectedTxSupplierId(initialData.supplierId);
            setDriverName(initialData.driverName || '');
            setDriverPhone(initialData.driverPhone || '');
          } else if (mode === 'add-item') {
            setItemName(initialData.name);
            setSelectedSupplierId(initialData.supplierId);
            setSelectedImage(initialData.image);
          }
      } else if (mode === 'add-return' && initialData) {
          // Setup return defaults based on original transaction
          setReturnQty('1');
          setReturnPrice(initialData.unitPrice ? initialData.unitPrice.toString() : initialData.amount.toString());
          setReturnNotes(`مرتجع من: ${initialData.name}`);
      } else {
          // Reset Forms
          setTrxName('');
          setTrxAmount('');
          setEntityName('');
          setEntityPhone('');
          setItemName('');
          setDriverName('');
          setDriverPhone('');
          setSelectedImage(undefined);

          setSelectedSupplierId(targetSupplierId);
          setSelectedClientId(undefined);
          setSelectedTxSupplierId(undefined);

          setTradeClientId(undefined);
          setTradeSupplierId(undefined);
          setTradeItemId(undefined);
          setTradeQuantity('');
          setTradeBuyPrice('');
          setTradeSellPrice('');

          // Reset User Form
          setUserEmail('');
          setUserPassword('');
          setUserRole('accountant');

          if (mode === 'client-action') {
              setTrxType('income');
              setTrxSubType('sales_invoice');
          } else if (mode === 'supplier-action') {
              setTrxType('expense');
              setTrxSubType('purchase_invoice');
          } else {
              setTrxType('income');
              setTrxSubType('');
          }
      }
    }
  }, [isOpen, mode, initialData, targetSupplierId]);

  // Update name based on sub-type
  useEffect(() => {
    if (!initialData) {
        if (mode === 'client-action' && targetName) {
            if (trxSubType === 'sales_invoice') setTrxName(`فاتورة بيع - ${targetName}`);
            else if (trxSubType === 'receipt') setTrxName(`سند قبض من ${targetName}`);
            else if (trxSubType === 'refund') setTrxName(`مرتجع نقدي لـ ${targetName}`);
        } else if (mode === 'supplier-action' && targetName) {
            if (trxSubType === 'purchase_invoice') setTrxName(`فاتورة شراء - ${targetName}`);
            else if (trxSubType === 'payment') setTrxName(`سند دفع لـ ${targetName}`);
            else if (trxSubType === 'refund') setTrxName(`مرتجع نقدي من ${targetName}`);
        }
    }
  }, [trxSubType, mode, targetName, initialData]);

  const filteredTradeItems = items.filter(i => !tradeSupplierId || i.supplierId === tradeSupplierId);

  if (!isOpen) return null;

  const getTitle = () => {
      if (initialData && mode !== 'add-return') return 'تعديل البيانات';
      switch(mode) {
          case 'transaction': return 'إضافة عملية مالية سريعة';
          case 'trade': return 'فاتورة تجارية (شراء وبيع)';
          case 'client-action': return `تسجيل عملية لـ ${targetName}`;
          case 'supplier-action': return `تسجيل عملية لـ ${targetName}`;
          case 'add-client': return 'إضافة عميل جديد';
          case 'add-supplier': return 'إضافة مورد جديد';
          case 'add-item': return 'إضافة صنف جديد';
          case 'add-user': return 'إضافة مستخدم جديد للنظام';
          case 'add-return': return 'تسجيل مرتجع على الفاتورة';
      }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (mode === 'add-return' && onSaveReturn) {
        if (!returnQty || !returnPrice) return;
        onSaveReturn({
            quantity: parseFloat(returnQty),
            amount: parseFloat(returnPrice), // Price per unit
            notes: returnNotes
        });
    }
    else if (mode === 'add-user' && onSaveUser) {
        if (!entityName || !userEmail || !userPassword) {
            alert("يرجى ملء جميع بيانات المستخدم");
            return;
        }
        onSaveUser({
            name: entityName,
            email: userEmail,
            password: userPassword,
            role: userRole
        });
    }
    else if (mode === 'trade') {
        if (!tradeClientId || !tradeSupplierId || !tradeItemId || !tradeQuantity || !tradeBuyPrice || !tradeSellPrice) {
            alert("يرجى إكمال جميع حقول الفاتورة التجارية");
            return;
        }
        const selectedItem = items.find(i => i.id === tradeItemId);
        onSaveTrade({
            clientId: tradeClientId,
            supplierId: tradeSupplierId,
            itemId: tradeItemId,
            itemName: selectedItem ? selectedItem.name : 'Unknown',
            quantity: parseFloat(tradeQuantity),
            buyPrice: parseFloat(tradeBuyPrice),
            sellPrice: parseFloat(tradeSellPrice),
            driverName: driverName,
            driverPhone: driverPhone
        });
    }
    else if (mode === 'transaction' || mode === 'client-action' || mode === 'supplier-action') {
      if (!trxName || !trxAmount) return;

      let finalClientId = targetClientId;
      let finalSupplierId = targetSupplierId;

      if (mode === 'transaction') {
          if (trxType === 'income') finalClientId = selectedClientId;
          if (trxType === 'expense') finalSupplierId = selectedTxSupplierId;
      }

      onSaveTransaction({ 
          name: trxName, 
          amount: parseFloat(trxAmount), 
          type: trxType,
          clientId: finalClientId,
          supplierId: finalSupplierId,
          driverName: driverName,
          driverPhone: driverPhone
      });
    } 
    else if (mode === 'add-client') {
      if (!entityName) return;
      onSaveClient({ name: entityName, phone: entityPhone, image: selectedImage });
    }
    else if (mode === 'add-supplier') {
        if (!entityName) return;
        onSaveSupplier({ name: entityName, phone: entityPhone, image: selectedImage });
    }
    else if (mode === 'add-item') {
        const finalSupplierId = targetSupplierId || selectedSupplierId;
        if (!itemName || !finalSupplierId) {
            alert('يرجى كتابة اسم الصنف واختيار المورد');
            return;
        }
        onSaveItem({ name: itemName, supplierId: finalSupplierId, image: selectedImage });
    }
  };

  const renderNormalTransactionTypes = () => (
    <div className="grid grid-cols-2 gap-4">
      <button
        type="button"
        onClick={() => { setTrxType('income'); setSelectedTxSupplierId(undefined); }}
        className={`p-3 rounded-xl border-2 flex flex-col items-center justify-center gap-1 transition-all ${
          trxType === 'income' 
            ? 'border-emerald-500 bg-emerald-50 text-emerald-700' 
            : 'border-slate-100 hover:border-slate-300 text-slate-500'
        }`}
      >
        <span className="font-bold text-sm">قبض / فاتورة بيع 💵</span>
      </button>
      <button
        type="button"
        onClick={() => { setTrxType('expense'); setSelectedClientId(undefined); }}
        className={`p-3 rounded-xl border-2 flex flex-col items-center justify-center gap-1 transition-all ${
          trxType === 'expense' 
            ? 'border-red-500 bg-red-50 text-red-700' 
            : 'border-slate-100 hover:border-slate-300 text-slate-500'
        }`}
      >
        <span className="font-bold text-sm">صرف / شراء 💸</span>
      </button>
    </div>
  );

  const renderDriverFields = () => (
      <div className="bg-slate-50 p-3 rounded-xl border border-slate-200 mt-2">
          <div className="flex items-center gap-2 mb-2 text-slate-600 font-bold text-xs">
              <Truck size={14} />
              بيانات السائق / المندوب (اختياري)
          </div>
          <div className="grid grid-cols-2 gap-3">
              <div>
                  <input type="text" value={driverName} onChange={(e) => setDriverName(e.target.value)} className="w-full border border-slate-200 rounded-lg px-3 py-2 text-sm focus:outline-none focus:border-blue-400" placeholder="اسم السائق" />
              </div>
              <div>
                  <input type="text" value={driverPhone} onChange={(e) => setDriverPhone(e.target.value)} className="w-full border border-slate-200 rounded-lg px-3 py-2 text-sm focus:outline-none focus:border-blue-400" placeholder="رقم الهاتف" />
              </div>
          </div>
      </div>
  );

  return (
    <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex items-center justify-center p-4 fade-in no-print">
      <div className="bg-white rounded-2xl w-full max-w-md shadow-2xl overflow-hidden transform transition-all scale-100 max-h-[90vh] overflow-y-auto">
        <div className="bg-slate-50 px-6 py-4 border-b border-slate-100 flex justify-between items-center sticky top-0 z-10">
          <h3 className="font-bold text-lg text-slate-800">{getTitle()}</h3>
          <button onClick={onClose} className="text-slate-400 hover:text-red-500 transition-colors">
            <X size={24} />
          </button>
        </div>

        <div className="p-6">
          <form onSubmit={handleSubmit} className="space-y-4">

            {(mode === 'add-client' || mode === 'add-supplier' || mode === 'add-item') && (
                <div className="flex justify-center mb-4">
                    <div 
                        onClick={() => fileInputRef.current?.click()}
                        className="w-24 h-24 rounded-full border-2 border-dashed border-slate-300 flex items-center justify-center cursor-pointer hover:border-blue-500 hover:bg-blue-50 transition-colors overflow-hidden relative group"
                    >
                        {selectedImage ? (
                            <img src={selectedImage} alt="Preview" className="w-full h-full object-cover" />
                        ) : (
                            <div className="text-center text-slate-400">
                                <Upload size={24} className="mx-auto mb-1" />
                                <span className="text-[10px]">صورة</span>
                            </div>
                        )}
                        <input type="file" ref={fileInputRef} onChange={handleImageChange} accept="image/*" className="hidden" />
                    </div>
                </div>
            )}

            {/* === RETURN MODE === */}
            {mode === 'add-return' && (
                <div className="space-y-4">
                    <div className="bg-red-50 p-3 rounded-lg text-xs text-red-800 mb-2 flex items-center gap-2">
                        <RefreshCw size={16} />
                         سيتم خصم قيمة المرتجع من رصيد العميل/المورد تلقائياً
                    </div>
                    <div>
                        <label className="block text-sm font-semibold text-slate-700 mb-1">اسم الصنف / البيان</label>
                        <input type="text" value={returnNotes} onChange={(e) => setReturnNotes(e.target.value)} className="w-full border border-slate-200 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-red-500 outline-none" required />
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                        <div>
                            <label className="block text-sm font-semibold text-slate-700 mb-1">الكمية المرتجعة</label>
                            <input type="number" value={returnQty} onChange={(e) => setReturnQty(e.target.value)} className="w-full border border-slate-200 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-red-500 outline-none font-bold text-center" min="1" required />
                        </div>
                        <div>
                             <label className="block text-sm font-semibold text-slate-700 mb-1">سعر الوحدة</label>
                            <input type="number" value={returnPrice} onChange={(e) => setReturnPrice(e.target.value)} className="w-full border border-slate-200 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-red-500 outline-none font-bold text-center" min="0" step="0.01" required />
                        </div>
                    </div>
                    <div className="bg-slate-100 p-3 rounded-lg flex justify-between items-center font-bold">
                        <span>إجمالي الخصم:</span>
                        <span className="text-red-600">{(parseFloat(returnQty || '0') * parseFloat(returnPrice || '0')).toLocaleString()} ج.م</span>
                    </div>
                </div>
            )}

            {/* === USER MODE === */}
            {mode === 'add-user' && (
                <div className="space-y-4">
                     <div className="bg-purple-50 p-3 rounded-lg text-xs text-purple-800 mb-2 flex items-center gap-2">
                        <UserPlus size={16} />
                        إضافة عضو جديد يمكنه الدخول للنظام (من نفس الجهاز)
                    </div>
                    <div>
                        <label className="block text-sm font-semibold text-slate-700 mb-1">الاسم</label>
                        <input type="text" value={entityName} onChange={(e) => setEntityName(e.target.value)} className="w-full border border-slate-200 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-purple-500 outline-none" placeholder="مثال: أحمد المحاسب" required />
                    </div>
                    <div>
                        <label className="block text-sm font-semibold text-slate-700 mb-1">البريد الإلكتروني (للدخول)</label>
                        <input type="email" value={userEmail} onChange={(e) => setUserEmail(e.target.value)} className="w-full border border-slate-200 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-purple-500 outline-none" placeholder="user@gmail.com" required />
                    </div>
                    <div>
                        <label className="block text-sm font-semibold text-slate-700 mb-1">كلمة المرور</label>
                        <div className="relative">
                            <Lock className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                            <input type="text" value={userPassword} onChange={(e) => setUserPassword(e.target.value)} className="w-full border border-slate-200 rounded-lg py-2.5 pr-10 pl-4 focus:ring-2 focus:ring-purple-500 outline-none" placeholder="123456" required />
                        </div>
                    </div>
                    <div>
                        <label className="block text-sm font-semibold text-slate-700 mb-1">الصلاحية</label>
                        <div className="flex gap-4">
                             <label className="flex items-center gap-2 cursor-pointer p-3 border rounded-lg flex-1 hover:bg-slate-50">
                                <input type="radio" name="role" value="accountant" checked={userRole === 'accountant'} onChange={() => setUserRole('accountant')} className="w-4 h-4 text-purple-600" />
                                <div>
                                    <span className="block font-bold text-sm">محاسب</span>
                                    <span className="text-xs text-slate-500">صلاحيات محدودة</span>
                                </div>
                            </label>
                            <label className="flex items-center gap-2 cursor-pointer p-3 border rounded-lg flex-1 hover:bg-slate-50">
                                <input type="radio" name="role" value="admin" checked={userRole === 'admin'} onChange={() => setUserRole('admin')} className="w-4 h-4 text-purple-600" />
                                <div>
                                    <span className="block font-bold text-sm">مدير</span>
                                    <span className="text-xs text-slate-500">تحكم كامل</span>
                                </div>
                            </label>
                        </div>
                    </div>
                </div>
            )}

            {/* === TRADE MODE === */}
            {mode === 'trade' && (
                <div className="space-y-4">
                     {/* Trade inputs ... same as before */}
                     <div className="bg-blue-50 p-3 rounded-lg text-xs text-blue-800 mb-2">
                        هذه الفاتورة تقوم بإنشاء عملية توريد من المورد (دين عليك) وعملية بيع للعميل (دين لك) في آن واحد.
                    </div>
                    <div className="grid grid-cols-2 gap-3">
                        <div>
                            <label className="block text-xs font-bold text-slate-700 mb-1">المورد</label>
                            <select value={tradeSupplierId || ''} onChange={(e) => setTradeSupplierId(Number(e.target.value))} className="w-full border border-slate-300 rounded-lg p-2 text-sm focus:ring-2 focus:ring-blue-500 outline-none" required>
                                <option value="">اختر المورد...</option>
                                {suppliers.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                            </select>
                        </div>
                        <div>
                            <label className="block text-xs font-bold text-slate-700 mb-1">العميل</label>
                            <select value={tradeClientId || ''} onChange={(e) => setTradeClientId(Number(e.target.value))} className="w-full border border-slate-300 rounded-lg p-2 text-sm focus:ring-2 focus:ring-blue-500 outline-none" required>
                                <option value="">اختر العميل...</option>
                                {clients.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                            </select>
                        </div>
                    </div>
                    <div>
                        <label className="block text-xs font-bold text-slate-700 mb-1">الصنف</label>
                        <select value={tradeItemId || ''} onChange={(e) => setTradeItemId(Number(e.target.value))} className="w-full border border-slate-300 rounded-lg p-2 text-sm focus:ring-2 focus:ring-blue-500 outline-none" required>
                            <option value="">{tradeSupplierId ? 'اختر الصنف من هذا المورد...' : 'اختر المورد أولاً...'}</option>
                            {filteredTradeItems.map(i => <option key={i.id} value={i.id}>{i.name}</option>)}
                        </select>
                    </div>
                    <div>
                         <label className="block text-xs font-bold text-slate-700 mb-1">العدد / الكمية</label>
                         <input type="number" value={tradeQuantity} onChange={e => setTradeQuantity(e.target.value)} className="w-full border border-slate-300 rounded-lg p-2 text-center font-bold" placeholder="0" required />
                    </div>
                    <div className="grid grid-cols-2 gap-3 bg-slate-50 p-3 rounded-xl border border-slate-200">
                        <div>
                            <label className="block text-xs font-bold text-red-600 mb-1">سعر الشراء</label>
                            <input type="number" value={tradeBuyPrice} onChange={e => setTradeBuyPrice(e.target.value)} className="w-full border border-red-200 rounded-lg p-2 text-sm text-center focus:ring-red-500 outline-none" placeholder="0.00" step="0.01" required />
                        </div>
                        <div>
                            <label className="block text-xs font-bold text-emerald-600 mb-1">سعر البيع</label>
                            <input type="number" value={tradeSellPrice} onChange={e => setTradeSellPrice(e.target.value)} className="w-full border border-emerald-200 rounded-lg p-2 text-sm text-center focus:ring-emerald-500 outline-none" placeholder="0.00" step="0.01" required />
                        </div>
                    </div>
                    {renderDriverFields()}
                </div>
            )}

            {/* Normal Modes */}
            {(mode === 'transaction' || mode === 'client-action' || mode === 'supplier-action') && (
              <>
                {mode === 'transaction' && renderNormalTransactionTypes()}

                {mode === 'transaction' && trxType === 'income' && (
                    <div className="bg-blue-50 p-3 rounded-lg border border-blue-100">
                        <label className="block text-xs font-bold text-blue-800 mb-1">تحديد العميل</label>
                        <select value={selectedClientId || ''} onChange={(e) => setSelectedClientId(Number(e.target.value))} className="w-full border border-blue-200 rounded-md p-2 text-sm bg-white focus:outline-none">
                            <option value="">-- عميل عام / نقدي --</option>
                            {clients.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                        </select>
                    </div>
                )}
                {mode === 'transaction' && trxType === 'expense' && (
                    <div className="bg-orange-50 p-3 rounded-lg border border-orange-100">
                         <label className="block text-xs font-bold text-orange-800 mb-1">تحديد المورد</label>
                        <select value={selectedTxSupplierId || ''} onChange={(e) => setSelectedTxSupplierId(Number(e.target.value))} className="w-full border border-orange-200 rounded-md p-2 text-sm bg-white focus:outline-none">
                            <option value="">-- مورد عام / مصروفات --</option>
                            {suppliers.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                        </select>
                    </div>
                )}

                {(mode === 'transaction' || mode === 'client-action' || mode === 'supplier-action') && (
                  <>
                    <div>
                    <label className="block text-sm font-semibold text-slate-700 mb-1">البيان</label>
                    <input type="text" value={trxName} onChange={(e) => setTrxName(e.target.value)} className="w-full border border-slate-200 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-blue-500 focus:outline-none" placeholder="وصف العملية..." required />
                    </div>
                    <div>
                    <label className="block text-sm font-semibold text-slate-700 mb-1">المبلغ (ج.م)</label>
                    <input type="number" value={trxAmount} onChange={(e) => setTrxAmount(e.target.value)} className="w-full border border-slate-200 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-blue-500 focus:outline-none font-bold text-lg" placeholder="0.00" min="0" step="0.01" required />
                    </div>
                    {renderDriverFields()}
                  </>
                )}
              </>
            )}

            {/* Add Entity Modes */}
            {(mode === 'add-client' || mode === 'add-supplier') && (
              <>
                <div className="bg-blue-50 text-blue-800 p-3 rounded-lg text-sm mb-2 font-medium">
                    {mode === 'add-client' ? (initialData ? 'تعديل بيانات العميل' : 'بيانات العميل الجديد') : (initialData ? 'تعديل بيانات المورد' : 'بيانات المورد / الشركة')}
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">الاسم بالكامل</label>
                  <input type="text" value={entityName} onChange={(e) => setEntityName(e.target.value)} className="w-full border border-slate-200 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-blue-500 focus:outline-none" required />
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">رقم الهاتف</label>
                  <input type="tel" value={entityPhone} onChange={(e) => setEntityPhone(e.target.value)} className="w-full border border-slate-200 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-blue-500 focus:outline-none" />
                </div>
              </>
            )}

            {/* Add Item Mode */}
            {mode === 'add-item' && (
                <>
                 <div className="bg-orange-50 text-orange-800 p-3 rounded-lg text-sm mb-2 font-medium">إضافة صنف جديد للمخزن</div>
                 <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">اسم الصنف / المنتج</label>
                  <input type="text" value={itemName} onChange={(e) => setItemName(e.target.value)} className="w-full border border-slate-200 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-blue-500 focus:outline-none" required />
                </div>
                {!targetSupplierId && (
                    <div>
                        <label className="block text-sm font-semibold text-slate-700 mb-1">المورد / الشركة المنتجة</label>
                        <select value={selectedSupplierId || ''} onChange={(e) => setSelectedSupplierId(Number(e.target.value))} className="w-full border border-slate-200 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-blue-500 focus:outline-none bg-white" required>
                            <option value="">اختر المورد...</option>
                            {suppliers.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                        </select>
                    </div>
                )}
                </>
            )}

            <div className="pt-4 flex gap-3">
              <button type="button" onClick={onClose} className="flex-1 py-3 text-slate-600 bg-slate-100 hover:bg-slate-200 rounded-xl font-bold transition-colors">إلغاء</button>
              <button type="submit" className="flex-[2] py-3 text-white bg-blue-600 hover:bg-blue-700 rounded-xl font-bold transition-colors shadow-lg shadow-blue-200 flex items-center justify-center gap-2">
                <Check size={20} />
                {initialData && mode !== 'add-return' ? 'حفظ التعديلات' : 'حفظ البيانات'}
              </button>
            </div>
          </form>
        </div>
      </div>
    </div>
  );
};

export default AddModal;

import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import Clients from './components/Clients';
import Suppliers from './components/Suppliers';
import Items from './components/Items';
import Invoices from './components/Invoices';
import Team from './components/Team'; 
import AddModal from './components/AddModal';
import ShareButton from './components/ShareButton';
import ClientDetails from './components/ClientDetails';
import InvoiceDetails from './components/InvoiceDetails';
import SettingsModal from './components/SettingsModal';
import Login from './components/Login'; 
import { ViewState, Transaction, Client, Supplier, Item, Stats, TransactionType, ModalMode, User, UserRole } from './types';
import { 
    loadTransactions, saveTransactions, 
    loadClients, saveClients, 
    loadSuppliers, saveSuppliers, 
    loadItems, saveItems, 
    loadUsers, saveUsers, getCurrentUser, setCurrentUser, 
    clearAllData 
} from './services/storage';
import { Plus, Printer, Bell, Search, Download, ShoppingCart } from 'lucide-react';

function App() {
  // Auth State
  const [currentUser, setAuthUser] = useState<User | null>(null);

  const [currentView, setCurrentView] = useState<ViewState>('dashboard');

  // Data State
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [clients, setClients] = useState<Client[]>([]);
  const [suppliers, setSuppliers] = useState<Supplier[]>([]);
  const [items, setItems] = useState<Item[]>([]);
  const [users, setUsers] = useState<User[]>([]); 

  // Selected Details State
  const [selectedClient, setSelectedClient] = useState<Client | null>(null);
  const [selectedInvoice, setSelectedInvoice] = useState<Transaction | null>(null);

  // Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);

  const [modalMode, setModalMode] = useState<ModalMode>('transaction');
  const [targetSupplierId, setTargetSupplierId] = useState<number | undefined>(undefined);
  const [targetClientId, setTargetClientId] = useState<number | undefined>(undefined);
  const [targetName, setTargetName] = useState<string>('');

  // Editing State
  const [editingId, setEditingId] = useState<number | null>(null);
  const [editingInitialData, setEditingInitialData] = useState<any>(null);

  // Return Transaction State (The invoice being returned)
  const [returnTargetTransaction, setReturnTargetTransaction] = useState<Transaction | null>(null);

  // Search State
  const [searchTerm, setSearchTerm] = useState('');

  // Load data
  const refreshData = () => {
    setTransactions(loadTransactions());
    setClients(loadClients());
    setSuppliers(loadSuppliers());
    setItems(loadItems());
    setUsers(loadUsers());
  };

  useEffect(() => {
    const sessionUser = getCurrentUser();
    if (sessionUser) {
        setAuthUser(sessionUser);
        refreshData();
    }
  }, []);

  // Calculate Stats
  const stats: Stats = useMemo(() => {
    let income = 0;
    let expense = 0;
    transactions.forEach(t => {
      if (t.type === 'income') income += t.amount;
      else expense += t.amount;
    });
    return { income, expense, balance: income - expense };
  }, [transactions]);

  // Filter Logic
  const filteredTransactions = useMemo(() => {
    if (!searchTerm) return transactions;
    return transactions.filter(t => 
      t.name.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [transactions, searchTerm]);

  const filteredClients = useMemo(() => {
    if (!searchTerm) return clients;
    return clients.filter(c => 
      c.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      c.phone.includes(searchTerm)
    );
  }, [clients, searchTerm]);

  const filteredSuppliers = useMemo(() => {
    if (!searchTerm) return suppliers;
    return suppliers.filter(s => {
        const nameMatch = s.name.toLowerCase().includes(searchTerm.toLowerCase());
        const phoneMatch = s.phone.includes(searchTerm);
        return nameMatch || phoneMatch;
    });
  }, [suppliers, searchTerm]);

  const filteredItems = useMemo(() => {
    if (!searchTerm) return items;
    return items.filter(i => {
        const itemMatch = i.name.toLowerCase().includes(searchTerm.toLowerCase());
        const supplierMatch = suppliers.find(s => s.id === i.supplierId)?.name.toLowerCase().includes(searchTerm.toLowerCase());
        return itemMatch || supplierMatch;
    });
  }, [items, suppliers, searchTerm]);

  // CSV Export Logic
  const handleExportCSV = () => {
    let csvContent = "data:text/csv;charset=utf-8,\uFEFF"; 
    let filename = "export.csv";

    if (currentView === 'clients') {
      csvContent += "ID,Name,Phone\n";
      filteredClients.forEach(c => { csvContent += `${c.id},"${c.name}","${c.phone}"\n`; });
      filename = "clients.csv";
    } else if (currentView === 'suppliers') {
      csvContent += "ID,Name,Phone\n";
      filteredSuppliers.forEach(s => { csvContent += `${s.id},"${s.name}","${s.phone}"\n`; });
      filename = "suppliers.csv";
    } else {
      csvContent += "ID,Date,Description,Type,Amount\n";
      filteredTransactions.forEach(t => {
         const typeAr = t.type === 'income' ? 'قبض' : 'صرف';
         csvContent += `${t.id},${t.date},"${t.name}",${typeAr},${t.amount}\n`;
      });
      filename = "transactions.csv";
    }

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", filename);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // --- Handlers ---

  const handleSaveTransaction = (data: { name: string; amount: number; type: TransactionType; clientId?: number; supplierId?: number; driverName?: string; driverPhone?: string }) => {
    if (editingId) {
        const updated = transactions.map(t => t.id === editingId ? { ...t, ...data } : t);
        setTransactions(updated);
        saveTransactions(updated);
    } else {
        const newTrx: Transaction = {
          id: Date.now(),
          name: data.name,
          amount: data.amount,
          type: data.type,
          date: new Date().toLocaleDateString('ar-EG'),
          clientId: data.clientId,
          supplierId: data.supplierId,
          driverName: data.driverName,
          driverPhone: data.driverPhone
        };
        const updated = [...transactions, newTrx];
        setTransactions(updated);
        saveTransactions(updated);
    }
    closeModal();
  };

  const handleSaveTrade = (data: { 
      clientId: number; 
      supplierId: number; 
      itemId: number; 
      itemName: string; 
      quantity: number; 
      buyPrice: number; 
      sellPrice: number;
      driverName?: string;
      driverPhone?: string; 
  }) => {
      const now = Date.now();
      const dateStr = new Date().toLocaleDateString('ar-EG');
      const purchaseTrx: Transaction = { 
          id: now, 
          name: `توريد: ${data.itemName} (عدد ${data.quantity})`, 
          amount: data.quantity * data.buyPrice, 
          type: 'expense', 
          date: dateStr, 
          supplierId: data.supplierId, 
          itemId: data.itemId, 
          quantity: data.quantity, 
          unitPrice: data.buyPrice 
      };

      const saleTrx: Transaction = { 
          id: now + 1, 
          name: `بيع: ${data.itemName} (عدد ${data.quantity})`, 
          amount: data.quantity * data.sellPrice, 
          type: 'income', 
          date: dateStr, 
          clientId: data.clientId, 
          itemId: data.itemId, 
          quantity: data.quantity, 
          unitPrice: data.sellPrice, 
          relatedTransactionId: now,
          driverName: data.driverName,
          driverPhone: data.driverPhone
      };

      const updated = [...transactions, purchaseTrx, saleTrx];
      setTransactions(updated);
      saveTransactions(updated);
      closeModal();
  };

  const handleSaveReturn = (data: { quantity: number; amount: number; notes: string }) => {
      if (!returnTargetTransaction) return;

      const totalReturnAmount = data.quantity * data.amount;
      // Invert type: If original was Income (Sale), return is Expense.
      const returnType: TransactionType = returnTargetTransaction.type === 'income' ? 'expense' : 'income';

      const returnTrx: Transaction = {
          id: Date.now(),
          name: data.notes,
          amount: totalReturnAmount,
          type: returnType,
          date: new Date().toLocaleDateString('ar-EG'),
          clientId: returnTargetTransaction.clientId,
          supplierId: returnTargetTransaction.supplierId,
          itemId: returnTargetTransaction.itemId,
          quantity: data.quantity,
          unitPrice: data.amount,
          isReturn: true,
          originalTransactionId: returnTargetTransaction.id
      };

      const updated = [...transactions, returnTrx];
      setTransactions(updated);
      saveTransactions(updated);
      closeModal();
  };

  const handleSaveClient = (data: { name: string; phone: string; image?: string }) => {
    let updated: Client[];
    if (editingId) {
        updated = clients.map(c => c.id === editingId ? { ...c, ...data, image: data.image || c.image } : c);
    } else {
        updated = [...clients, { id: Date.now(), name: data.name, phone: data.phone, image: data.image }];
    }
    setClients(updated);
    saveClients(updated);
    closeModal();
  };

  const handleSaveSupplier = (data: { name: string; phone: string; image?: string }) => {
      let updated: Supplier[];
      if (editingId) {
          updated = suppliers.map(s => s.id === editingId ? { ...s, ...data, image: data.image || s.image } : s);
      } else {
          updated = [...suppliers, { id: Date.now(), name: data.name, phone: data.phone, image: data.image }];
      }
      setSuppliers(updated);
      saveSuppliers(updated);
      closeModal();
  };

  const handleSaveItem = (data: { name: string; supplierId: number; image?: string }) => {
      let updated: Item[];
      if (editingId) {
          updated = items.map(i => i.id === editingId ? { ...i, ...data, image: data.image || i.image } : i);
      } else {
          updated = [...items, { id: Date.now(), name: data.name, supplierId: data.supplierId, image: data.image }];
      }
      setItems(updated);
      saveItems(updated);
      closeModal();
  };

  const handleSaveUser = (data: { name: string; email: string; password: string; role: UserRole }) => {
      const newUser: User = { id: Date.now(), ...data, isActive: true };
      const updated = [...users, newUser];
      setUsers(updated);
      saveUsers(updated);
      closeModal();
  };

  // --- User Management Handlers ---
  const handleDeleteUser = (id: number) => {
      const updated = users.filter(u => u.id !== id);
      setUsers(updated);
      saveUsers(updated);
  };

  const handleToggleUserStatus = (id: number) => {
      const updated = users.map(u => {
          if (u.id === id) return { ...u, isActive: !u.isActive };
          return u;
      });
      setUsers(updated);
      saveUsers(updated);
  };

  // --- Deletion Handlers ---
  const handleDeleteTransaction = (id: number) => {
    const updated = transactions.filter(t => t.id !== id && t.originalTransactionId !== id); // Also delete linked returns if any (optional)
    setTransactions(updated);
    saveTransactions(updated);
  };
  const handleDeleteClient = (id: number) => {
    const updated = clients.filter(c => c.id !== id);
    setClients(updated);
    saveClients(updated);
    if (selectedClient && selectedClient.id === id) {
        setCurrentView('clients');
        setSelectedClient(null);
    }
  };
  const handleDeleteSupplier = (id: number) => {
      const updatedSuppliers = suppliers.filter(s => s.id !== id);
      const updatedItems = items.filter(i => i.supplierId !== id); 
      setSuppliers(updatedSuppliers);
      setItems(updatedItems);
      saveSuppliers(updatedSuppliers);
      saveItems(updatedItems);
  };
  const handleDeleteItem = (id: number) => {
      const updated = items.filter(i => i.id !== id);
      setItems(updated);
      saveItems(updated);
  };

  const handleClearData = () => {
    clearAllData();
    refreshData();
  };

  const handleLogout = () => {
      setCurrentUser(null);
      setAuthUser(null);
      setCurrentView('dashboard');
  };

  const handleLoginSuccess = (user: User) => {
      setAuthUser(user);
      refreshData();
  };

  // --- Modal Triggers ---
  const closeModal = () => {
      setIsModalOpen(false);
      setEditingId(null);
      setEditingInitialData(null);
      setTargetClientId(undefined);
      setTargetSupplierId(undefined);
      setTargetName('');
      setReturnTargetTransaction(null);
  };

  const openTransactionModal = () => { setModalMode('transaction'); setIsModalOpen(true); };
  const openTradeModal = () => { setModalMode('trade'); setIsModalOpen(true); };
  const openClientModal = () => { setModalMode('add-client'); setIsModalOpen(true); };
  const openSupplierModal = () => { setModalMode('add-supplier'); setIsModalOpen(true); };
  const openAddItemModal = () => { setModalMode('add-item'); setIsModalOpen(true); };
  const openAddUserModal = () => { setModalMode('add-user'); setIsModalOpen(true); };

  const handleClientAction = (clientId: number, clientName: string) => { setTargetClientId(clientId); setTargetName(clientName); setModalMode('client-action'); setIsModalOpen(true); };
  const handleSupplierAction = (supplierId: number, supplierName: string) => { setTargetSupplierId(supplierId); setTargetName(supplierName); setModalMode('supplier-action'); setIsModalOpen(true); };

  const handleEditClient = (client: Client) => { setEditingId(client.id); setEditingInitialData(client); setModalMode('add-client'); setIsModalOpen(true); };
  const handleEditSupplier = (supplier: Supplier) => { setEditingId(supplier.id); setEditingInitialData(supplier); setModalMode('add-supplier'); setIsModalOpen(true); };
  const handleEditTransaction = (trx: Transaction) => { setEditingId(trx.id); setEditingInitialData(trx); setModalMode('transaction'); setIsModalOpen(true); };
  const handleEditItem = (item: Item) => { setEditingId(item.id); setEditingInitialData(item); setModalMode('add-item'); setIsModalOpen(true); };

  const handleViewClientDetails = (client: Client) => { setSelectedClient(client); setCurrentView('client-details'); };
  const handleViewInvoice = (trx: Transaction) => { setSelectedInvoice(trx); setCurrentView('invoice-details'); };

  // New: Open Return Modal
  const handleAddReturn = (trx: Transaction) => {
      setReturnTargetTransaction(trx);
      setEditingInitialData(trx); // Pass original data for defaults
      setModalMode('add-return');
      setIsModalOpen(true);
  }

  // === RENDER ===

  if (!currentUser) {
      return <Login onLoginSuccess={handleLoginSuccess} />;
  }

  return (
    <div className="flex min-h-screen bg-slate-50 font-sans">
      <Sidebar 
        currentView={currentView} 
        currentUser={currentUser}
        onChangeView={(view) => {
            setCurrentView(view);
            if (view !== 'client-details') setSelectedClient(null);
            if (view !== 'invoice-details') setSelectedInvoice(null);
        }} 
        onClearData={handleClearData} 
        onOpenSettings={() => setIsSettingsOpen(true)}
        onLogout={handleLogout}
      />

      <main className="flex-1 flex flex-col relative overflow-hidden">
        {/* Header */}
        <header className="h-20 bg-white shadow-sm flex justify-between items-center px-8 z-20 no-print sticky top-0">
          <div>
            <h2 className="text-xl font-bold text-slate-800">
                {currentView === 'dashboard' && 'لوحة التحكم الرئيسية'}
                {currentView === 'clients' && 'إدارة العملاء'}
                {currentView === 'suppliers' && 'الموردين والشركات'}
                {currentView === 'items' && 'المخزن والأصناف'}
                {currentView === 'invoices' && 'سجل الفواتير'}
                {currentView === 'team' && 'إدارة الصلاحيات والمستخدمين'}
                {currentView === 'client-details' && selectedClient && `كشف حساب: ${selectedClient.name}`}
                {currentView === 'invoice-details' && selectedInvoice && `تفاصيل الفاتورة #${selectedInvoice.id.toString().slice(-4)}`}
            </h2>
          </div>

          <div className="flex-1 mx-8 max-w-lg hidden md:block">
            {['dashboard', 'clients', 'suppliers', 'invoices'].includes(currentView) && (
                <div className="relative group">
                <Search className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-blue-500 transition-colors" size={18} />
                <input 
                    type="text" 
                    placeholder="بحث..." 
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="w-full bg-slate-100 border-none rounded-xl py-2.5 pr-10 pl-4 focus:ring-2 focus:ring-blue-500 outline-none transition-all text-sm"
                />
                </div>
            )}
          </div>

          <div className="flex items-center gap-3">
             <button 
                onClick={openTradeModal}
                className="hidden lg:flex items-center gap-2 bg-slate-900 text-white px-4 py-2 rounded-lg hover:bg-slate-700 transition text-sm font-bold shadow-sm"
                title="فاتورة تجارية جديدة (بيع وشراء)"
             >
                <ShoppingCart size={18} />
                <span>فاتورة تجارية</span>
             </button>

             <ShareButton 
                currentView={currentView} 
                stats={stats} 
                counts={{
                    clients: clients.length,
                    suppliers: suppliers.length,
                    items: items.length,
                    transactions: transactions.length
                }}
             />

             <button onClick={handleExportCSV} className="flex items-center gap-2 bg-emerald-600 text-white px-4 py-2 rounded-lg hover:bg-emerald-700 transition text-sm font-bold shadow-sm" title="تصدير إلى CSV">
                <Download size={18} />
                <span className="hidden xl:inline">تصدير CSV</span>
             </button>
             <button onClick={() => window.print()} className="flex items-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition text-sm font-bold shadow-sm">
                <Printer size={18} />
                <span className="hidden xl:inline">طباعة</span>
             </button>
          </div>
        </header>

        {/* Content */}
        <div className="flex-1 overflow-auto p-8 relative">
          <div className="max-w-7xl mx-auto">
            <div className="hidden print-only mb-8 border-b-2 border-slate-800 pb-4">
                <div className="flex justify-between items-center">
                    <div>
                        <h1 className="text-4xl font-extrabold text-black mb-1">المحاسب الذكي</h1>
                        <p className="text-gray-600 font-bold text-lg">مكتب بهاء للتجارة والتوزيع</p>
                    </div>
                    <div className="text-left">
                        <p className="text-gray-500 text-sm">تاريخ التقرير</p>
                        <p className="font-bold text-xl">{new Date().toLocaleDateString('ar-EG', { year: 'numeric', month: 'long', day: 'numeric' })}</p>
                    </div>
                </div>
            </div>

            {currentView === 'dashboard' && <Dashboard stats={stats} transactions={filteredTransactions} onDeleteTransaction={handleDeleteTransaction} onEditTransaction={handleEditTransaction} />}
            {currentView === 'invoices' && <Invoices transactions={filteredTransactions} onDeleteTransaction={handleDeleteTransaction} onEditTransaction={handleEditTransaction} onViewInvoice={handleViewInvoice} searchTerm={searchTerm} onSearchChange={setSearchTerm} />}
            {currentView === 'clients' && <Clients clients={filteredClients} onDeleteClient={handleDeleteClient} onEditClient={handleEditClient} onOpenAddModal={openClientModal} onClientAction={handleClientAction} onViewDetails={handleViewClientDetails} />}
            {currentView === 'suppliers' && <Suppliers suppliers={filteredSuppliers} onDeleteSupplier={handleDeleteSupplier} onEditSupplier={handleEditSupplier} onOpenAddSupplierModal={openSupplierModal} onSupplierAction={handleSupplierAction} />}
            {currentView === 'items' && <Items items={filteredItems} suppliers={suppliers} onDeleteItem={handleDeleteItem} onEditItem={handleEditItem} onOpenAddItemModal={() => openAddItemModal()} />}
            {currentView === 'team' && currentUser.role === 'admin' && <Team users={users} currentUser={currentUser} onDeleteUser={handleDeleteUser} onToggleUserStatus={handleToggleUserStatus} onOpenAddUserModal={openAddUserModal} />}
            {currentView === 'client-details' && selectedClient && <ClientDetails client={selectedClient} transactions={transactions} onBack={() => { setCurrentView('clients'); setSelectedClient(null); }} />}

            {currentView === 'invoice-details' && selectedInvoice && (
                <InvoiceDetails 
                    transaction={selectedInvoice}
                    allTransactions={transactions} 
                    client={clients.find(c => c.id === selectedInvoice.clientId)}
                    supplier={suppliers.find(s => s.id === selectedInvoice.supplierId)}
                    onBack={() => { setCurrentView('invoices'); setSelectedInvoice(null); }}
                    onAddReturn={handleAddReturn}
                />
            )}
          </div>
        </div>

        {/* FAB */}
        {!['client-details', 'invoice-details', 'team'].includes(currentView) && (
            <button
            onClick={() => {
                if (currentView === 'clients') openClientModal();
                else if (currentView === 'suppliers') openSupplierModal();
                else if (currentView === 'items') openAddItemModal();
                else openTransactionModal();
            }}
            className={`fixed bottom-8 left-8 text-white w-14 h-14 rounded-full shadow-2xl flex items-center justify-center transition-transform hover:scale-110 active:scale-95 z-40 no-print ${currentView === 'suppliers' ? 'bg-orange-600 hover:bg-orange-700' : currentView === 'items' ? 'bg-slate-700 hover:bg-slate-800' : 'bg-blue-600 hover:bg-blue-700'}`}
            >
            <Plus size={28} />
            </button>
        )}

        <AddModal 
          isOpen={isModalOpen}
          mode={modalMode}
          targetSupplierId={targetSupplierId}
          targetClientId={targetClientId}
          targetName={targetName}
          suppliers={suppliers}
          clients={clients}
          items={items}
          initialData={editingInitialData}
          onClose={closeModal}
          onSaveTransaction={handleSaveTransaction}
          onSaveTrade={handleSaveTrade}
          onSaveClient={handleSaveClient}
          onSaveSupplier={handleSaveSupplier}
          onSaveItem={handleSaveItem}
          onSaveUser={handleSaveUser}
          onSaveReturn={handleSaveReturn}
        />

        <SettingsModal 
            isOpen={isSettingsOpen}
            onClose={() => setIsSettingsOpen(false)}
            onDataRestored={() => {
                refreshData();
                setAuthUser(getCurrentUser()); // Refresh user if overwritten
            }}
        />
      </main>
    </div>
  );
}

export default App;

import { Client, Supplier, Item, Transaction, User } from '../types';

const TRX_KEY = 'almohaseb_transactions';
const CLIENTS_KEY = 'almohaseb_clients';
const SUPPLIERS_KEY = 'almohaseb_suppliers';
const ITEMS_KEY = 'almohaseb_items';
const USERS_KEY = 'almohaseb_users';
const SESSION_KEY = 'almohaseb_session';

// Users & Auth
export const loadUsers = (): User[] => {
  try {
    const data = localStorage.getItem(USERS_KEY);
    if (data) {
        const parsedUsers: User[] = JSON.parse(data);
        // Ensure all users have isActive flag (migration for existing data)
        return parsedUsers.map(u => ({ ...u, isActive: u.isActive !== undefined ? u.isActive : true }));
    }

    // Default Admin requested by user
    const defaultAdmin: User = {
        id: 1,
        name: 'mahmoud',
        email: 'mahmoudegypte@gmail.com', // Updated email
        password: 'Mahmoud@2025',
        role: 'admin',
