  id: number;
  name: string;
  email: string;
  password: string; // Stored locally for demo purposes
  role: UserRole;
  image?: string;
  isActive?: boolean; // New field for account status
}

export interface Transaction {
  id: number;
  name: string;
  amount: number;
  type: TransactionType;
  date: string;
  clientId?: number;
  supplierId?: number;
  // New fields for Trade
  itemId?: number;
  quantity?: number;
  unitPrice?: number;
  relatedTransactionId?: number; // To link the purchase and sale

  // New Fields for Driver & Returns
  driverName?: string;
  driverPhone?: string;
  isReturn?: boolean; // True if this transaction is a refund/return
  originalTransactionId?: number; // Links the return to the original invoice

  // Custom Field
  immunizationStatus?: 'immunized' | 'not_immunized';
}

export interface Client {
  id: number;
  name: string;
  phone: string;
  image?: string;
}

export interface Supplier {
  id: number;
  name: string;
  phone: string;
  image?: string;
}

export interface Item {
  id: number;
  name: string;
  supplierId: number;
  image?: string;
}

export type ViewState = 'dashboard' | 'clients' | 'suppliers' | 'items' | 'invoices' | 'client-details' | 'invoice-details' | 'team' | 'reports';

export interface Stats {
  income: number;
  expense: number;
  balance: number;
}

export type ModalMode = 'transaction' | 'trade' | 'add-client' | 'add-supplier' | 'add-item' | 'client-action' | 'supplier-action' | 'add-user' | 'add-return';

import React from 'react';
import { LayoutDashboard, Users, FileText, Trash2, Truck, Package, Settings, LogOut, Shield, BarChart3 } from 'lucide-react';
import { ViewState, User } from '../types';

interface SidebarProps {
  currentView: ViewState;
  currentUser: User | null;
  onChangeView: (view: ViewState) => void;
  onClearData: () => void;
  onOpenSettings: () => void;
