import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import Clients from './components/Clients';
import Suppliers from './components/Suppliers';
import Items from './components/Items';
import Invoices from './components/Invoices';
import Reports from './components/Reports';
import Team from './components/Team'; 
import AddModal from './components/AddModal';
import ShareButton from './components/ShareButton';
import ClientDetails from './components/ClientDetails';
import InvoiceDetails from './components/InvoiceDetails';
import SettingsModal from './components/SettingsModal';
import Login from './components/Login'; 
import { ViewState, Transaction, Client, Supplier, Item, Stats, TransactionType, ModalMode, User, UserRole } from './types';
import { 
    loadTransactions, saveTransactions, 
    loadClients, saveClients, 
    loadSuppliers, saveSuppliers, 
    loadItems, saveItems, 
    loadUsers, saveUsers, getCurrentUser, setCurrentUser, 
    clearAllData 
} from './services/storage';
import { Plus, Printer, Bell, Search, Download, ShoppingCart, MapPin, Phone } from 'lucide-react';

function App() {
  // Auth State
  const [currentUser, setAuthUser] = useState<User | null>(null);

  const [currentView, setCurrentView] = useState<ViewState>('dashboard');

  // Data State
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [clients, setClients] = useState<Client[]>([]);
  const [suppliers, setSuppliers] = useState<Supplier[]>([]);
  const [items, setItems] = useState<Item[]>([]);
  const [users, setUsers] = useState<User[]>([]); 

  // Selected Details State
  const [selectedClient, setSelectedClient] = useState<Client | null>(null);
  const [selectedInvoice, setSelectedInvoice] = useState<Transaction | null>(null);

  // Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);

  const [modalMode, setModalMode] = useState<ModalMode>('transaction');
  const [targetSupplierId, setTargetSupplierId] = useState<number | undefined>(undefined);
  const [targetClientId, setTargetClientId] = useState<number | undefined>(undefined);
  const [targetName, setTargetName] = useState<string>('');

  // Editing State
  const [editingId, setEditingId] = useState<number | null>(null);
  const [editingInitialData, setEditingInitialData] = useState<any>(null);

  // Return Transaction State (The invoice being returned)
  const [returnTargetTransaction, setReturnTargetTransaction] = useState<Transaction | null>(null);

  // Search State
  const [searchTerm, setSearchTerm] = useState('');

  // Load data
  const refreshData = () => {
    setTransactions(loadTransactions());
    setClients(loadClients());
    setSuppliers(loadSuppliers());
    setItems(loadItems());
    setUsers(loadUsers());
  };

  useEffect(() => {
    const sessionUser = getCurrentUser();
    if (sessionUser) {
        setAuthUser(sessionUser);
        refreshData();
    }
  }, []);

  // Calculate Stats
  const stats: Stats = useMemo(() => {
    let income = 0;
    let expense = 0;
    transactions.forEach(t => {
      if (t.type === 'income') income += t.amount;
      else expense += t.amount;
    });
    return { income, expense, balance: income - expense };
  }, [transactions]);

  // Filter Logic
  const filteredTransactions = useMemo(() => {
    if (!searchTerm) return transactions;
    return transactions.filter(t => 
      t.name.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [transactions, searchTerm]);

  const filteredClients = useMemo(() => {
    if (!searchTerm) return clients;
    return clients.filter(c => 
      c.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      c.phone.includes(searchTerm)
    );
  }, [clients, searchTerm]);

  const filteredSuppliers = useMemo(() => {
    if (!searchTerm) return suppliers;
    return suppliers.filter(s => {
        const nameMatch = s.name.toLowerCase().includes(searchTerm.toLowerCase());
        const phoneMatch = s.phone.includes(searchTerm);
        return nameMatch || phoneMatch;
    });
  }, [suppliers, searchTerm]);

  const filteredItems = useMemo(() => {
    if (!searchTerm) return items;
    return items.filter(i => {
        const itemMatch = i.name.toLowerCase().includes(searchTerm.toLowerCase());
        const supplierMatch = suppliers.find(s => s.id === i.supplierId)?.name.toLowerCase().includes(searchTerm.toLowerCase());
        return itemMatch || supplierMatch;
    });
  }, [items, suppliers, searchTerm]);

  // CSV Export Logic
  const handleExportCSV = () => {
    let csvContent = "data:text/csv;charset=utf-8,\uFEFF"; 
    let filename = "export.csv";

    if (currentView === 'clients') {
      csvContent += "ID,Name,Phone\n";
      filteredClients.forEach(c => { csvContent += `${c.id},"${c.name}","${c.phone}"\n`; });
      filename = "clients.csv";
    } else if (currentView === 'suppliers') {
      csvContent += "ID,Name,Phone\n";
      filteredSuppliers.forEach(s => { csvContent += `${s.id},"${s.name}","${s.phone}"\n`; });
      filename = "suppliers.csv";
    } else {
      csvContent += "ID,Date,Description,Type,Amount\n";
      filteredTransactions.forEach(t => {
         const typeAr = t.type === 'income' ? 'قبض' : 'صرف';
         csvContent += `${t.id},${t.date},"${t.name}",${typeAr},${t.amount}\n`;
      });
      filename = "transactions.csv";
    }

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", filename);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // --- Handlers ---

  const handleSaveTransaction = (data: { 
      name: string; 
      amount: number; 
      type: TransactionType; 
      clientId?: number; 
      supplierId?: number; 
      driverName?: string; 
      driverPhone?: string;
      immunizationStatus?: 'immunized' | 'not_immunized';
    }) => {
    if (editingId) {
        const updated = transactions.map(t => t.id === editingId ? { ...t, ...data } : t);
        setTransactions(updated);
        saveTransactions(updated);
    } else {
        const newTrx: Transaction = {
          id: Date.now(),
          name: data.name,
          amount: data.amount,
          type: data.type,
          date: new Date().toLocaleDateString('ar-EG'),
          clientId: data.clientId,
          supplierId: data.supplierId,
          driverName: data.driverName,
          driverPhone: data.driverPhone,
          immunizationStatus: data.immunizationStatus
        };
        const updated = [...transactions, newTrx];
        setTransactions(updated);
        saveTransactions(updated);
    }
    closeModal();
  };

  const handleSaveTrade = (data: { 
      clientId: number; 
      supplierId: number; 
      itemId: number; 
      itemName: string; 
      quantity: number; 
      buyPrice: number; 
      sellPrice: number;
      driverName?: string;
      driverPhone?: string; 
      immunizationStatus?: 'immunized' | 'not_immunized';
  }) => {
      const now = Date.now();
      const dateStr = new Date().toLocaleDateString('ar-EG');
      const purchaseTrx: Transaction = { 
          id: now, 
          name: `توريد: ${data.itemName} (عدد ${data.quantity})`, 
          amount: data.quantity * data.buyPrice, 
          type: 'expense', 
          date: dateStr, 
          supplierId: data.supplierId, 
          itemId: data.itemId, 
          quantity: data.quantity, 
          unitPrice: data.buyPrice,
          immunizationStatus: data.immunizationStatus
      };

      const saleTrx: Transaction = { 
          id: now + 1, 
          name: `بيع: ${data.itemName} (عدد ${data.quantity})`, 
          amount: data.quantity * data.sellPrice, 
          type: 'income', 
          date: dateStr, 
          clientId: data.clientId, 
          itemId: data.itemId, 
          quantity: data.quantity, 
          unitPrice: data.sellPrice, 
          relatedTransactionId: now,
          driverName: data.driverName,
          driverPhone: data.driverPhone,
          immunizationStatus: data.immunizationStatus
      };

      const updated = [...transactions, purchaseTrx, saleTrx];
      setTransactions(updated);
      saveTransactions(updated);
      closeModal();
  };

  const handleSaveReturn = (data: { quantity: number; amount: number; notes: string }) => {
      if (!returnTargetTransaction) return;

      const totalReturnAmount = data.quantity * data.amount;
      // Invert type: If original was Income (Sale), return is Expense.
      const returnType: TransactionType = returnTargetTransaction.type === 'income' ? 'expense' : 'income';

      const returnTrx: Transaction = {
          id: Date.now(),
          name: data.notes,
          amount: totalReturnAmount,
          type: returnType,
          date: new Date().toLocaleDateString('ar-EG'),
          clientId: returnTargetTransaction.clientId,
          supplierId: returnTargetTransaction.supplierId,
          itemId: returnTargetTransaction.itemId,
          quantity: data.quantity,
          unitPrice: data.amount,
          isReturn: true,
          originalTransactionId: returnTargetTransaction.id,
          immunizationStatus: returnTargetTransaction.immunizationStatus
      };

      const updated = [...transactions, returnTrx];
      setTransactions(updated);
      saveTransactions(updated);
      closeModal();
  };

  const handleSaveClient = (data: { name: string; phone: string; image?: string }) => {
    let updated: Client[];
    if (editingId) {
        updated = clients.map(c => c.id === editingId ? { ...c, ...data, image: data.image || c.image } : c);
    } else {
        updated = [...clients, { id: Date.now(), name: data.name, phone: data.phone, image: data.image }];
    }
    setClients(updated);
    saveClients(updated);
    closeModal();
  };

  const handleSaveSupplier = (data: { name: string; phone: string; image?: string }) => {
      let updated: Supplier[];
      if (editingId) {
          updated = suppliers.map(s => s.id === editingId ? { ...s, ...data, image: data.image || s.image } : s);
      } else {
          updated = [...suppliers, { id: Date.now(), name: data.name, phone: data.phone, image: data.image }];
      }
      setSuppliers(updated);
      saveSuppliers(updated);
      closeModal();
  };

  const handleSaveItem = (data: { name: string; supplierId: number; image?: string }) => {
      let updated: Item[];
      if (editingId) {
          updated = items.map(i => i.id === editingId ? { ...i, ...data, image: data.image || i.image } : i);
      } else {
          updated = [...items, { id: Date.now(), name: data.name, supplierId: data.supplierId, image: data.image }];
      }
      setItems(updated);
      saveItems(updated);
      closeModal();
  };

  const handleSaveUser = (data: { name: string; email: string; password: string; role: UserRole }) => {
      const newUser: User = { id: Date.now(), ...data, isActive: true };
      const updated = [...users, newUser];
      setUsers(updated);
      saveUsers(updated);
      closeModal();
  };

  // --- User Management Handlers ---
  const handleDeleteUser = (id: number) => {
      const updated = users.filter(u => u.id !== id);
      setUsers(updated);
      saveUsers(updated);
  };

  const handleToggleUserStatus = (id: number) => {
      const updated = users.map(u => {
          if (u.id === id) return { ...u, isActive: !u.isActive };
          return u;
      });
      setUsers(updated);
      saveUsers(updated);
  };

  // --- Deletion Handlers ---
  const handleDeleteTransaction = (id: number) => {
    const updated = transactions.filter(t => t.id !== id && t.originalTransactionId !== id); // Also delete linked returns if any (optional)
    setTransactions(updated);
    saveTransactions(updated);
  };
  const handleDeleteClient = (id: number) => {
    const updated = clients.filter(c => c.id !== id);
    setClients(updated);
    saveClients(updated);
    if (selectedClient && selectedClient.id === id) {
        setCurrentView('clients');
        setSelectedClient(null);
    }
  };
  const handleDeleteSupplier = (id: number) => {
      const updatedSuppliers = suppliers.filter(s => s.id !== id);
      const updatedItems = items.filter(i => i.supplierId !== id); 
      setSuppliers(updatedSuppliers);
      setItems(updatedItems);
      saveSuppliers(updatedSuppliers);
      saveItems(updatedItems);
  };
  const handleDeleteItem = (id: number) => {
      const updated = items.filter(i => i.id !== id);
      setItems(updated);
      saveItems(updated);
  };

  const handleClearData = () => {
    clearAllData();
    refreshData();
  };

  const handleLogout = () => {
      setCurrentUser(null);
      setAuthUser(null);
      setCurrentView('dashboard');
  };

  const handleLoginSuccess = (user: User) => {
      setAuthUser(user);
      refreshData();
  };

  // --- Modal Triggers ---
  const closeModal = () => {
      setIsModalOpen(false);
      setEditingId(null);
      setEditingInitialData(null);
      setTargetClientId(undefined);
      setTargetSupplierId(undefined);
      setTargetName('');
      setReturnTargetTransaction(null);
  };

  const openTransactionModal = () => { setModalMode('transaction'); setIsModalOpen(true); };
  const openTradeModal = () => { setModalMode('trade'); setIsModalOpen(true); };
  const openClientModal = () => { setModalMode('add-client'); setIsModalOpen(true); };
  const openSupplierModal = () => { setModalMode('add-supplier'); setIsModalOpen(true); };
  const openAddItemModal = () => { setModalMode('add-item'); setIsModalOpen(true); };
  const openAddUserModal = () => { setModalMode('add-user'); setIsModalOpen(true); };

  const handleClientAction = (clientId: number, clientName: string) => { setTargetClientId(clientId); setTargetName(clientName); setModalMode('client-action'); setIsModalOpen(true); };
  const handleSupplierAction = (supplierId: number, supplierName: string) => { setTargetSupplierId(supplierId); setTargetName(supplierName); setModalMode('supplier-action'); setIsModalOpen(true); };

  const handleEditClient = (client: Client) => { setEditingId(client.id); setEditingInitialData(client); setModalMode('add-client'); setIsModalOpen(true); };
  const handleEditSupplier = (supplier: Supplier) => { setEditingId(supplier.id); setEditingInitialData(supplier); setModalMode('add-supplier'); setIsModalOpen(true); };
  const handleEditTransaction = (trx: Transaction) => { setEditingId(trx.id); setEditingInitialData(trx); setModalMode('transaction'); setIsModalOpen(true); };
  const handleEditItem = (item: Item) => { setEditingId(item.id); setEditingInitialData(item); setModalMode('add-item'); setIsModalOpen(true); };

  const handleViewClientDetails = (client: Client) => { setSelectedClient(client); setCurrentView('client-details'); };
  const handleViewInvoice = (trx: Transaction) => { setSelectedInvoice(trx); setCurrentView('invoice-details'); };

  // New: Open Return Modal
  const handleAddReturn = (trx: Transaction) => {
      setReturnTargetTransaction(trx);
      setEditingInitialData(trx); // Pass original data for defaults
      setModalMode('add-return');
      setIsModalOpen(true);
  }

  // === RENDER ===

  if (!currentUser) {
      return <Login onLoginSuccess={handleLoginSuccess} />;
  }

  return (
    <div className="flex min-h-screen bg-slate-50 font-sans">
      <Sidebar 
        currentView={currentView} 
        currentUser={currentUser}
        onChangeView={(view) => {
            setCurrentView(view);
            if (view !== 'client-details') setSelectedClient(null);
            if (view !== 'invoice-details') setSelectedInvoice(null);
        }} 
        onClearData={handleClearData} 
        onOpenSettings={() => setIsSettingsOpen(true)}
        onLogout={handleLogout}
      />

      <main className="flex-1 flex flex-col relative overflow-hidden">
        {/* Header */}
        <header className="h-20 bg-white shadow-sm flex justify-between items-center px-8 z-20 no-print sticky top-0">
          <div>
            <h2 className="text-xl font-bold text-slate-800">
                {currentView === 'dashboard' && 'لوحة التحكم الرئيسية'}
                {currentView === 'clients' && 'إدارة العملاء'}
                {currentView === 'suppliers' && 'الموردين والشركات'}
                {currentView === 'items' && 'المخزن والأصناف'}
                {currentView === 'invoices' && 'سجل الفواتير'}
                {currentView === 'team' && 'إدارة الصلاحيات والمستخدمين'}
                {currentView === 'reports' && 'التقارير المالية والمخزنية'}
                {currentView === 'client-details' && selectedClient && `كشف حساب: ${selectedClient.name}`}
                {currentView === 'invoice-details' && selectedInvoice && `تفاصيل الفاتورة #${selectedInvoice.id.toString().slice(-4)}`}
            </h2>
          </div>

          <div className="flex-1 mx-8 max-w-lg hidden md:block">
            {['dashboard', 'clients', 'suppliers', 'invoices'].includes(currentView) && (
                <div className="relative group">
                <Search className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-blue-500 transition-colors" size={18} />
                <input 
                    type="text" 
                    placeholder="بحث..." 
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="w-full bg-slate-100 border-none rounded-xl py-2.5 pr-10 pl-4 focus:ring-2 focus:ring-blue-500 outline-none transition-all text-sm"
                />
                </div>
            )}
          </div>

          <div className="flex items-center gap-3">
             <button 
                onClick={openTradeModal}
                className="hidden lg:flex items-center gap-2 bg-slate-900 text-white px-4 py-2 rounded-lg hover:bg-slate-700 transition text-sm font-bold shadow-sm"
                title="فاتورة تجارية جديدة (بيع وشراء)"
             >
                <ShoppingCart size={18} />
                <span>فاتورة تجارية</span>
             </button>

             <ShareButton 
                currentView={currentView} 
                stats={stats} 
                counts={{
                    clients: clients.length,
                    suppliers: suppliers.length,
                    items: items.length,
                    transactions: transactions.length
                }}
             />

             <button onClick={handleExportCSV} className="flex items-center gap-2 bg-emerald-600 text-white px-4 py-2 rounded-lg hover:bg-emerald-700 transition text-sm font-bold shadow-sm" title="تصدير إلى CSV">
                <Download size={18} />
                <span className="hidden xl:inline">تصدير CSV</span>
             </button>
             <button onClick={() => window.print()} className="flex items-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition text-sm font-bold shadow-sm">
                <Printer size={18} />
                <span className="hidden xl:inline">طباعة</span>
             </button>
          </div>
        </header>

        {/* Content */}
        <div className="flex-1 overflow-auto p-8 relative">
          <div className="max-w-7xl mx-auto">
            <div className="hidden print-only mb-8 border-b-2 border-slate-800 pb-4">
                <div className="flex justify-between items-start">
                    <div className="flex items-center gap-4">
                         {/* Simple Logo for list print */}
                         <svg width="60" height="60" viewBox="0 0 100 100" fill="none" xmlns="http://www.w3.org/2000/svg">
                            <rect x="10" y="10" width="80" height="80" rx="16" fill="black" />
                            <path d="M50 25L75 40V70L50 85L25 70V40L50 25Z" stroke="white" strokeWidth="4" fill="none"/>
                            <path d="M50 45V65M40 55H60" stroke="white" strokeWidth="4" strokeLinecap="round"/>
                        </svg>
                        <div>
                            <h1 className="text-3xl font-extrabold text-black mb-1">مكتب بهاء عبد الغني</h1>
                            <p className="text-gray-600 font-bold text-lg">كفر الشيخ - مطوبس - بجوار قهوة قدري</p>
                            <div className="flex items-center gap-2 text-sm font-bold mt-1">
                                <Phone size={14} />
                                <span>01224168810</span>
                            </div>
                        </div>
                    </div>
                    <div className="text-left pt-2">
                        <p className="text-gray-500 text-sm">تاريخ التقرير</p>
                        <p className="font-bold text-xl">{new Date().toLocaleDateString('ar-EG', { year: 'numeric', month: 'long', day: 'numeric' })}</p>
                    </div>
                </div>
            </div>

            {currentView === 'dashboard' && <Dashboard stats={stats} transactions={filteredTransactions} onDeleteTransaction={handleDeleteTransaction} onEditTransaction={handleEditTransaction} />}
            {currentView === 'invoices' && <Invoices transactions={filteredTransactions} onDeleteTransaction={handleDeleteTransaction} onEditTransaction={handleEditTransaction} onViewInvoice={handleViewInvoice} searchTerm={searchTerm} onSearchChange={setSearchTerm} />}
            {currentView === 'clients' && <Clients clients={filteredClients} onDeleteClient={handleDeleteClient} onEditClient={handleEditClient} onOpenAddModal={openClientModal} onClientAction={handleClientAction} onViewDetails={handleViewClientDetails} />}
            {currentView === 'suppliers' && <Suppliers suppliers={filteredSuppliers} onDeleteSupplier={handleDeleteSupplier} onEditSupplier={handleEditSupplier} onOpenAddSupplierModal={openSupplierModal} onSupplierAction={handleSupplierAction} />}
            {currentView === 'items' && <Items items={filteredItems} suppliers={suppliers} onDeleteItem={handleDeleteItem} onEditItem={handleEditItem} onOpenAddItemModal={() => openAddItemModal()} />}
            {currentView === 'reports' && currentUser.role === 'admin' && <Reports transactions={transactions} clients={clients} suppliers={suppliers} items={items} />}
            {currentView === 'team' && currentUser.role === 'admin' && <Team users={users} currentUser={currentUser} onDeleteUser={handleDeleteUser} onToggleUserStatus={handleToggleUserStatus} onOpenAddUserModal={openAddUserModal} />}
            {currentView === 'client-details' && selectedClient && <ClientDetails client={selectedClient} transactions={transactions} onBack={() => { setCurrentView('clients'); setSelectedClient(null); }} />}

            {currentView === 'invoice-details' && selectedInvoice && (
                <InvoiceDetails 
                    transaction={selectedInvoice}
                    allTransactions={transactions} 
                    client={clients.find(c => c.id === selectedInvoice.clientId)}
                    supplier={suppliers.find(s => s.id === selectedInvoice.supplierId)}
                    onBack={() => { setCurrentView('invoices'); setSelectedInvoice(null); }}
                    onAddReturn={handleAddReturn}
                />
            )}
          </div>
        </div>

        {/* FAB */}
        {!['client-details', 'invoice-details', 'team', 'reports'].includes(currentView) && (
            <button
            onClick={() => {
                if (currentView === 'clients') openClientModal();
                else if (currentView === 'suppliers') openSupplierModal();
                else if (currentView === 'items') openAddItemModal();
                else openTransactionModal();
            }}
            className={`fixed bottom-8 left-8 text-white w-14 h-14 rounded-full shadow-2xl flex items-center justify-center transition-transform hover:scale-110 active:scale-95 z-40 no-print ${currentView === 'suppliers' ? 'bg-orange-600 hover:bg-orange-700' : currentView === 'items' ? 'bg-slate-700 hover:bg-slate-800' : 'bg-blue-600 hover:bg-blue-700'}`}
            >
            <Plus size={28} />
            </button>
        )}

        <AddModal 
          isOpen={isModalOpen}
          mode={modalMode}
          targetSupplierId={targetSupplierId}
          targetClientId={targetClientId}
          targetName={targetName}
          suppliers={suppliers}
          clients={clients}
          items={items}
          initialData={editingInitialData}
          onClose={closeModal}
          onSaveTransaction={handleSaveTransaction}
          onSaveTrade={handleSaveTrade}
          onSaveClient={handleSaveClient}
          onSaveSupplier={handleSaveSupplier}
          onSaveItem={handleSaveItem}
          onSaveUser={handleSaveUser}
          onSaveReturn={handleSaveReturn}
        />

        <SettingsModal 
            isOpen={isSettingsOpen}
            onClose={() => setIsSettingsOpen(false)}
            onDataRestored={() => {
                refreshData();
                setAuthUser(getCurrentUser()); // Refresh user if overwritten
            }}
        />
      </main>
    </div>
  );
}

export default App;

import React, { useMemo } from 'react';
import { Client, Transaction } from '../types';
import { ArrowRight, Printer, User, Phone, Calendar, ArrowDownLeft, ArrowUpRight, FileText } from 'lucide-react';

interface ClientDetailsProps {
  client: Client;
  transactions: Transaction[];
  onBack: () => void;
}

const ClientDetails: React.FC<ClientDetailsProps> = ({ client, transactions, onBack }) => {

  // تصفية العمليات وترتيبها من الأقدم للأحدث لحساب الرصيد التراكمي
  const statementData = useMemo(() => {
    const sortedTrx = transactions
      .filter(t => t.clientId === client.id)
      .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime() || a.id - b.id);

    let runningBalance = 0;
    return sortedTrx.map(t => {
        // افتراض: 'income' (بيع/قبض) يزيد المديونية/الحساب، 'expense' (مرتجع) ينقصها
        // أو العكس حسب طبيعة العمل، هنا سنفترض أن النظام يسجل المبيعات كـ Income
        if (t.type === 'income') runningBalance += t.amount;
        else runningBalance -= t.amount;

        return { ...t, runningBalance };
    });
  }, [transactions, client.id]);

  // حساب الإجماليات
  const totals = useMemo(() => {
    let totalSales = 0; 
    let totalReturns = 0; 

    statementData.forEach(t => {
       if (t.type === 'income') totalSales += t.amount;
       else totalReturns += t.amount;
    });

    return { totalSales, totalReturns, net: totalSales - totalReturns };
  }, [statementData]);

  // اللوجو الجديد
  const OfficeLogo = () => (
    <svg width="60" height="60" viewBox="0 0 100 100" fill="none" xmlns="http://www.w3.org/2000/svg">
       <path d="M20 20 H80 V80 H20 Z" fill="#1e293b" opacity="0.1"/>
       <path d="M50 10 L85 30 V85 H15 V30 L50 10 Z" stroke="#2563EB" strokeWidth="4" fill="none" strokeLinejoin="round"/>
       <path d="M35 85 V45 M65 85 V45 M35 45 L50 35 L65 45" stroke="#2563EB" strokeWidth="4" strokeLinecap="round" strokeLinejoin="round"/>
       <path d="M50 55 V75" stroke="#2563EB" strokeWidth="4" strokeLinecap="round"/>
    </svg>
  );

  return (
    <div className="space-y-6 fade-in pb-20">

      {/* Header & Navigation (No Print) */}
      <div className="flex items-center justify-between no-print">
        <button 
            onClick={onBack}
            className="flex items-center gap-2 text-slate-500 hover:text-blue-600 transition font-bold"
        >
            <ArrowRight size={20} />
            العودة للعملاء
        </button>
        <button 
            onClick={() => window.print()}
            className="flex items-center gap-2 bg-slate-800 text-white px-4 py-2 rounded-lg hover:bg-slate-700 transition shadow-sm font-bold"
        >
            <Printer size={18} />
            طباعة كشف الحساب
        </button>
      </div>

      {/* Printable Sheet */}
      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-8 md:p-12 min-h-[297mm] print:shadow-none print:border-none print:w-full">

        {/* Report Header */}
        <div className="border-b-2 border-slate-800 pb-6 mb-8 flex justify-between items-center">
            <div className="flex items-center gap-4">
                <OfficeLogo />
                <div>
                    <h1 className="text-2xl font-extrabold text-slate-900">مكتب بهاء عبد الغني</h1>
                    <p className="text-blue-600 font-bold">للتجارة والتوزيع</p>
                </div>
            </div>
            <div className="text-left">
                <h2 className="text-xl font-bold text-slate-800 mb-1">كشف حساب عميل</h2>
                <p className="text-slate-500 text-sm">تاريخ الاستخراج: {new Date().toLocaleDateString('ar-EG')}</p>
            </div>
        </div>

        {/* Client Info Card */}
        <div className="bg-slate-50 rounded-xl border border-slate-200 p-6 mb-8 flex flex-col md:flex-row justify-between items-start gap-6">
            <div className="flex items-center gap-4">
                <div className="w-16 h-16 rounded-full bg-white border-2 border-slate-200 flex items-center justify-center text-slate-400">
                    {client.image ? (
                        <img src={client.image} alt={client.name} className="w-full h-full object-cover rounded-full" />
                    ) : (
                        <User size={32} />
                    )}
                </div>
                <div>
                    <p className="text-xs text-slate-500 font-bold uppercase mb-1">اسم العميل</p>
                    <h2 className="text-xl font-bold text-slate-900">{client.name}</h2>
                </div>
            </div>

            <div className="flex flex-col items-end gap-1">
                 <div className="flex items-center gap-2">
                    <span className="font-bold text-slate-800 dir-ltr">{client.phone || '---'}</span>
                    <Phone size={16} className="text-slate-400" />
                 </div>
                 <div className="flex items-center gap-2">
                    <span className="text-sm text-slate-600">بداية التعامل: {new Date(client.id).toLocaleDateString('ar-EG')}</span>
                    <Calendar size={16} className="text-slate-400" />
                 </div>
            </div>
        </div>

        {/* Summary Boxes */}
        <div className="grid grid-cols-3 gap-4 mb-8">
            <div className="bg-blue-50 p-4 rounded-xl border border-blue-100 text-center">
                <p className="text-xs text-blue-600 font-bold mb-1">إجمالي المبيعات / عليه</p>
                <p className="text-lg font-extrabold text-blue-800">{totals.totalSales.toLocaleString()} ج.م</p>
            </div>
