import React, { useState } from 'react';
import { User } from '../types';
import { loadUsers, setCurrentUser } from '../services/storage';
import { Lock, User as UserIcon, ChevronRight } from 'lucide-react';

interface LoginProps {
  onLoginSuccess: (user: User) => void;
}

const Login: React.FC<LoginProps> = ({ onLoginSuccess }) => {
  const [identifier, setIdentifier] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const users = loadUsers();

    // Check by Email OR Name
    const user = users.find(u => 
        (u.email.toLowerCase() === identifier.toLowerCase() || u.name.toLowerCase() === identifier.toLowerCase()) 
        && u.password === password
    );

    if (user) {
      if (user.isActive === false) {
          setError('عذراً، تم إيقاف هذا الحساب مؤقتاً من قبل الإدارة.');
      } else {
          setCurrentUser(user);
          onLoginSuccess(user);
      }
    } else {
      setError('اسم المستخدم أو كلمة المرور غير صحيحة');
    }
  };

  // Updated Professional Logo
  const OfficeLogo = () => (
    <svg width="60" height="60" viewBox="0 0 100 100" fill="none" xmlns="http://www.w3.org/2000/svg" className="mx-auto mb-4">
       <path d="M20 20 H80 V80 H20 Z" fill="white" opacity="0.1"/>
       <path d="M50 10 L85 30 V85 H15 V30 L50 10 Z" stroke="white" strokeWidth="4" fill="none" strokeLinejoin="round"/>
       <path d="M35 85 V45 M65 85 V45 M35 45 L50 35 L65 45" stroke="white" strokeWidth="4" strokeLinecap="round" strokeLinejoin="round"/>
       <path d="M50 55 V75" stroke="white" strokeWidth="4" strokeLinecap="round"/>
    </svg>
  );

  return (
    <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4" dir="rtl">
      <div className="bg-white w-full max-w-md rounded-2xl shadow-2xl overflow-hidden fade-in">
        <div className="bg-blue-600 p-8 text-center relative overflow-hidden">
            <div className="absolute top-0 left-0 w-full h-full bg-gradient-to-br from-blue-600 to-indigo-800 opacity-50"></div>
            <div className="relative z-10">
                <OfficeLogo />
                <h1 className="text-3xl font-extrabold text-white mb-2">مكتب بهاء عبد الغني</h1>
                <p className="text-blue-100 font-bold text-sm">للتجارة والتوزيع - كفر الشيخ</p>
            </div>
        </div>

        <div className="p-8">
            <h2 className="text-xl font-bold text-slate-800 mb-6 text-center">تسجيل الدخول</h2>

            <form onSubmit={handleLogin} className="space-y-4">
                {error && (
                    <div className="bg-red-50 text-red-600 p-3 rounded-lg text-sm text-center font-bold border border-red-100">
                        {error}
                    </div>
                )}

                <div>
                    <label className="block text-sm font-bold text-slate-700 mb-1">اسم المستخدم أو البريد الإلكتروني</label>
                    <div className="relative">
                        <UserIcon className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                        <input 
                            type="text" 
                            value={identifier}
                            onChange={(e) => setIdentifier(e.target.value)}
                            className="w-full bg-slate-50 border border-slate-200 rounded-xl py-3 pr-10 pl-4 focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                            placeholder="username / email"
                            required
                        />
                    </div>
                </div>

                <div>
                    <label className="block text-sm font-bold text-slate-700 mb-1">كلمة المرور</label>
                    <div className="relative">
                        <Lock className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                        <input 
                            type="password" 
                            value={password}
                            onChange={(e) => setPassword(e.target.value)}
                            className="w-full bg-slate-50 border border-slate-200 rounded-xl py-3 pr-10 pl-4 focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                            placeholder="••••••"
                            required
                        />
                    </div>
                </div>

                <button 
                    type="submit" 
                    className="w-full bg-blue-600 text-white py-3 rounded-xl font-bold hover:bg-blue-700 transition flex items-center justify-center gap-2 shadow-lg shadow-blue-200 mt-4"
                >
                    دخول للنظام
                    <ChevronRight size={18} className="rotate-180" />
                </button>
            </form>

            <div className="mt-8 text-center border-t pt-4">
                <p className="text-xs text-slate-400">للأعضاء الجدد يرجى مراجعة المدير للحصول على البيانات.</p>
                <p className="text-xs text-slate-300 mt-2 font-mono">حرر بواسطة محمود محمد</p>
            </div>
        </div>
      </div>
    </div>
  );
};

