import React, { useState, useRef, useEffect } from 'react';
import { Bell, AlertTriangle, Clock, X, ChevronRight } from 'lucide-react';
import { NotificationItem } from '../types';

interface NotificationsProps {
  notifications: NotificationItem[];
  onClientSelect: (clientId: number) => void;
}

const Notifications: React.FC<NotificationsProps> = ({ notifications, onClientSelect }) => {
  const [isOpen, setIsOpen] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);

  // Close dropdown when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  return (
    <div className="relative no-print" ref={dropdownRef}>
      <button 
        onClick={() => setIsOpen(!isOpen)}
        className="relative p-2 rounded-full hover:bg-slate-100 transition-colors"
      >
        <Bell size={24} className={notifications.length > 0 ? "text-slate-700" : "text-slate-400"} />
        {notifications.length > 0 && (
            <span className="absolute top-1 right-1 w-4 h-4 bg-red-500 text-white text-[10px] font-bold rounded-full flex items-center justify-center border-2 border-white">
                {notifications.length > 9 ? '9+' : notifications.length}
            </span>
        )}
      </button>

      {isOpen && (
        <div className="absolute left-0 top-12 w-80 bg-white rounded-xl shadow-2xl border border-slate-100 z-50 overflow-hidden fade-in origin-top-left">
          <div className="p-3 border-b border-slate-100 bg-slate-50 flex justify-between items-center">
            <h3 className="font-bold text-slate-800 text-sm">التنبيهات ({notifications.length})</h3>
            <button onClick={() => setIsOpen(false)} className="text-slate-400 hover:text-red-500">
                <X size={16} />
            </button>
          </div>

          <div className="max-h-80 overflow-y-auto">
              {notifications.length === 0 ? (
                  <div className="p-8 text-center text-slate-400 text-xs">
                      <Bell size={24} className="mx-auto mb-2 opacity-20" />
                      لا توجد تنبيهات جديدة
                  </div>
              ) : (
                  <div className="divide-y divide-slate-50">
                      {notifications.map(notif => (
                          <div 
                            key={notif.id} 
                            onClick={() => {
                                onClientSelect(notif.clientId);
                                setIsOpen(false);
                            }}
                            className="p-3 hover:bg-slate-50 transition cursor-pointer group"
                          >
                              <div className="flex items-start gap-3">
                                  <div className={`p-2 rounded-lg shrink-0 ${notif.type === 'late_payment' ? 'bg-red-50 text-red-600' : 'bg-orange-50 text-orange-600'}`}>
                                      {notif.type === 'late_payment' ? <AlertTriangle size={18} /> : <Clock size={18} />}
                                  </div>
                                  <div className="flex-1">
                                      <p className="font-bold text-slate-800 text-sm mb-0.5">{notif.clientName}</p>
                                      <p className="text-xs text-slate-500 leading-snug">
                                          {notif.type === 'late_payment' 
                                            ? `تأخر عن السداد لمدة ${Math.floor(notif.days)} يوم. الرصيد: ${notif.amount?.toLocaleString()} ج.م`
                                            : `لم يقم بأي طلب منذ ${Math.floor(notif.days)} يوم.`
                                          }
                                      </p>
                                  </div>
                                  <ChevronRight size={14} className="text-slate-300 group-hover:text-blue-500 mt-2" />
                              </div>
                          </div>
                      ))}
                  </div>
              )}
          </div>
        </div>
      )}
    </div>
  );
};

