                    </div>
                    <div>
                        <label className="block text-sm font-semibold text-slate-700 mb-1">الصلاحية</label>
                        <div className="flex gap-4">
                             <label className="flex items-center gap-2 cursor-pointer p-3 border rounded-lg flex-1 hover:bg-slate-50">
                                <input type="radio" name="role" value="accountant" checked={userRole === 'accountant'} onChange={() => setUserRole('accountant')} className="w-4 h-4 text-purple-600" />
                                <div>
                                    <span className="block font-bold text-sm">محاسب</span>
                                    <span className="text-xs text-slate-500">صلاحيات محدودة</span>
                                </div>
                            </label>
                            <label className="flex items-center gap-2 cursor-pointer p-3 border rounded-lg flex-1 hover:bg-slate-50">
                                <input type="radio" name="role" value="admin" checked={userRole === 'admin'} onChange={() => setUserRole('admin')} className="w-4 h-4 text-purple-600" />
                                <div>
                                    <span className="block font-bold text-sm">مدير</span>
                                    <span className="text-xs text-slate-500">تحكم كامل</span>
                                </div>
                            </label>
                        </div>
                    </div>
                </div>
            )}

            {/* === TRADE MODE === */}
            {mode === 'trade' && (
                <div className="space-y-4">
                     {/* Trade inputs ... same as before */}
                     <div className="bg-blue-50 p-3 rounded-lg text-xs text-blue-800 mb-2">
                        هذه الفاتورة تقوم بإنشاء عملية توريد من المورد (دين عليك) وعملية بيع للعميل (دين لك) في آن واحد.
                    </div>
                    <div className="grid grid-cols-2 gap-3">
                        <div>
                            <label className="block text-xs font-bold text-slate-700 mb-1">المورد</label>
                            <select value={tradeSupplierId || ''} onChange={(e) => setTradeSupplierId(Number(e.target.value))} className="w-full border border-slate-300 rounded-lg p-2 text-sm focus:ring-2 focus:ring-blue-500 outline-none" required>
                                <option value="">اختر المورد...</option>
                                {suppliers.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                            </select>
                        </div>
                        <div>
                            <label className="block text-xs font-bold text-slate-700 mb-1">العميل</label>
                            <select value={tradeClientId || ''} onChange={(e) => setTradeClientId(Number(e.target.value))} className="w-full border border-slate-300 rounded-lg p-2 text-sm focus:ring-2 focus:ring-blue-500 outline-none" required>
                                <option value="">اختر العميل...</option>
                                {clients.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                            </select>
                        </div>
                    </div>
                    <div>
                        <label className="block text-xs font-bold text-slate-700 mb-1">الصنف</label>
                        <select value={tradeItemId || ''} onChange={(e) => setTradeItemId(Number(e.target.value))} className="w-full border border-slate-300 rounded-lg p-2 text-sm focus:ring-2 focus:ring-blue-500 outline-none" required>
                            <option value="">{tradeSupplierId ? 'اختر الصنف من هذا المورد...' : 'اختر المورد أولاً...'}</option>
                            {filteredTradeItems.map(i => <option key={i.id} value={i.id}>{i.name}</option>)}
                        </select>
                    </div>
                    <div>
                         <label className="block text-xs font-bold text-slate-700 mb-1">العدد / الكمية</label>
                         <input type="number" value={tradeQuantity} onChange={e => setTradeQuantity(e.target.value)} className="w-full border border-slate-300 rounded-lg p-2 text-center font-bold" placeholder="0" required />
                    </div>
                    <div className="grid grid-cols-2 gap-3 bg-slate-50 p-3 rounded-xl border border-slate-200">
                        <div>
                            <label className="block text-xs font-bold text-red-600 mb-1">سعر الشراء</label>
                            <input type="number" value={tradeBuyPrice} onChange={e => setTradeBuyPrice(e.target.value)} className="w-full border border-red-200 rounded-lg p-2 text-sm text-center focus:ring-red-500 outline-none" placeholder="0.00" step="0.01" required />
                        </div>
                        <div>
                            <label className="block text-xs font-bold text-emerald-600 mb-1">سعر البيع</label>
                            <input type="number" value={tradeSellPrice} onChange={e => setTradeSellPrice(e.target.value)} className="w-full border border-emerald-200 rounded-lg p-2 text-sm text-center focus:ring-emerald-500 outline-none" placeholder="0.00" step="0.01" required />
                        </div>
                    </div>
                    {renderDriverFields()}
                    {renderNotesField()}
                </div>
            )}

            {/* Normal Modes */}
            {(mode === 'transaction' || mode === 'client-action' || mode === 'supplier-action') && (
              <>
                {mode === 'transaction' && renderNormalTransactionTypes()}

                {mode === 'transaction' && trxType === 'income' && (
                    <div className="bg-blue-50 p-3 rounded-lg border border-blue-100">
                        <label className="block text-xs font-bold text-blue-800 mb-1">تحديد العميل</label>
                        <select value={selectedClientId || ''} onChange={(e) => setSelectedClientId(Number(e.target.value))} className="w-full border border-blue-200 rounded-md p-2 text-sm bg-white focus:outline-none">
                            <option value="">-- عميل عام / نقدي --</option>
                            {clients.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                        </select>
                    </div>
                )}
                {mode === 'transaction' && trxType === 'expense' && (
                    <div className="bg-orange-50 p-3 rounded-lg border border-orange-100">
                         <label className="block text-xs font-bold text-orange-800 mb-1">تحديد المورد</label>
                        <select value={selectedTxSupplierId || ''} onChange={(e) => setSelectedTxSupplierId(Number(e.target.value))} className="w-full border border-orange-200 rounded-md p-2 text-sm bg-white focus:outline-none">
                            <option value="">-- مورد عام / مصروفات --</option>
                            {suppliers.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                        </select>
                    </div>
                )}

                {(mode === 'transaction' || mode === 'client-action' || mode === 'supplier-action') && (
                  <>
                    <div>
                    <label className="block text-sm font-semibold text-slate-700 mb-1">البيان</label>
                    <input type="text" value={trxName} onChange={(e) => setTrxName(e.target.value)} className="w-full border border-slate-200 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-blue-500 focus:outline-none" placeholder="وصف العملية..." required />
                    </div>
                    <div>
                    <label className="block text-sm font-semibold text-slate-700 mb-1">المبلغ (ج.م)</label>
                    <input type="number" value={trxAmount} onChange={(e) => setTrxAmount(e.target.value)} className="w-full border border-slate-200 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-blue-500 focus:outline-none font-bold text-lg" placeholder="0.00" min="0" step="0.01" required />
                    </div>

                    {/* Toggle for Generic Transactions */}
                    {mode === 'transaction' && (
                        <div className="flex items-center gap-2 my-2">
                             <input type="checkbox" checked={showDetails} onChange={(e) => setShowDetails(e.target.checked)} id="showDetails" className="w-4 h-4" />
                             <label htmlFor="showDetails" className="text-sm text-slate-600">هذه فاتورة؟ (إضافة بيانات سائق/ملاحظات)</label>
                        </div>
                    )}

                    {renderDriverFields()}
                    {renderNotesField()}
                  </>
                )}
              </>
            )}

            {/* Add Entity Modes */}
            {(mode === 'add-client' || mode === 'add-supplier') && (
              <>
                <div className="bg-blue-50 text-blue-800 p-3 rounded-lg text-sm mb-2 font-medium">
                    {mode === 'add-client' ? (initialData ? 'تعديل بيانات العميل' : 'بيانات العميل الجديد') : (initialData ? 'تعديل بيانات المورد' : 'بيانات المورد / الشركة')}
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">الاسم بالكامل</label>
                  <input type="text" value={entityName} onChange={(e) => setEntityName(e.target.value)} className="w-full border border-slate-200 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-blue-500 focus:outline-none" required />
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">رقم الهاتف</label>
                  <input type="tel" value={entityPhone} onChange={(e) => setEntityPhone(e.target.value)} className="w-full border border-slate-200 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-blue-500 focus:outline-none" />
                </div>
              </>
            )}

            {/* Add Item Mode */}
            {mode === 'add-item' && (
                <>
                 <div className="bg-orange-50 text-orange-800 p-3 rounded-lg text-sm mb-2 font-medium">إضافة صنف جديد للمخزن</div>
                 <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">اسم الصنف / المنتج</label>
                  <input type="text" value={itemName} onChange={(e) => setItemName(e.target.value)} className="w-full border border-slate-200 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-blue-500 focus:outline-none" required />
                </div>
                {!targetSupplierId && (
                    <div>
                        <label className="block text-sm font-semibold text-slate-700 mb-1">المورد / الشركة المنتجة</label>
                        <select value={selectedSupplierId || ''} onChange={(e) => setSelectedSupplierId(Number(e.target.value))} className="w-full border border-slate-200 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-blue-500 focus:outline-none bg-white" required>
                            <option value="">اختر المورد...</option>
                            {suppliers.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                        </select>
                    </div>
                )}
                </>
            )}

            <div className="pt-4 flex gap-3">
              <button type="button" onClick={onClose} className="flex-1 py-3 text-slate-600 bg-slate-100 hover:bg-slate-200 rounded-xl font-bold transition-colors">إلغاء</button>
              <button type="submit" className="flex-[2] py-3 text-white bg-blue-600 hover:bg-blue-700 rounded-xl font-bold transition-colors shadow-lg shadow-blue-200 flex items-center justify-center gap-2">
                <Check size={20} />
                {initialData && mode !== 'add-return' ? 'حفظ التعديلات' : 'حفظ البيانات'}
              </button>
            </div>
          </form>
        </div>
      </div>
    </div>
  );
};

export default AddModal;

import React, { useState, useEffect, useRef } from 'react';
import { X, Check, Upload, Image as ImageIcon, FileText, Banknote, ArrowRightLeft, ShoppingCart, Calculator, UserPlus, Lock, Truck, RefreshCw, ShieldCheck, StickyNote } from 'lucide-react';
import { TransactionType, ModalMode, Supplier, Client, Item, UserRole } from '../types';

interface AddModalProps {
  isOpen: boolean;
  mode: ModalMode;
  targetSupplierId?: number;
  targetClientId?: number;
  targetName?: string;
  targetActionType?: 'invoice' | 'receipt'; // New prop
  suppliers?: Supplier[];
  clients?: Client[];
  items?: Item[];
  initialData?: any;
  onClose: () => void;
  onSaveTransaction: (data: { 
      name: string; 
      amount: number; 
      type: TransactionType; 
      clientId?: number; 
      supplierId?: number; 
      driverName?: string; 
      driverPhone?: string;
      immunizationStatus?: 'immunized' | 'not_immunized';
      notes?: string;
    }) => void;
  onSaveTrade: (data: { 
      clientId: number; 
      supplierId: number; 
      itemId: number; 
      itemName: string;
      quantity: number; 
      buyPrice: number; 
      sellPrice: number;
      driverName?: string;
      driverPhone?: string; 
      immunizationStatus?: 'immunized' | 'not_immunized';
      notes?: string;
  }) => void;
  onSaveClient: (data: { name: string; phone: string; image?: string }) => void;
  onSaveSupplier: (data: { name: string; phone: string; image?: string }) => void;
  onSaveItem: (data: { name: string; supplierId: number; image?: string }) => void;
  onSaveUser?: (data: { name: string; email: string; password: string; role: UserRole }) => void;
  onSaveReturn?: (data: { quantity: number; amount: number; notes: string }) => void; 
}

const AddModal: React.FC<AddModalProps> = ({ 
    isOpen, 
    mode, 
    targetSupplierId, 
    targetClientId,
    targetName,
    targetActionType,
    suppliers = [],
    clients = [],
    items = [],
    initialData,
    onClose, 
    onSaveTransaction, 
    onSaveTrade,
    onSaveClient, 
    onSaveSupplier, 
    onSaveItem,
    onSaveUser,
    onSaveReturn
}) => {

  // Transaction State
  const [trxName, setTrxName] = useState('');
  const [trxAmount, setTrxAmount] = useState('');
  const [trxType, setTrxType] = useState<TransactionType>('income');
  const [trxSubType, setTrxSubType] = useState<string>('');
  const [trxNotes, setTrxNotes] = useState('');

  // Local state to toggle details in generic transaction mode
  const [showDetails, setShowDetails] = useState(false);

  // Driver State
  const [driverName, setDriverName] = useState('');
  const [driverPhone, setDriverPhone] = useState('');

  // Immunization State
  const [immunizationStatus, setImmunizationStatus] = useState<'immunized' | 'not_immunized'>('not_immunized');

  // Generic Selection State
  const [selectedClientId, setSelectedClientId] = useState<number | undefined>(undefined);
  const [selectedTxSupplierId, setSelectedTxSupplierId] = useState<number | undefined>(undefined);

  // Trade Specific State
  const [tradeClientId, setTradeClientId] = useState<number | undefined>(undefined);
  const [tradeSupplierId, setTradeSupplierId] = useState<number | undefined>(undefined);
  const [tradeItemId, setTradeItemId] = useState<number | undefined>(undefined);
  const [tradeQuantity, setTradeQuantity] = useState<string>('');
  const [tradeBuyPrice, setTradeBuyPrice] = useState<string>('');
  const [tradeSellPrice, setTradeSellPrice] = useState<string>('');

  // Return Specific State
  const [returnQty, setReturnQty] = useState('');
  const [returnPrice, setReturnPrice] = useState('');
  const [returnNotes, setReturnNotes] = useState('');

  // Entity Creation State
  const [entityName, setEntityName] = useState('');
  const [entityPhone, setEntityPhone] = useState('');

  // Item Creation State
  const [itemName, setItemName] = useState('');
  const [selectedSupplierId, setSelectedSupplierId] = useState<number | undefined>(undefined);

  // User Creation State
  const [userEmail, setUserEmail] = useState('');
  const [userPassword, setUserPassword] = useState('');
  const [userRole, setUserRole] = useState<UserRole>('accountant');

  // Image State
  const [selectedImage, setSelectedImage] = useState<string | undefined>(undefined);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedImage(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  useEffect(() => {
    if (isOpen) {
      if (initialData && mode !== 'add-return') {
          // Pre-fill logic...
          if (mode === 'add-client' || mode === 'add-supplier') {
            setEntityName(initialData.name);
            setEntityPhone(initialData.phone);
            setSelectedImage(initialData.image);
          } else if (mode === 'transaction') {
            setTrxName(initialData.name);
            setTrxAmount(initialData.amount.toString());
            setTrxType(initialData.type);
            setSelectedClientId(initialData.clientId);
            setSelectedTxSupplierId(initialData.supplierId);
            setDriverName(initialData.driverName || '');
            setDriverPhone(initialData.driverPhone || '');
            setImmunizationStatus(initialData.immunizationStatus || 'not_immunized');
            setTrxNotes(initialData.notes || '');

            // Auto show details if data exists
            if(initialData.driverName || initialData.notes || initialData.immunizationStatus) setShowDetails(true);
          } else if (mode === 'add-item') {
            setItemName(initialData.name);
            setSelectedSupplierId(initialData.supplierId);
            setSelectedImage(initialData.image);
          }
      } else if (mode === 'add-return' && initialData) {
          // Setup return defaults based on original transaction
          setReturnQty('1');
          setReturnPrice(initialData.unitPrice ? initialData.unitPrice.toString() : initialData.amount.toString());
          setReturnNotes(`مرتجع من: ${initialData.name}`);
      } else {
          // Reset Forms
          setTrxName('');
          setTrxAmount('');
          setEntityName('');
          setEntityPhone('');
          setItemName('');
          setDriverName('');
          setDriverPhone('');
          setImmunizationStatus('not_immunized');
          setTrxNotes('');
          setSelectedImage(undefined);
          setShowDetails(false);

          setSelectedSupplierId(targetSupplierId);
          setSelectedClientId(undefined);
          setSelectedTxSupplierId(undefined);

          setTradeClientId(undefined);
          setTradeSupplierId(undefined);
          setTradeItemId(undefined);
          setTradeQuantity('');
          setTradeBuyPrice('');
          setTradeSellPrice('');

          // Reset User Form
          setUserEmail('');
          setUserPassword('');
          setUserRole('accountant');

          // Initialize Type based on targetActionType (Invoice vs Receipt)
          if (mode === 'client-action') {
              setTrxType('income');
              // Infer subtitle from action type
              if (targetActionType === 'invoice') setTrxSubType('sales_invoice');
              else setTrxSubType('receipt');
          } else if (mode === 'supplier-action') {
              setTrxType('expense');
               if (targetActionType === 'invoice') setTrxSubType('purchase_invoice');
              else setTrxSubType('payment');
          } else {
              setTrxType('income');
              setTrxSubType('');
          }
      }
    }
  }, [isOpen, mode, initialData, targetSupplierId, targetActionType]);

  // Update name based on sub-type
  useEffect(() => {
    if (!initialData) {
        if (mode === 'client-action' && targetName) {
            if (trxSubType === 'sales_invoice') setTrxName(`فاتورة بيع - ${targetName}`);
            else if (trxSubType === 'receipt') setTrxName(`سند قبض من ${targetName}`);
        } else if (mode === 'supplier-action' && targetName) {
            if (trxSubType === 'purchase_invoice') setTrxName(`فاتورة شراء - ${targetName}`);
            else if (trxSubType === 'payment') setTrxName(`سند دفع لـ ${targetName}`);
        }
    }
  }, [trxSubType, mode, targetName, initialData]);

  const filteredTradeItems = items.filter(i => !tradeSupplierId || i.supplierId === tradeSupplierId);

  // Condition to show extra details (Driver, Notes)
  const shouldShowDetails = 
  mode === 'trade' || 
  targetActionType === 'invoice' || 
  (mode === 'transaction' && showDetails);

  if (!isOpen) return null;

  const getTitle = () => {
      if (initialData && mode !== 'add-return') return 'تعديل البيانات';
      switch(mode) {
          case 'transaction': return 'إضافة عملية مالية سريعة';
          case 'trade': return 'فاتورة تجارية (شراء وبيع)';
          case 'client-action': return `تسجيل عملية لـ ${targetName}`;
          case 'supplier-action': return `تسجيل عملية لـ ${targetName}`;
          case 'add-client': return 'إضافة عميل جديد';
          case 'add-supplier': return 'إضافة مورد جديد';
          case 'add-item': return 'إضافة صنف جديد';
          case 'add-user': return 'إضافة مستخدم جديد للنظام';
          case 'add-return': return 'تسجيل مرتجع على الفاتورة';
      }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (mode === 'add-return' && onSaveReturn) {
        if (!returnQty || !returnPrice) return;
        onSaveReturn({
            quantity: parseFloat(returnQty),
            amount: parseFloat(returnPrice), // Price per unit
            notes: returnNotes
        });
    }
    else if (mode === 'add-user' && onSaveUser) {
        if (!entityName || !userEmail || !userPassword) {
            alert("يرجى ملء جميع بيانات المستخدم");
            return;
        }
        onSaveUser({
            name: entityName,
            email: userEmail,
            password: userPassword,
            role: userRole
        });
    }
    else if (mode === 'trade') {
        if (!tradeClientId || !tradeSupplierId || !tradeItemId || !tradeQuantity || !tradeBuyPrice || !tradeSellPrice) {
            alert("يرجى إكمال جميع حقول الفاتورة التجارية");
            return;
        }
        const selectedItem = items.find(i => i.id === tradeItemId);
        onSaveTrade({
            clientId: tradeClientId,
            supplierId: tradeSupplierId,
            itemId: tradeItemId,
            itemName: selectedItem ? selectedItem.name : 'Unknown',
            quantity: parseFloat(tradeQuantity),
            buyPrice: parseFloat(tradeBuyPrice),
            sellPrice: parseFloat(tradeSellPrice),
            driverName: driverName,
            driverPhone: driverPhone,
            immunizationStatus: immunizationStatus,
            notes: trxNotes
        });
    }
    else if (mode === 'transaction' || mode === 'client-action' || mode === 'supplier-action') {
      if (!trxName || !trxAmount) return;

      let finalClientId = targetClientId;
      let finalSupplierId = targetSupplierId;

      if (mode === 'transaction') {
          if (trxType === 'income') finalClientId = selectedClientId;
          if (trxType === 'expense') finalSupplierId = selectedTxSupplierId;
      }

      // Determine if we should save the extra details
      const includeDetails = shouldShowDetails;

      onSaveTransaction({ 
          name: trxName, 
          amount: parseFloat(trxAmount), 
          type: trxType,
          clientId: finalClientId,
          supplierId: finalSupplierId,
          // Only include these fields if they are visible/applicable (Invoices)
          driverName: includeDetails ? driverName : undefined,
          driverPhone: includeDetails ? driverPhone : undefined,
          immunizationStatus: includeDetails ? immunizationStatus : undefined,
          notes: includeDetails ? trxNotes : undefined
      });
    } 
    else if (mode === 'add-client') {
      if (!entityName) return;
      onSaveClient({ name: entityName, phone: entityPhone, image: selectedImage });
    }
    else if (mode === 'add-supplier') {
        if (!entityName) return;
        onSaveSupplier({ name: entityName, phone: entityPhone, image: selectedImage });
    }
    else if (mode === 'add-item') {
        const finalSupplierId = targetSupplierId || selectedSupplierId;
        if (!itemName || !finalSupplierId) {
            alert('يرجى كتابة اسم الصنف واختيار المورد');
            return;
        }
        onSaveItem({ name: itemName, supplierId: finalSupplierId, image: selectedImage });
    }
