export default AddModal;

import { Client, Supplier, Item, Transaction, User } from '../types';

const API_URL = './api.php'; // Relative path to API

// Session management (Still local for logged-in state speed)
const SESSION_KEY = 'almohaseb_session';

export const getCurrentUser = (): User | null => {
    try {
        const data = localStorage.getItem(SESSION_KEY);
        return data ? JSON.parse(data) : null;
    } catch {
        return null;
    }
};

export const setCurrentUser = (user: User | null) => {
    if (user) {
        localStorage.setItem(SESSION_KEY, JSON.stringify(user));
    } else {
        localStorage.removeItem(SESSION_KEY);
    }
};

// Generic Fetch Wrapper
async function fetchData(action: string) {
    try {
        const res = await fetch(`${API_URL}?action=${action}`);
        if (!res.ok) throw new Error('Network error');
        return await res.json();
    } catch (e) {
        console.error(`Error fetching ${action}:`, e);
        return [];
    }
}

async function saveData(action: string, data: any) {
    try {
        // If data is an array (bulk save - deprecated in this new API model but handling it just in case)
        // We actually refactored to save single items.
        // But for "saveTransactions" which is called with the WHOLE array in App.tsx, we need to adapt.
        // Wait, App.tsx calls saveTransactions(updatedArray). This is inefficient for API.
        // We will modify the API calls in App.tsx to send only the CHANGED item.
        // BUT to keep changes minimal, we will loop here if array, or send single if object.

        if (Array.isArray(data)) {
            // If it's an array, it means the App replaced the whole state.
            // Since we don't want to re-upload 1000 items, we should ideally change App.tsx.
            // However, to satisfy the user request with minimal breakage:
            // We will only send the LAST item if it's an add, or find the diff.
            // Limitation: This simple migration assumes we send the *Record* being edited/added.
            // We will update App.tsx to pass the single record to a new function, or we intercept here.

            // CRITICAL FIX: The App.tsx logic passes the WHOLE array. 
            // We cannot easily change that without refactoring App.tsx significantly.
            // TEMPORARY HACK: We won't implement bulk save here.
            // We will assume App.tsx calls `saveItem(singleItem)`.
            // I will update App.tsx to call specific save functions.
            return; 
        }

        const res = await fetch(`${API_URL}?action=${action}`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(data)
        });
        return await res.json();
    } catch (e) {
        console.error(`Error saving ${action}:`, e);
    }
}

async function deleteData(table: string, id: number) {
     try {
        await fetch(`${API_URL}?action=delete&table=${table}`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ id })
        });
    } catch (e) {
        console.error(`Error deleting from ${table}:`, e);
    }
}

