```

---

### 2. ملف `public/install.php`
هذا الملف لإنشاء الجداول في قاعدة البيانات. أنشئ ملفاً بهذا الاسم، ضع فيه الكود التالي، ثم افتحه في المتصفح مرة واحدة (مثلاً: `yourdomain.com/install.php`).

```php
<?php
// public/install.php
include 'db_config.php';

try {
    // جدول المستخدمين
    $sql = "CREATE TABLE IF NOT EXISTS users (
        id INT AUTO_INCREMENT PRIMARY KEY,
        name VARCHAR(255) NOT NULL,
        email VARCHAR(255) NOT NULL UNIQUE,
        password VARCHAR(255) NOT NULL,
        role ENUM('admin', 'accountant') DEFAULT 'accountant',
        image LONGTEXT,
        isActive TINYINT(1) DEFAULT 1,
        created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
    )";
    $conn->exec($sql);

    // جدول العملاء
    $sql = "CREATE TABLE IF NOT EXISTS clients (
        id INT AUTO_INCREMENT PRIMARY KEY,
        name VARCHAR(255) NOT NULL,
        phone VARCHAR(50),
        image LONGTEXT,
        created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
    )";
    $conn->exec($sql);

    // جدول الموردين
    $sql = "CREATE TABLE IF NOT EXISTS suppliers (
        id INT AUTO_INCREMENT PRIMARY KEY,
        name VARCHAR(255) NOT NULL,
        phone VARCHAR(50),
        image LONGTEXT,
        created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
    )";
    $conn->exec($sql);

    // جدول الأصناف
    $sql = "CREATE TABLE IF NOT EXISTS items (
        id INT AUTO_INCREMENT PRIMARY KEY,
        name VARCHAR(255) NOT NULL,
        supplierId INT,
        image LONGTEXT,
        created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
    )";
    $conn->exec($sql);

    // جدول العمليات (الفواتير)
    $sql = "CREATE TABLE IF NOT EXISTS transactions (
        id INT AUTO_INCREMENT PRIMARY KEY,
        name VARCHAR(255),
        amount DECIMAL(15, 2) NOT NULL DEFAULT 0,
        type ENUM('income', 'expense') NOT NULL,
        date VARCHAR(50),
        clientId INT NULL,
        supplierId INT NULL,
        itemId INT NULL,
        quantity DECIMAL(10, 2) DEFAULT 0,
        unitPrice DECIMAL(15, 2) DEFAULT 0,
        relatedTransactionId INT NULL,
        driverName VARCHAR(255),
        driverPhone VARCHAR(50),
        isReturn TINYINT(1) DEFAULT 0,
        originalTransactionId INT NULL,
        immunizationStatus VARCHAR(50),
        notes TEXT,
        created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
    )";
    $conn->exec($sql);

    // إضافة مستخدم افتراضي إذا لم يوجد
    $stmt = $conn->prepare("SELECT COUNT(*) FROM users");
    $stmt->execute();
    if ($stmt->fetchColumn() == 0) {
        // admin / 123456
        $sql = "INSERT INTO users (name, email, password, role) VALUES ('Admin', 'admin@sys.com', '123456', 'admin')";
