include 'db_config.php';

$action = isset($_GET['action']) ? $_GET['action'] : '';
$data = json_decode(file_get_contents("php://input"), true);

// دوال مساعدة
function jsonResponse($data) {
    echo json_encode($data, JSON_UNESCAPED_UNICODE);
