                $stmt = $conn->prepare($sql);
                $stmt->execute([
                    $data['name'], $data['amount'], $data['type'], $data['date'], 
                    $clientId, $supplierId, $itemId, $qty, $uPrice, 
                    $dName, $dPhone, $isRet, $origId, $imm, $notes
                ]);
                $data['id'] = $conn->lastInsertId();
            }
            jsonResponse($data);
            break;

        // --- DELETE GENERIC ---
        case 'delete':
            $table = $_GET['table'];
            // Whitelist tables for security
            $allowed_tables = ['users', 'clients', 'suppliers', 'items', 'transactions'];
            if (in_array($table, $allowed_tables)) {
                $stmt = $conn->prepare("DELETE FROM $table WHERE id = ?");
                $stmt->execute([$data['id']]);
                jsonResponse(['success' => true]);
            } else {
                http_response_code(400);
                jsonResponse(['error' => 'Invalid table']);
            }
            break;

        default:
            jsonResponse(['status' => 'API is working']);
            break;
    }

} catch(PDOException $e) {
    http_response_code(500);
    jsonResponse(['error' => $e->getMessage()]);
}
?>
