import { Client, Supplier, Item, Transaction, User } from '../types';

// Session management
const SESSION_KEY = 'almohaseb_session';

const KEYS = {
    TRANSACTIONS: 'db_transactions',
    CLIENTS: 'db_clients',
    SUPPLIERS: 'db_suppliers',
    ITEMS: 'db_items',
    USERS: 'db_users'
};

export const getCurrentUser = (): User | null => {
    try {
        const data = localStorage.getItem(SESSION_KEY);
        return data ? JSON.parse(data) : null;
    } catch {
        return null;
    }
};

export const setCurrentUser = (user: User | null) => {
    if (user) {
        localStorage.setItem(SESSION_KEY, JSON.stringify(user));
    } else {
        localStorage.removeItem(SESSION_KEY);
    }
};

// Generic Helpers
const get = <T>(key: string): T[] => {
    try {
        const s = localStorage.getItem(key);
        return s ? JSON.parse(s) : [];
    } catch (e) {
        return [];
    }
};

const set = (key: string, data: any[]) => {
    try {
        localStorage.setItem(key, JSON.stringify(data));
    } catch (e) {
        console.error("Error saving to localStorage", e);
    }
};

// --- Users ---
export const loadUsers = async (): Promise<User[]> => {
    let users = get<User>(KEYS.USERS);

    // 1. Ensure Default Admin Exists
    const adminIndex = users.findIndex(u => u.email === 'admin');
    const defaultAdmin: User = {
        id: 1,
        name: 'مدير النظام',
        email: 'admin',
        password: 'M@hmoud2025',
        role: 'admin',
        isActive: true
    };

    if (adminIndex === -1) {
        users.push(defaultAdmin);
    } else {
        // Reset password for admin if specifically requested by user update logic
        // For now, we keep existing password if changed, unless it's the first load fix
        if (users[adminIndex].password !== 'M@hmoud2025') {
             // Optional: Force update if locked out, otherwise assume user changed it.
             // users[adminIndex].password = 'M@hmoud2025'; 
        }
    }

    // 2. Ensure "Mahmoud" Account Exists
    const mahmoudEmail = 'mahmoudegypte@gmail.com';
    const mahmoudIndex = users.findIndex(u => u.email === mahmoudEmail || u.name.toLowerCase() === 'mahmoud');

    const mahmoudUser: User = {
        id: 2,
        name: 'mahmoud',
        email: mahmoudEmail,
        password: 'M@hmoud2025',
        role: 'admin',
        isActive: true
    };

    if (mahmoudIndex === -1) {
        users.push(mahmoudUser);
    } else {
        // Ensure role is admin
        users[mahmoudIndex].role = 'admin';
        users[mahmoudIndex].isActive = true;
        // Check if we need to sync email if logged in by username
