export const saveUserRecord = async (user: User) => {
    const list = await loadUsers();
    if (user.id === 0) {
        user.id = Date.now();
        list.push(user);
    } else {
        const idx = list.findIndex(u => u.id === user.id);
        if (idx > -1) list[idx] = user;
    }
    set(KEYS.USERS, list);
    return user;
};

export const deleteUserRecord = async (id: number) => {
    let list = await loadUsers();
    // Protect default admin and mahmoud from deletion
    list = list.filter(u => 
        u.id !== id || 
        (u.email !== 'admin' && u.email !== 'mahmoudegypte@gmail.com')
    );
    set(KEYS.USERS, list);
};

// --- Clients ---
export const loadClients = async (): Promise<Client[]> => get<Client>(KEYS.CLIENTS);

export const saveClientRecord = async (item: Client) => {
    const list = await loadClients();
    if (item.id === 0) {
        item.id = Date.now();
        list.push(item);
    } else {
        const idx = list.findIndex(i => i.id === item.id);
        if (idx > -1) list[idx] = item;
    }
    set(KEYS.CLIENTS, list);
    return item;
};

export const deleteClientRecord = async (id: number) => {
    const list = await loadClients();
    set(KEYS.CLIENTS, list.filter(i => i.id !== id));
};

// --- Suppliers ---
export const loadSuppliers = async (): Promise<Supplier[]> => get<Supplier>(KEYS.SUPPLIERS);

export const saveSupplierRecord = async (item: Supplier) => {
    const list = await loadSuppliers();
    if (item.id === 0) {
        item.id = Date.now();
        list.push(item);
    } else {
        const idx = list.findIndex(i => i.id === item.id);
        if (idx > -1) list[idx] = item;
    }
    set(KEYS.SUPPLIERS, list);
    return item;
};

export const deleteSupplierRecord = async (id: number) => {
    const list = await loadSuppliers();
    set(KEYS.SUPPLIERS, list.filter(i => i.id !== id));
};

// --- Items ---
export const loadItems = async (): Promise<Item[]> => get<Item>(KEYS.ITEMS);

export const saveItemRecord = async (item: Item) => {
    const list = await loadItems();
    if (item.id === 0) {
        item.id = Date.now();
        list.push(item);
    } else {
        const idx = list.findIndex(i => i.id === item.id);
        if (idx > -1) list[idx] = item;
    }
    set(KEYS.ITEMS, list);
    return item;
};

export const deleteItemRecord = async (id: number) => {
    const list = await loadItems();
    set(KEYS.ITEMS, list.filter(i => i.id !== id));
};

