import React, { useRef, useState } from 'react';
import { X, Download, Upload, AlertTriangle, Database, Loader2, RefreshCw } from 'lucide-react';
import { 
    loadTransactions, loadClients, loadSuppliers, loadItems, 
    saveTransactions, saveClients, saveSuppliers, saveItems 
} from '../services/storage';

interface SettingsModalProps {
  isOpen: boolean;
  onClose: () => void;
  onDataRestored: () => void;
}

const SettingsModal: React.FC<SettingsModalProps> = ({ isOpen, onClose, onDataRestored }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [loading, setLoading] = useState(false);
  const [restoring, setRestoring] = useState(false);

  if (!isOpen) return null;

  const handleBackup = async () => {
    setLoading(true);
    try {
        const [transactions, clients, suppliers, items] = await Promise.all([
            loadTransactions(),
            loadClients(),
            loadSuppliers(),
            loadItems()
        ]);

        const data = {
        transactions,
        clients,
        suppliers,
        items,
        timestamp: new Date().toISOString(),
        version: '1.0'
        };

        const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.href = url;
        link.download = `AlMohaseb_Backup_${new Date().toISOString().split('T')[0]}.json`;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    } catch (e) {
        alert('حدث خطأ أثناء تحميل البيانات');
    } finally {
        setLoading(false);
    }
  };

  const handleRestore = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (!confirm('تحذير: استعادة النسخة الاحتياطية ستقوم بحذف البيانات الحالية واستبدالها بالبيانات الموجودة في الملف. هل أنت متأكد؟')) {
        if (fileInputRef.current) fileInputRef.current.value = '';
        return;
    }

    setRestoring(true);
    const reader = new FileReader();

    reader.onload = (event) => {
        try {
            const jsonStr = event.target?.result as string;
            const data = JSON.parse(jsonStr);

            // Validation: Check if it looks like our backup
            if (!data.transactions && !data.clients && !data.suppliers) {
                throw new Error('الملف المختار غير صالح أو لا يحتوي على بيانات صحيحة');
            }

            // Restore Data
            if (data.transactions) saveTransactions(data.transactions);
            if (data.clients) saveClients(data.clients);
            if (data.suppliers) saveSuppliers(data.suppliers);
            if (data.items) saveItems(data.items);

            // Note: We deliberately don't restore USERS to prevent locking admin out, 
            // unless specific logic is required.

            alert('تم استعادة البيانات بنجاح!');
            onDataRestored(); // Refresh App UI
            onClose();

        } catch (err) {
            console.error(err);
            alert('حدث خطأ أثناء قراءة الملف. تأكد من اختيار ملف Backup صحيح (.json)');
        } finally {
            setRestoring(false);
            if (fileInputRef.current) fileInputRef.current.value = '';
        }
    };

    reader.onerror = () => {
        alert('حدث خطأ أثناء قراءة الملف');
        setRestoring(false);
    };

    reader.readAsText(file);
  };

  const triggerFileUpload = () => {
      fileInputRef.current?.click();
  };

  return (
    <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex items-center justify-center p-4 fade-in no-print">
      <div className="bg-white rounded-2xl w-full max-w-md shadow-2xl overflow-hidden">
        <div className="bg-slate-50 px-6 py-4 border-b border-slate-100 flex justify-between items-center">
          <h3 className="font-bold text-lg text-slate-800 flex items-center gap-2">
            <Database size={20} className="text-blue-600" />
            إدارة البيانات والنسخ الاحتياطي
          </h3>
          <button onClick={onClose} className="text-slate-400 hover:text-red-500 transition-colors">
            <X size={24} />
          </button>
        </div>

        <div className="p-6 space-y-6">

            {/* Backup Section */}
            <div className="bg-blue-50 border border-blue-100 rounded-xl p-4">
                <div className="flex items-start gap-3">
                    <div className="bg-blue-100 p-2 rounded-lg text-blue-600">
                        <Download size={24} />
                    </div>
                    <div className="flex-1">
                        <h4 className="font-bold text-slate-800 mb-1">حفظ نسخة احتياطية</h4>
                        <p className="text-sm text-slate-600 mb-3">
                            قم بتحميل ملف يحتوي على جميع الفواتير والعملاء والموردين لحفظها على جهازك.
                        </p>
                        <button 
                            onClick={handleBackup}
                            disabled={loading || restoring}
                            className="w-full bg-blue-600 text-white py-2 rounded-lg font-bold hover:bg-blue-700 transition shadow-sm flex justify-center items-center gap-2"
                        >
                            {loading ? <Loader2 className="animate-spin" size={18} /> : 'تحميل الملف (Backup)'}
                        </button>
                    </div>
                </div>
            </div>

            {/* Restore Section */}
            <div className="bg-orange-50 border border-orange-100 rounded-xl p-4">
                <div className="flex items-start gap-3">
                    <div className="bg-orange-100 p-2 rounded-lg text-orange-600">
                        <Upload size={24} />
                    </div>
                    <div className="flex-1">
                        <h4 className="font-bold text-slate-800 mb-1">استعادة نسخة سابقة</h4>
                        <p className="text-sm text-slate-600 mb-3">
                            اختر ملف النسخة الاحتياطية (.json) لاسترجاع البيانات. سيتم استبدال البيانات الحالية.
                        </p>
                        <input 
                            type="file" 
                            accept=".json" 
                            ref={fileInputRef} 
                            onChange={handleRestore} 
                            className="hidden" 
                        />
                        <button 
                            onClick={triggerFileUpload}
                            disabled={loading || restoring}
                            className="w-full bg-orange-600 text-white py-2 rounded-lg font-bold hover:bg-orange-700 transition shadow-sm flex justify-center items-center gap-2"
                        >
                            {restoring ? <Loader2 className="animate-spin" size={18} /> : (
                                <>
                                    <RefreshCw size={18} />
                                    <span>استعادة البيانات (Restore)</span>
                                </>
                            )}
                        </button>
                    </div>
                </div>
            </div>

            <div className="flex items-center gap-2 text-xs text-slate-400 bg-slate-50 p-3 rounded-lg">
                <AlertTriangle size={14} />
                <span>نصيحة: تأكد من حفظ نسخة احتياطية حديثة دائماً لتجنب فقدان البيانات.</span>
            </div>

        </div>
      </div>
    </div>
  );
};

