import { ViewState, Transaction, Client, Supplier, Item, Stats, TransactionType, ModalMode, User, UserRole, NotificationItem } from './types';
import { 
    loadTransactions, saveTransactionRecord, deleteTransactionRecord,
    loadClients, saveClientRecord, deleteClientRecord,
    loadSuppliers, saveSupplierRecord, deleteSupplierRecord,
    loadItems, saveItemRecord, deleteItemRecord,
