                         <label className="block text-[10px] font-bold text-blue-800 mb-1">عدد التحصين</label>
                         <input type="number" value={immQty} onChange={(e) => setImmQty(e.target.value)} className="w-full border border-blue-200 rounded-md p-1.5 text-sm text-center font-bold outline-none focus:ring-1 focus:ring-blue-500" placeholder="0" />
                     </div>
                     <div>
                         <label className="block text-[10px] font-bold text-blue-800 mb-1">سعر التحصين</label>
                         <input type="number" value={immPrice} onChange={(e) => setImmPrice(e.target.value)} className="w-full border border-blue-200 rounded-md p-1.5 text-sm text-center font-bold outline-none focus:ring-1 focus:ring-blue-500" placeholder="0.00" />
                     </div>
                 </div>
             )}
          </div>
      </div>
  )};

